import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum DeliveryStatus {
  PENDING = 'PENDENTE',
  IN_TRANSIT = 'EM TRÂNSITO',
  DELIVERED = 'ENTREGUE',
  FAILED = 'FALHA NA ENTREGA'
}

export interface Delivery {
  id: string;
  orderNumber: string;
  customerName: string;
  address: string;
  driverName: string;
  status: DeliveryStatus;
  updatedAt: string;
  lat: number;
  lng: number;
  notes?: string;
}

export type UserRole = 'ADMIN' | 'DRIVER' | 'CUSTOMER';

export interface AppState {
  deliveries: Delivery[];
  currentUserRole: UserRole;
  selectedDriver: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { DeliveryStatus } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateTrackingMessage(status: DeliveryStatus, customerName: string): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Crie uma mensagem curta e amigável em português para o cliente ${customerName} informando que o status do seu pedido é ${status}.`,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text || "Status atualizado com sucesso.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return `Seu pedido está atualmente como ${status}.`;
  }
}

export async function parseExcelData(rawData: any[]): Promise<any[]> {
  // Use Gemini to clean or structure potentially messy data from Excel
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analise estes dados brutos de uma planilha e transforme em um JSON estruturado com os campos: orderNumber, customerName, address, driverName. Dados: ${JSON.stringify(rawData.slice(0, 10))}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              orderNumber: { type: Type.STRING },
              customerName: { type: Type.STRING },
              address: { type: Type.STRING },
              driverName: { type: Type.STRING },
            },
            required: ["orderNumber", "customerName", "address", "driverName"]
          }
        }
      }
    });
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Parsing Error:", error);
    return rawData;
  }
}

import React, { useEffect, useRef } from 'react';
import { Delivery, DeliveryStatus } from '../types';

interface DeliveryMapProps {
  deliveries: Delivery[];
  highlightId?: string;
}

const DeliveryMap: React.FC<DeliveryMapProps> = ({ deliveries, highlightId }) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const markersRef = useRef<any[]>([]);

  useEffect(() => {
    if (!mapContainerRef.current) return;

    // Initialize map if not already done
    if (!mapRef.current) {
      mapRef.current = (window as any).L.map(mapContainerRef.current).setView([-23.5505, -46.6333], 12); // São Paulo default
      (window as any).L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(mapRef.current);
    }

    // Clear old markers
    markersRef.current.forEach(m => m.remove());
    markersRef.current = [];

    // Add new markers
    const bounds = (window as any).L.latLngBounds([]);

    deliveries.forEach(delivery => {
      const color = delivery.status === DeliveryStatus.DELIVERED ? 'green' : 
                    delivery.status === DeliveryStatus.IN_TRANSIT ? 'blue' : 'orange';

      const markerIcon = (window as any).L.divIcon({
        className: 'custom-div-icon',
        html: `<div style="background-color: ${color}; width: 15px; height: 15px; border-radius: 50%; border: 2px solid white;"></div>`,
        iconSize: [15, 15],
        iconAnchor: [7, 7]
      });

      const marker = (window as any).L.marker([delivery.lat, delivery.lng], { icon: markerIcon })
        .addTo(mapRef.current)
        .bindPopup(`
          <strong>Pedido: ${delivery.orderNumber}</strong><br/>
          Status: ${delivery.status}<br/>
          Cliente: ${delivery.customerName}<br/>
          Endereço: ${delivery.address}
        `);

      if (delivery.id === highlightId) {
        marker.openPopup();
        mapRef.current.setView([delivery.lat, delivery.lng], 15);
      }

      markersRef.current.push(marker);
      bounds.extend([delivery.lat, delivery.lng]);
    });

    if (deliveries.length > 0 && !highlightId) {
      mapRef.current.fitBounds(bounds, { padding: [50, 50] });
    }

  }, [deliveries, highlightId]);

  return <div ref={mapContainerRef} className="leaflet-container shadow-inner border border-slate-200" />;
};

export default DeliveryMap;

import React, { useState, useEffect, useCallback } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Search, 
  FileUp, 
  CheckCircle2, 
  Clock, 
  MapPin, 
  ChevronRight,
  LogOut,
  LayoutDashboard,
  Settings
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole } from './types';
import DeliveryMap from './components/DeliveryMap';
import { generateTrackingMessage, parseExcelData } from './services/geminiService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [role, setRole] = useState<UserRole>('CUSTOMER');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);

  // Load from LocalStorage
  useEffect(() => {
    const saved = localStorage.getItem('swiftlog_deliveries');
    if (saved) {
      setDeliveries(JSON.parse(saved));
    }
  }, []);

  // Save to LocalStorage
  useEffect(() => {
    localStorage.setItem('swiftlog_deliveries', JSON.stringify(deliveries));
  }, [deliveries]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      const bstr = evt.target?.result;
      const wb = XLSX.read(bstr, { type: 'binary' });
      const wsname = wb.SheetNames[0];
      const ws = wb.Sheets[wsname];
      const data = XLSX.utils.sheet_to_json(ws);

      // Simple transformation (normally we'd use gemini parse here for more robust clean up)
      // For demo, we create standard delivery objects with fake coords around SP
      const newDeliveries: Delivery[] = data.map((item: any, idx: number) => ({
        id: crypto.randomUUID(),
        orderNumber: String(item.orderNumber || item['Nº Pedido'] || Math.floor(1000 + Math.random() * 9000)),
        customerName: item.customerName || item['Cliente'] || 'Cliente Desconhecido',
        address: item.address || item['Endereço'] || 'Rua Exemplo, 123',
        driverName: item.driverName || item['Motorista'] || 'Motorista Padrão',
        status: DeliveryStatus.PENDING,
        updatedAt: new Date().toISOString(),
        lat: -23.5505 + (Math.random() - 0.5) * 0.1,
        lng: -46.6333 + (Math.random() - 0.5) * 0.1,
      }));

      setDeliveries(prev => [...prev, ...newDeliveries]);
      setLoading(false);
    };
    reader.readAsBinaryString(file);
  };

  const updateDeliveryStatus = async (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;

    const updated = deliveries.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    );
    setDeliveries(updated);

    // Call Gemini for a friendly message if status changed to DELIVERED
    if (newStatus === DeliveryStatus.DELIVERED) {
      const msg = await generateTrackingMessage(newStatus, delivery.customerName);
      setAiMessage(msg);
      setTimeout(() => setAiMessage(null), 5000);
    }
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.includes(searchQuery) || d.customerName.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driverList = Array.from(new Set(deliveries.map(d => d.driverName)));
  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar for Roles */}
      <aside className="w-full md:w-64 bg-slate-900 text-white p-6 space-y-8 flex flex-col sticky top-0 md:h-screen">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-600 rounded-lg">
            <Package className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-2">
          <button 
            onClick={() => setRole('ADMIN')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${role === 'ADMIN' ? 'bg-blue-600 shadow-lg' : 'hover:bg-slate-800'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            <span className="font-medium text-sm">Administrador</span>
          </button>
          <button 
            onClick={() => setRole('DRIVER')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${role === 'DRIVER' ? 'bg-blue-600 shadow-lg' : 'hover:bg-slate-800'}`}
          >
            <Truck className="w-5 h-5" />
            <span className="font-medium text-sm">Portal do Motorista</span>
          </button>
          <button 
            onClick={() => setRole('CUSTOMER')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${role === 'CUSTOMER' ? 'bg-blue-600 shadow-lg' : 'hover:bg-slate-800'}`}
          >
            <User className="w-5 h-5" />
            <span className="font-medium text-sm">Rastreio Cliente</span>
          </button>
        </nav>

        <div className="pt-6 border-t border-slate-800">
           <div className="flex items-center gap-3 p-3 bg-slate-800 rounded-xl">
             <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-xs font-bold">SL</div>
             <div className="flex-1 min-w-0">
               <p className="text-sm font-medium truncate">Equipe Logística</p>
               <p className="text-xs text-slate-400">Logado</p>
             </div>
           </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-10 space-y-8">

        {/* Gemini Feedback Alert */}
        {aiMessage && (
          <div className="fixed top-5 right-5 z-50 animate-bounce">
            <div className="bg-green-100 border border-green-200 text-green-800 px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-4">
              <CheckCircle2 className="w-6 h-6 text-green-600" />
              <div>
                <p className="font-bold">Notificação IA</p>
                <p className="text-sm opacity-90">{aiMessage}</p>
              </div>
            </div>
          </div>
        )}

        {/* View Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h2 className="text-3xl font-bold tracking-tight text-slate-900">
              {role === 'ADMIN' && "Gestão de Carregamentos"}
              {role === 'DRIVER' && "Minhas Entregas"}
              {role === 'CUSTOMER' && "Rastrear meu Pedido"}
            </h2>
            <p className="text-slate-500 mt-1">
              {role === 'ADMIN' && "Importe planilhas e gerencie a frota."}
              {role === 'DRIVER' && "Gerencie seu roteiro e realize o check-out."}
              {role === 'CUSTOMER' && "Consulte o status em tempo real."}
            </p>
          </div>

          {role === 'ADMIN' && (
            <label className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl font-semibold cursor-pointer transition-all shadow-lg hover:shadow-blue-200">
              <FileUp className="w-5 h-5" />
              Importar Excel
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

          {/* Main List Section */}
          <div className="lg:col-span-2 space-y-6">

            {/* Search/Filter Bar */}
            <div className="relative group">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" />
              <input 
                type="text" 
                placeholder={role === 'DRIVER' ? "Pesquisar no roteiro..." : "Digite o número do pedido ou nome do cliente..."}
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-12 pr-4 py-4 bg-white border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 outline-none transition-all shadow-sm"
              />
            </div>

            {/* Role Specific Filters/Selectors */}
            {role === 'DRIVER' && (
              <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
                <Truck className="text-slate-400" />
                <select 
                  value={selectedDriver}
                  onChange={(e) => setSelectedDriver(e.target.value)}
                  className="flex-1 bg-transparent border-none outline-none font-medium text-slate-700"
                >
                  <option value="">Selecione seu nome de Motorista...</option>
                  {driverList.map(name => <option key={name} value={name}>{name}</option>)}
                </select>
              </div>
            )}

            {/* List Component */}
            <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b border-slate-200">
                    <tr>
                      <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Pedido</th>
                      <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Destinatário</th>
                      <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Status</th>
                      <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider text-right">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {(role === 'DRIVER' ? driversOrders : (role === 'CUSTOMER' && searchQuery ? filteredDeliveries : (role === 'ADMIN' ? filteredDeliveries : []))).map((delivery) => (
                      <tr key={delivery.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4">
                          <span className="font-mono text-blue-600 font-bold">#{delivery.orderNumber}</span>
                          <p className="text-xs text-slate-400 mt-0.5">{delivery.driverName}</p>
                        </td>
                        <td className="px-6 py-4">
                          <p className="font-medium text-slate-800">{delivery.customerName}</p>
                          <p className="text-xs text-slate-500 flex items-center gap-1">
                            <MapPin className="w-3 h-3" /> {delivery.address}
                          </p>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`px-3 py-1 rounded-full text-xs font-bold inline-flex items-center gap-1 ${
                            delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-100 text-green-700' :
                            delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-blue-100 text-blue-700' :
                            'bg-orange-100 text-orange-700'
                          }`}>
                            {delivery.status === DeliveryStatus.PENDING && <Clock className="w-3 h-3" />}
                            {delivery.status === DeliveryStatus.IN_TRANSIT && <Truck className="w-3 h-3" />}
                            {delivery.status === DeliveryStatus.DELIVERED && <CheckCircle2 className="w-3 h-3" />}
                            {delivery.status}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-right">
                          {role === 'DRIVER' && delivery.status !== DeliveryStatus.DELIVERED && (
                            <div className="flex justify-end gap-2">
                              {delivery.status === DeliveryStatus.PENDING && (
                                <button 
                                  onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)}
                                  className="text-xs font-bold bg-blue-600 text-white px-3 py-1.5 rounded-lg hover:bg-blue-700 transition-colors"
                                >
                                  Iniciar
                                </button>
                              )}
                              {delivery.status === DeliveryStatus.IN_TRANSIT && (
                                <button 
                                  onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)}
                                  className="text-xs font-bold bg-green-600 text-white px-3 py-1.5 rounded-lg hover:bg-green-700 transition-colors"
                                >
                                  Concluir
                                </button>
                              )}
                            </div>
                          )}
                          {(role === 'ADMIN' || (role === 'CUSTOMER' && searchQuery)) && (
                            <button className="p-2 hover:bg-slate-200 rounded-lg text-slate-400 transition-colors">
                              <ChevronRight className="w-5 h-5" />
