                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          {/* Map/Context Section */}
          <div className="space-y-6">
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <MapPin className="text-blue-600" />
                Visualização do Mapa
              </h3>
              <DeliveryMap 
                deliveries={role === 'CUSTOMER' ? filteredDeliveries : (role === 'DRIVER' ? driversOrders : deliveries)} 
                highlightId={role === 'CUSTOMER' && filteredDeliveries.length === 1 ? filteredDeliveries[0].id : undefined}
