                  <p className="text-xs text-slate-500 uppercase font-bold tracking-wider">Total</p>
                  <p className="text-2xl font-black text-slate-800">{deliveries.length}</p>
                </div>
                <div className="bg-green-50 p-3 rounded-xl border border-green-100">
                  <p className="text-xs text-green-600 uppercase font-bold tracking-wider">Entregues</p>
                  <p className="text-2xl font-black text-green-700">
                    {deliveries.filter(d => d.status === DeliveryStatus.DELIVERED).length}
                  </p>
                </div>
              </div>
            </div>

            {/* Quick Insights */}
            <div className="bg-slate-900 p-6 rounded-2xl text-white space-y-4 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-4 opacity-10">
                 <Settings className="w-20 h-20 rotate-12" />
               </div>
               <h3 className="text-lg font-bold">Resumo da Operação</h3>
               <p className="text-sm text-slate-400 leading-relaxed">
                 O sistema monitora automaticamente as janelas de entrega e produtividade da frota.
                 {deliveries.length > 0 && ` No momento, temos ${deliveries.filter(d => d.status === DeliveryStatus.IN_TRANSIT).length} motoristas em rota.`}
               </p>
               <button className="w-full py-3 bg-white/10 hover:bg-white/20 rounded-xl font-medium text-sm transition-colors backdrop-blur-sm">
                 Ver Relatórios Detalhados
               </button>
            </div>
          </div>

        </div>

        {loading && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-8 rounded-3xl shadow-2xl flex flex-col items-center gap-4">
                <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-bold text-slate-800">Processando Planilha...</p>
             </div>
          </div>
        )}

      </main>
    </div>
  );
};

export default App;

