import React, { useState, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Search, 
  FileUp, 
  CheckCircle2, 
  Clock, 
  MapPin, 
  ChevronRight,
  LayoutDashboard,
  Users,
  Plus,
  Trash2,
  DollarSign,
  AlertCircle
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import DeliveryMap from './components/DeliveryMap';
import { generateTrackingMessage } from './services/geminiService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [role, setRole] = useState<UserRole>('CUSTOMER');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);

  // Import Flow State
  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');

  // Driver Management State
  const [newDriverName, setNewDriverName] = useState('');

  // Load from LocalStorage
  useEffect(() => {
    const savedDeliveries = localStorage.getItem('swiftlog_deliveries');
    const savedDrivers = localStorage.getItem('swiftlog_drivers');
    if (savedDeliveries) setDeliveries(JSON.parse(savedDeliveries));
    if (savedDrivers) setDrivers(JSON.parse(savedDrivers));
    else {
      // Default sample driver
      setDrivers([{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }]);
    }
  }, []);

  // Save to LocalStorage
  useEffect(() => {
    localStorage.setItem('swiftlog_deliveries', JSON.stringify(deliveries));
  }, [deliveries]);

  useEffect(() => {
    localStorage.setItem('swiftlog_drivers', JSON.stringify(drivers));
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];

        // Read as array of arrays to target specific columns
        // B = index 1, D = index 3, F = index 5
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });

        // Skip header if it exists (usually row 0)
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          if (!row[1] && !row[5]) return null; // Skip empty rows
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            address: 'São Paulo, SP' // Placeholder, normally parsed from a full address column
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        console.error("Error parsing Excel:", err);
        alert("Erro ao ler o arquivo Excel. Verifique o formato.");
      } finally {
        setLoading(false);
        e.target.value = ''; // Reset input
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = () => {
    if (!pendingImport || !importDriverId) return;

    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -23.5505 + (Math.random() - 0.5) * 0.1,
      lng: -46.6333 + (Math.random() - 0.5) * 0.1,
    }));

    setDeliveries(prev => [...prev, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const addDriver = () => {
    if (!newDriverName.trim()) return;
    const newDriver: Driver = {
      id: crypto.randomUUID(),
      name: newDriverName.trim(),
    };
    setDrivers([...drivers, newDriver]);
    setNewDriverName('');
  };

  const removeDriver = (id: string) => {
