export enum DeliveryStatus {
  PENDING = 'PENDENTE',
  IN_TRANSIT = 'EM TRÂNSITO',
  DELIVERED = 'ENTREGUE',
  FAILED = 'FALHA NA ENTREGA'
}

export interface Driver {
  id: string;
  name: string;
  phone?: string;
  vehicle?: string;
}

export interface Delivery {
  id: string;
  orderNumber: string;
  customerName: string;
  orderValue: number;
  address: string;
  driverName: string;
  status: DeliveryStatus;
  updatedAt: string;
  completedAt?: string;
  lat: number;
  lng: number;
  notes?: string;
  receiptPhoto?: string; // Base64 image
}

export type UserRole = 'ADMIN' | 'DRIVER' | 'CUSTOMER' | 'DRIVERS_MGMT';

export interface AppState {
  deliveries: Delivery[];
  drivers: Driver[];
  currentUserRole: UserRole;
  selectedDriver: string | null;
}

const DB_NAME = 'SwiftLogDB';
const DB_VERSION = 1;
const STORE_DELIVERIES = 'deliveries';
const STORE_DRIVERS = 'drivers';

export const initDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onupgradeneeded = () => {
      const db = request.result;
      if (!db.objectStoreNames.contains(STORE_DELIVERIES)) {
        db.createObjectStore(STORE_DELIVERIES, { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains(STORE_DRIVERS)) {
        db.createObjectStore(STORE_DRIVERS, { keyPath: 'id' });
      }
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

export const saveData = async (storeName: string, data: any[]) => {
  const db = await initDB();
  const tx = db.transaction(storeName, 'readwrite');
  const store = tx.objectStore(storeName);
  // Simple clear and refill for this app's scale
  await new Promise<void>((resolve) => {
    const clearReq = store.clear();
    clearReq.onsuccess = () => resolve();
  });
  data.forEach(item => store.put(item));
  return new Promise((resolve) => {
    tx.oncomplete = () => resolve(true);
  });
};

export const getData = async (storeName: string): Promise<any[]> => {
  const db = await initDB();
  const tx = db.transaction(storeName, 'readonly');
  const store = tx.objectStore(storeName);
  return new Promise((resolve) => {
    const request = store.getAll();
    request.onsuccess = () => resolve(request.result);
  });
};

