import { saveData, getData } from './services/dbService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [role, setRole] = useState<UserRole>('CUSTOMER');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);

  // Modals
  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initial Load from IndexedDB
  useEffect(() => {
    const loadData = async () => {
      const dls = await getData('deliveries');
      const drs = await getData('drivers');
      if (dls.length) setDeliveries(dls);
      if (drs.length) setDrivers(drs);
      else {
        const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
        setDrivers(defaultDrivers);
        await saveData('drivers', defaultDrivers);
      }
    };
    loadData();
  }, []);

  // Sync to IndexedDB on changes
  useEffect(() => {
    if (deliveries.length > 0) saveData('deliveries', deliveries);
  }, [deliveries]);

  useEffect(() => {
    if (drivers.length > 0) saveData('drivers', drivers);
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            address: 'São Paulo, SP'
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel.");
      } finally {
        setLoading(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -23.5505 + (Math.random() - 0.5) * 0.1,
      lng: -46.6333 + (Math.random() - 0.5) * 0.1,
    }));

    const updated = [...deliveries, ...newDeliveries];
    setDeliveries(updated);
    await saveData('deliveries', updated);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      const updated = deliveries.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      );
      setDeliveries(updated);
      await saveData('deliveries', updated);

      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const updateDeliveryStatus = async (id: string, newStatus: DeliveryStatus) => {
    if (newStatus === DeliveryStatus.DELIVERED) {
      const delivery = deliveries.find(d => d.id === id);
      setPhotoModal({ id, customer: delivery?.customerName || '' });
      return;
    }

    const updated = deliveries.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    );
    setDeliveries(updated);
    await saveData('deliveries', updated);
  };

  const addDriver = async () => {
    if (!newDriverName.trim()) return;
    const newDriver: Driver = { id: crypto.randomUUID(), name: newDriverName.trim() };
    const updated = [...drivers, newDriver];
    setDrivers(updated);
    await saveData('drivers', updated);
    setNewDriverName('');
  };

  const removeDriver = async (id: string) => {
    const updated = drivers.filter(d => d.id !== id);
    setDrivers(updated);
    await saveData('drivers', updated);
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-slate-900 text-white p-6 space-y-8 flex flex-col sticky top-0 md:h-screen z-20 shadow-2xl">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-600 rounded-lg">
            <Package className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {[
            { id: 'ADMIN', label: 'Painel Geral', icon: LayoutDashboard },
            { id: 'DRIVERS_MGMT', label: 'Motoristas', icon: Users },
            { id: 'DRIVER', label: 'Portal Motorista', icon: Truck },
            { id: 'CUSTOMER', label: 'Rastreio Cliente', icon: User },
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => setRole(item.id as UserRole)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${role === item.id ? 'bg-blue-600 shadow-lg' : 'hover:bg-slate-800 text-slate-400'}`}
            >
              <item.icon className="w-5 h-5" />
              <span className="font-medium text-sm">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="pt-6 border-t border-slate-800">
           <div className="flex items-center gap-3 p-3 bg-slate-800 rounded-xl">
             <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-xs font-bold text-white uppercase tracking-tighter">DB</div>
             <div className="flex-1 min-w-0">
               <p className="text-xs font-bold truncate">BANCO DE DADOS</p>
               <p className="text-[10px] text-green-400 font-bold uppercase">Persistência Ativa</p>
             </div>
           </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8 lg:p-12 space-y-8 relative">

        {/* Floating AI Notification */}
        {aiMessage && (
          <div className="fixed top-5 right-5 z-50 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="bg-white border-l-4 border-green-500 text-slate-800 px-6 py-4 rounded-xl shadow-2xl flex items-center gap-4">
              <CheckCircle2 className="w-6 h-6 text-green-500" />
              <div>
                <p className="font-bold text-sm">Entrega Concluída!</p>
                <p className="text-xs text-slate-500 italic">"{aiMessage}"</p>
              </div>
            </div>
          </div>
        )}

        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h2 className="text-3xl font-black tracking-tight text-slate-900">
              {role === 'ADMIN' && "Controle de Entregas"}
              {role === 'DRIVERS_MGMT' && "Base de Parceiros"}
              {role === 'DRIVER' && "Minha Rota"}
              {role === 'CUSTOMER' && "Rastreio Realtime"}
            </h2>
            <p className="text-slate-500 font-medium">Operação logística com prova de entrega fotográfica.</p>
          </div>
          {role === 'ADMIN' && (
            <label className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black cursor-pointer transition-all shadow-xl hover:shadow-blue-200 uppercase text-xs tracking-widest">
              <FileUp className="w-4 h-4" />
              Importar Excel
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </header>

        {role === 'DRIVERS_MGMT' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-1 bg-white p-8 rounded-3xl border border-slate-200 shadow-sm space-y-6">
              <h3 className="font-black text-slate-800 flex items-center gap-2 uppercase text-sm">
                <Plus className="w-5 h-5 text-blue-600" />
                Cadastrar Motorista
              </h3>
              <div className="space-y-4">
                <input 
                  type="text" 
                  placeholder="Nome do motorista..."
                  value={newDriverName}
                  onChange={(e) => setNewDriverName(e.target.value)}
                  className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-100 outline-none transition-all font-bold"
                />
                <button 
                  onClick={addDriver}
                  className="w-full bg-slate-900 hover:bg-black text-white font-black py-4 rounded-2xl transition-all shadow-lg uppercase text-xs tracking-widest"
                >
                  Adicionar à Base
                </button>
              </div>
            </div>
            <div className="lg:col-span-2 bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 border-b border-slate-200">
                  <tr>
                    <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Parceiro</th>
                    <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ação</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {drivers.map(driver => (
                    <tr key={driver.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-8 py-5 font-bold text-slate-800">{driver.name}</td>
                      <td className="px-8 py-5 text-right">
                        <button onClick={() => removeDriver(driver.id)} className="p-3 text-red-400 hover:bg-red-50 rounded-xl transition-all"><Trash2 className="w-4 h-4" /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {(role === 'ADMIN' || role === 'DRIVER' || role === 'CUSTOMER') && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-6">

              <div className="relative group">
                <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" />
                <input 
                  type="text" 
                  placeholder={role === 'CUSTOMER' ? "Qual o número do seu pedido?" : "Filtrar por pedido ou fantasia..."}
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-14 pr-6 py-5 bg-white border border-slate-200 rounded-3xl focus:ring-8 focus:ring-blue-50 outline-none transition-all shadow-sm font-bold text-slate-700"
                />
              </div>

              {role === 'DRIVER' && (
                <div className="bg-blue-600 p-5 rounded-3xl shadow-xl flex items-center gap-4 text-white">
                  <Truck className="w-6 h-6" />
                  <select 
                    value={selectedDriver}
                    onChange={(e) => setSelectedDriver(e.target.value)}
                    className="flex-1 bg-white/10 border-none outline-none font-black text-sm uppercase tracking-wider p-2 rounded-xl"
                  >
                    <option value="" className="text-slate-900">Selecione seu Nome...</option>
                    {drivers.map(d => <option key={d.id} value={d.name} className="text-slate-900">{d.name}</option>)}
                  </select>
                </div>
              )}

              <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead className="bg-slate-50 border-b border-slate-200">
                      <tr>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Carga</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Cliente / Valor</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Status</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {(role === 'DRIVER' ? driversOrders : (role === 'CUSTOMER' && searchQuery ? filteredDeliveries : (role === 'ADMIN' ? filteredDeliveries : []))).map((delivery) => (
                        <tr key={delivery.id} className="hover:bg-slate-50 transition-colors group">
                          <td className="px-8 py-5">
                            <span className="font-mono text-blue-600 font-black text-base block">#{delivery.orderNumber}</span>
                            <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">{delivery.driverName}</span>
                          </td>
                          <td className="px-8 py-5">
                            <p className="font-bold text-slate-800">{delivery.customerName}</p>
                            <p className="text-xs text-green-600 font-black flex items-center gap-1">
                              <DollarSign className="w-3 h-3" />
                              {delivery.orderValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                            </p>
                          </td>
                          <td className="px-8 py-5 text-center">
                            <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest inline-flex items-center gap-2 ${
                              delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-100 text-green-700' :
                              delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-blue-100 text-blue-700' :
                              'bg-orange-100 text-orange-700'
                            }`}>
                              {delivery.status}
                            </span>
                          </td>
                          <td className="px-8 py-5 text-right">
                            <div className="flex justify-end gap-2">
                              {role === 'DRIVER' && delivery.status !== DeliveryStatus.DELIVERED && (
                                <>
                                  {delivery.status === DeliveryStatus.PENDING && (
                                    <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)} className="bg-blue-600 hover:bg-blue-700 text-white p-2 rounded-xl transition-all shadow-md"><Truck className="w-4 h-4" /></button>
                                  )}
                                  {delivery.status === DeliveryStatus.IN_TRANSIT && (
                                    <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)} className="bg-green-600 hover:bg-green-700 text-white flex items-center gap-2 px-4 py-2 rounded-xl transition-all shadow-md font-black text-[10px] uppercase tracking-widest"><Camera className="w-4 h-4" /> Finalizar</button>
                                  )}
                                </>
                              )}
                              {(role === 'ADMIN' || role === 'CUSTOMER' || (role === 'DRIVER' && delivery.status === DeliveryStatus.DELIVERED)) && delivery.receiptPhoto && (
                                <button onClick={() => setViewPhoto(delivery.receiptPhoto || null)} className="p-3 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all flex items-center gap-2 font-black text-[10px] uppercase tracking-widest">
                                  <ImageIcon className="w-4 h-4" /> Canhoto
                                </button>
                              )}
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>

            <div className="space-y-6">
              <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm space-y-4">
                <h3 className="font-black text-slate-800 flex items-center gap-2 uppercase text-xs tracking-widest">
                  <MapPin className="w-4 h-4 text-blue-600" /> Monitoramento
                </h3>
                <DeliveryMap 
                  deliveries={role === 'CUSTOMER' ? filteredDeliveries : (role === 'DRIVER' ? driversOrders : deliveries)} 
                  highlightId={role === 'CUSTOMER' && filteredDeliveries.length === 1 ? filteredDeliveries[0].id : undefined}
                />
              </div>

              <div className="bg-slate-900 p-8 rounded-3xl text-white space-y-4 shadow-2xl relative overflow-hidden">
                <div className="relative z-10">
                  <h3 className="text-xl font-black uppercase tracking-widest">Stats</h3>
                  <div className="grid grid-cols-2 gap-4 mt-6">
                    <div>
                      <p className="text-[10px] font-black text-slate-500 uppercase">Em Rota</p>
                      <p className="text-2xl font-black">{deliveries.filter(d => d.status === DeliveryStatus.IN_TRANSIT).length}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-black text-green-500 uppercase">Finalizadas</p>
                      <p className="text-2xl font-black text-green-400">{deliveries.filter(d => d.status === DeliveryStatus.DELIVERED).length}</p>
                    </div>
                  </div>
                </div>
                <div className="absolute -bottom-10 -right-10 opacity-10">
                  <Truck className="w-40 h-40" />
                </div>
              </div>
            </div>
          </div>
        )}

        {/* PHOTO CAPTURE MODAL */}
        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 space-y-8 animate-in zoom-in-95 duration-200 shadow-2xl">
              <div className="text-center space-y-3">
                <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Camera className="w-10 h-10" />
                </div>
                <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Comprovar Entrega</h3>
                <p className="text-sm text-slate-500 font-medium leading-relaxed">Para finalizar o pedido para <span className="text-slate-900 font-black">{photoModal.customer}</span>, tire uma foto nítida do canhoto assinado.</p>
              </div>

              <div className="space-y-4">
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl transition-all shadow-xl flex items-center justify-center gap-3 uppercase text-xs tracking-widest"
                >
                  <Camera className="w-5 h-5" /> Abrir Câmera / Galeria
                </button>
                <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
                <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[10px] tracking-widest hover:text-slate-600 transition-colors">Cancelar</button>
              </div>
            </div>
          </div>
        )}

        {/* IMPORT DRIVER MODAL */}
        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-50 p-4">
            <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl p-10 space-y-8">
              <div className="text-center">
                <div className="w-20 h-20 bg-blue-100 text-blue-600 rounded-3xl flex items-center justify-center mx-auto mb-6 rotate-3">
                  <Package className="w-10 h-10" />
                </div>
                <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Atribuir Carga</h3>
                <p className="text-slate-500 mt-2 font-medium">Detectamos <span className="text-blue-600 font-black">{pendingImport.length} pedidos</span> na planilha.</p>
              </div>

              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Motorista Responsável</label>
                  <select 
                    value={importDriverId}
                    onChange={(e) => setImportDriverId(e.target.value)}
                    className="w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-3xl font-black text-slate-800 focus:ring-8 focus:ring-blue-50 outline-none appearance-none cursor-pointer shadow-inner"
                  >
                    <option value="">Selecione o parceiro...</option>
                    {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                  </select>
                </div>

                <div className="flex gap-4 pt-4">
                  <button onClick={() => setPendingImport(null)} className="flex-1 py-5 rounded-2xl font-black text-slate-400 hover:bg-slate-50 transition-all uppercase text-xs tracking-widest">Voltar</button>
                  <button 
                    onClick={confirmImport}
                    disabled={!importDriverId}
                    className="flex-1 py-5 bg-slate-900 hover:bg-black text-white rounded-3xl font-black transition-all shadow-2xl disabled:opacity-20 uppercase text-xs tracking-widest"
                  >
                    Confirmar Rota
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* PHOTO VIEW MODAL */}
        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-2xl w-full" onClick={e => e.stopPropagation()}>
              <button onClick={() => setViewPhoto(null)} className="absolute -top-12 right-0 text-white p-2 hover:bg-white/10 rounded-full transition-all"><X className="w-8 h-8" /></button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-3xl shadow-2xl border-4 border-white/10" />
              <p className="text-center text-white/50 mt-4 font-black uppercase text-[10px] tracking-widest">Comprovante Digitalizado SwiftLog</p>
            </div>
          </div>
        )}

        {loading && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-12 rounded-[3rem] shadow-2xl flex flex-col items-center gap-6 border border-slate-100 animate-pulse">
                <div className="w-16 h-16 border-8 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-xs">Sincronizando Banco de Dados...</p>
             </div>
          </div>
        )}

      </main>
    </div>
  );
};

export default App;

export enum DeliveryStatus {
  PENDING = 'PENDENTE',
  IN_TRANSIT = 'EM TRÂNSITO',
  DELIVERED = 'ENTREGUE',
  FAILED = 'FALHA NA ENTREGA',
  REJECTED = 'DEVOLVIDO'
}

export interface Driver {
  id: string;
  name: string;
  phone?: string;
  vehicle?: string;
}

export interface Delivery {
  id: string;
  orderNumber: string;
  customerName: string;
  orderValue: number;
  city: string;
  address: string;
  driverName: string;
