  const [aiMessage, setAiMessage] = useState<string | null>(null);

  // Modals
  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initial Load from IndexedDB
  useEffect(() => {
    const loadData = async () => {
      const dls = await getData('deliveries');
      const drs = await getData('drivers');
      if (dls.length) setDeliveries(dls);
      if (drs.length) setDrivers(drs);
      else {
        const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
        setDrivers(defaultDrivers);
        await saveData('drivers', defaultDrivers);
      }
    };
    loadData();
  }, []);

  // Sync to IndexedDB on changes
  useEffect(() => {
    if (deliveries.length >= 0) saveData('deliveries', deliveries);
  }, [deliveries]);

  useEffect(() => {
    if (drivers.length >= 0) saveData('drivers', drivers);
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          // B=1, D=3, F=5, J=9
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: `${String(row[9] || 'Belém')}, Pará`
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel.");
      } finally {
        setLoading(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      // Coordenadas aproximadas do Pará para Belém e arredores
      lat: -1.4558 + (Math.random() - 0.5) * 2.0,
      lng: -48.4902 + (Math.random() - 0.5) * 4.0,
    }));

    const updated = [...deliveries, ...newDeliveries];
    setDeliveries(updated);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
