                <tbody className="divide-y divide-slate-100">
                  {drivers.map(driver => (
                    <tr key={driver.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-8 py-5 font-bold text-slate-800">{driver.name}</td>
                      <td className="px-8 py-5 text-right">
                        <button onClick={() => removeDriver(driver.id)} className="p-3 text-red-400 hover:bg-red-50 rounded-xl transition-all"><Trash2 className="w-4 h-4" /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* MODALS */}

        {/* Mandatory Photo Modal */}
        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 space-y-8 shadow-2xl border-4 border-green-500/20">
              <div className="text-center space-y-4">
                <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <Camera className="w-12 h-12" />
                </div>
                <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">FOTO OBRIGATÓRIA</h3>
                <p className="text-sm text-slate-500 font-medium leading-relaxed">
                   A entrega para <strong>{photoModal.customer}</strong> exige a foto do canhoto assinado para ser finalizada no sistema.
                </p>
              </div>

              <div className="space-y-4">
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl transition-all shadow-xl flex items-center justify-center gap-3 uppercase text-xs tracking-widest"
                >
                  <Camera className="w-5 h-5" /> Abrir Câmera
                </button>
                <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
                <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[10px] tracking-widest hover:text-slate-600 transition-colors">Cancelar</button>
              </div>
            </div>
          </div>
        )}

        {/* Rejection Modal */}
        {rejectionModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 space-y-8 shadow-2xl border-4 border-red-500/20 text-center">
              <div className="w-20 h-20 bg-red-100 text-red-600 rounded-full flex items-center justify-center mx-auto">
                <RotateCcw className="w-10 h-10" />
              </div>
              <div className="space-y-2">
                <h3 className="text-2xl font-black text-slate-900 uppercase">Devolver Pedido?</h3>
                <p className="text-slate-500 font-medium">Você confirma que o cliente <strong>{rejectionModal.customer}</strong> recusou a mercadoria?</p>
              </div>
              <div className="flex gap-4">
                 <button onClick={() => setRejectionModal(null)} className="flex-1 py-4 font-black text-slate-400 uppercase text-xs">Não</button>
                 <button onClick={finalizeRejection} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-black uppercase text-xs shadow-lg">Confirmar Devolução</button>
              </div>
            </div>
          </div>
        )}

        {/* Pending Import Driver Assign */}
        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-50 p-4">
            <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl p-10 space-y-8">
              <div className="text-center">
                <div className="w-20 h-20 bg-blue-100 text-blue-600 rounded-3xl flex items-center justify-center mx-auto mb-6 rotate-2 shadow-inner">
                  <Package className="w-10 h-10" />
                </div>
                <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Carregar Rota</h3>
                <p className="text-slate-500 mt-2 font-medium">Encontramos <span className="text-blue-600 font-black">{pendingImport.length} pedidos</span>. Atribua um motorista:</p>
              </div>

              <div className="space-y-6">
                <select 
                  value={importDriverId}
                  onChange={(e) => setImportDriverId(e.target.value)}
                  className="w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-3xl font-black text-slate-800 focus:ring-8 focus:ring-blue-50 outline-none appearance-none cursor-pointer"
                >
                  <option value="">Selecione o parceiro...</option>
                  {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                </select>

                <div className="flex gap-4 pt-4">
                  <button onClick={() => setPendingImport(null)} className="flex-1 py-5 rounded-2xl font-black text-slate-400 hover:bg-slate-50 transition-all uppercase text-xs tracking-widest">Cancelar</button>
                  <button 
                    onClick={confirmImport}
                    disabled={!importDriverId}
                    className="flex-1 py-5 bg-slate-900 hover:bg-black text-white rounded-3xl font-black transition-all shadow-2xl disabled:opacity-20 uppercase text-xs tracking-widest"
                  >
                    Gerar Carregamento
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Photo View Overlay */}
        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-2xl w-full" onClick={e => e.stopPropagation()}>
              <button onClick={() => setViewPhoto(null)} className="absolute -top-12 right-0 text-white p-2 hover:bg-white/10 rounded-full transition-all"><X className="w-8 h-8" /></button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-3xl shadow-2xl border-4 border-white/20" />
            </div>
          </div>
        )}

        {loading && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-12 rounded-[3rem] shadow-2xl flex flex-col items-center gap-6 animate-pulse">
                <div className="w-16 h-16 border-8 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-xs">Lendo dados do Pará...</p>
             </div>
          </div>
        )}

      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Search, 
  FileUp, 
  CheckCircle2, 
  Clock, 
  MapPin, 
  ChevronRight,
  LayoutDashboard,
  Users,
  Plus,
  Trash2,
  DollarSign,
  AlertCircle,
  Camera,
  X,
  Eye,
  Image as ImageIcon,
  RotateCcw,
  Navigation
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import DeliveryMap from './components/DeliveryMap';
import { generateTrackingMessage } from './services/geminiService';
import { saveData, getData } from './services/dbService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [role, setRole] = useState<UserRole>('CUSTOMER');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);

  // Fix: Added missing state variables for the driver management view
  const [newDriverName, setNewDriverName] = useState('');

  // Modals
  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initial Load from IndexedDB
  useEffect(() => {
    const loadData = async () => {
      const dls = await getData('deliveries');
      const drs = await getData('drivers');
      if (dls.length) setDeliveries(dls);
      if (drs.length) setDrivers(drs);
      else {
        const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
        setDrivers(defaultDrivers);
        await saveData('drivers', defaultDrivers);
      }
    };
    loadData();
  }, []);

  // Sync to IndexedDB on changes
  useEffect(() => {
    if (deliveries.length >= 0) saveData('deliveries', deliveries);
  }, [deliveries]);

  useEffect(() => {
    if (drivers.length >= 0) saveData('drivers', drivers);
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          // B=1, D=3, F=5, J=9
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: `${String(row[9] || 'Belém')}, Pará`
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel.");
      } finally {
        setLoading(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      // Coordenadas aproximadas do Pará para Belém e arredores
      lat: -1.4558 + (Math.random() - 0.5) * 2.0,
      lng: -48.4902 + (Math.random() - 0.5) * 4.0,
    }));

    const updated = [...deliveries, ...newDeliveries];
    setDeliveries(updated);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      const updated = deliveries.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      );
      setDeliveries(updated);

      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const finalizeRejection = async () => {
    if (!rejectionModal) return;
    const updated = deliveries.map(d => 
      d.id === rejectionModal.id ? { 
        ...d, 
        status: DeliveryStatus.REJECTED, 
        updatedAt: new Date().toISOString(),
        notes: 'Cliente recusou a entrega'
      } : d
    );
    setDeliveries(updated);
    setRejectionModal(null);
    setAiMessage("Entrega marcada como devolvida.");
    setTimeout(() => setAiMessage(null), 3000);
  };

  const updateDeliveryStatus = async (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;

    // Obrigatoriedade da foto para Entregue
    if (newStatus === DeliveryStatus.DELIVERED) {
      setPhotoModal({ id, customer: delivery.customerName });
      return;
    }

    // Modal de confirmação para Devolução
    if (newStatus === DeliveryStatus.REJECTED) {
      setRejectionModal({ id, customer: delivery.customerName });
      return;
    }

    const updated = deliveries.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    );
    setDeliveries(updated);
  };

  const addDriver = async () => {
    // Fix: Using the correct state newDriverName
    if (!newDriverName.trim()) return;
    const newDriver: Driver = { id: crypto.randomUUID(), name: newDriverName.trim() };
    setDrivers([...drivers, newDriver]);
    setNewDriverName('');
  };

  const removeDriver = async (id: string) => {
    setDrivers(drivers.filter(d => d.id !== id));
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-slate-900 text-white p-6 space-y-8 flex flex-col sticky top-0 md:h-screen z-20 shadow-2xl">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-600 rounded-lg">
            <Package className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {[
            { id: 'ADMIN', label: 'Painel Geral', icon: LayoutDashboard },
            { id: 'DRIVERS_MGMT', label: 'Motoristas', icon: Users },
            { id: 'DRIVER', label: 'Portal Motorista', icon: Truck },
            { id: 'CUSTOMER', label: 'Rastreio Cliente', icon: User },
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => setRole(item.id as UserRole)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${role === item.id ? 'bg-blue-600 shadow-lg' : 'hover:bg-slate-800 text-slate-400'}`}
            >
              <item.icon className="w-5 h-5" />
              <span className="font-medium text-sm">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="pt-6 border-t border-slate-800">
           <div className="flex items-center gap-3 p-3 bg-slate-800 rounded-xl">
             <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-xs font-bold text-white uppercase tracking-tighter">PA</div>
             <div className="flex-1 min-w-0">
               <p className="text-xs font-bold truncate tracking-widest uppercase">Operação Pará</p>
               <p className="text-[10px] text-blue-400 font-bold uppercase">Estado Ativo</p>
             </div>
           </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8 lg:p-12 space-y-8 relative">

        {aiMessage && (
          <div className="fixed top-5 right-5 z-50 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="bg-white border-l-4 border-green-500 text-slate-800 px-6 py-4 rounded-xl shadow-2xl flex items-center gap-4">
              <CheckCircle2 className="w-6 h-6 text-green-500" />
              <div>
                <p className="font-bold text-sm">Atualização do Sistema</p>
                <p className="text-xs text-slate-500">{aiMessage}</p>
              </div>
            </div>
          </div>
        )}

        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h2 className="text-3xl font-black tracking-tight text-slate-900 uppercase">
              {role === 'ADMIN' && "Controle SwiftLog"}
              {role === 'DRIVERS_MGMT' && "Base de Motoristas"}
              {role === 'DRIVER' && "Meu Roteiro"}
              {role === 'CUSTOMER' && "Onde está meu pedido?"}
            </h2>
            <p className="text-slate-500 font-medium">Gestão logística especializada para o estado do Pará.</p>
          </div>
          {role === 'ADMIN' && (
            <label className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black cursor-pointer transition-all shadow-xl hover:shadow-blue-200 uppercase text-xs tracking-widest">
              <FileUp className="w-4 h-4" />
              Carregar Planilha
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </header>

        {(role === 'ADMIN' || role === 'DRIVER' || role === 'CUSTOMER') && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-6">

              <div className="relative group">
                <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" />
                <input 
                  type="text" 
                  placeholder={role === 'CUSTOMER' ? "Número do Pedido ou Nome..." : "Filtrar entregas ou cidades..."}
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-14 pr-6 py-5 bg-white border border-slate-200 rounded-3xl focus:ring-8 focus:ring-blue-50 outline-none transition-all shadow-sm font-bold text-slate-700"
                />
              </div>

              {role === 'DRIVER' && (
                <div className="bg-slate-900 p-5 rounded-3xl shadow-xl flex items-center gap-4 text-white">
                  <div className="bg-blue-600 p-3 rounded-2xl"><Truck className="w-5 h-5" /></div>
                  <select 
                    value={selectedDriver}
                    onChange={(e) => setSelectedDriver(e.target.value)}
                    className="flex-1 bg-white/5 border-none outline-none font-black text-sm uppercase tracking-widest p-3 rounded-xl"
                  >
                    <option value="" className="text-slate-900">IDENTIFIQUE-SE...</option>
                    {drivers.map(d => <option key={d.id} value={d.name} className="text-slate-900">{d.name}</option>)}
                  </select>
                </div>
              )}

              <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead className="bg-slate-50 border-b border-slate-200">
                      <tr>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Entrega</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Cidade / Valor</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Status</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100 font-sans">
                      {(role === 'DRIVER' ? driversOrders : (role === 'CUSTOMER' && searchQuery ? filteredDeliveries : (role === 'ADMIN' ? filteredDeliveries : []))).map((delivery) => (
                        <tr key={delivery.id} className="hover:bg-slate-50 transition-colors group">
                          <td className="px-8 py-5">
                            <span className="font-mono text-blue-600 font-black text-base block">#{delivery.orderNumber}</span>
                            <span className="text-[10px] font-bold text-slate-500 uppercase tracking-tighter block mt-1">{delivery.customerName}</span>
                          </td>
                          <td className="px-8 py-5">
                            <p className="font-bold text-slate-800 flex items-center gap-1">
                               <MapPin className="w-3 h-3 text-red-500" /> {delivery.city}, PA
                            </p>
                            <p className="text-xs text-green-600 font-black flex items-center gap-1">
                              <DollarSign className="w-3 h-3" />
                              {delivery.orderValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                            </p>
                          </td>
                          <td className="px-8 py-5 text-center">
                            <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest inline-flex items-center gap-2 ${
                              delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-100 text-green-700 border border-green-200' :
                              delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-blue-100 text-blue-700 border border-blue-200' :
                              delivery.status === DeliveryStatus.REJECTED ? 'bg-red-100 text-red-700 border border-red-200' :
                              'bg-orange-100 text-orange-700 border border-orange-200'
                            }`}>
                              {delivery.status}
                            </span>
                          </td>
                          <td className="px-8 py-5 text-right">
                            <div className="flex justify-end gap-2">
                              {role === 'DRIVER' && (delivery.status !== DeliveryStatus.DELIVERED && delivery.status !== DeliveryStatus.REJECTED) && (
                                <>
                                  {delivery.status === DeliveryStatus.PENDING && (
                                    <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)} className="bg-blue-600 hover:bg-blue-700 text-white p-2.5 rounded-xl transition-all shadow-md"><Navigation className="w-4 h-4" /></button>
                                  )}
                                  {delivery.status === DeliveryStatus.IN_TRANSIT && (
                                    <div className="flex gap-2">
                                      <button 
                                        onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} 
                                        className="bg-red-100 hover:bg-red-200 text-red-700 p-2.5 rounded-xl transition-all border border-red-200 shadow-sm flex items-center gap-1 text-[9px] font-black uppercase"
                                      >
                                        <RotateCcw className="w-4 h-4" /> Devolver
                                      </button>
                                      <button 
                                        onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)} 
                                        className="bg-green-600 hover:bg-green-700 text-white flex items-center gap-2 px-4 py-2 rounded-xl transition-all shadow-lg font-black text-[10px] uppercase tracking-widest"
                                      >
                                        <Camera className="w-4 h-4" /> Finalizar
                                      </button>
                                    </div>
                                  )}
                                </>
                              )}
                              {delivery.receiptPhoto && (
                                <button onClick={() => setViewPhoto(delivery.receiptPhoto || null)} className="p-3 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all flex items-center gap-2 font-black text-[10px] uppercase tracking-widest">
                                  <ImageIcon className="w-4 h-4" /> Ver Canhoto
                                </button>
                              )}
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>

            <div className="space-y-6">
              <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm space-y-4">
                <h3 className="font-black text-slate-800 flex items-center gap-2 uppercase text-[10px] tracking-widest">
                  <MapPin className="w-4 h-4 text-blue-600" /> Rastreamento PA
                </h3>
                <DeliveryMap 
                  deliveries={role === 'CUSTOMER' ? filteredDeliveries : (role === 'DRIVER' ? driversOrders : deliveries)} 
                  highlightId={role === 'CUSTOMER' && filteredDeliveries.length === 1 ? filteredDeliveries[0].id : undefined}
                />
              </div>

              <div className="bg-slate-900 p-8 rounded-3xl text-white space-y-6 shadow-2xl relative overflow-hidden">
                <h3 className="text-sm font-black uppercase tracking-widest border-b border-white/10 pb-4">Desempenho da Rota</h3>
                <div className="grid grid-cols-2 gap-6 relative z-10">
                  <div className="space-y-1">
                    <p className="text-[9px] font-black text-slate-500 uppercase">Total Carregado</p>
                    <p className="text-xl font-black">{deliveries.length}</p>
                  </div>
                  <div className="space-y-1">
                    <p className="text-[9px] font-black text-green-500 uppercase">Entregue</p>
                    <p className="text-xl font-black text-green-400">{deliveries.filter(d => d.status === DeliveryStatus.DELIVERED).length}</p>
                  </div>
                  <div className="space-y-1">
                    <p className="text-[9px] font-black text-red-500 uppercase">Devoluções</p>
                    <p className="text-xl font-black text-red-400">{deliveries.filter(d => d.status === DeliveryStatus.REJECTED).length}</p>
                  </div>
                  <div className="space-y-1">
                    <p className="text-[9px] font-black text-blue-500 uppercase">Em Rota</p>
                    <p className="text-xl font-black text-blue-400">{deliveries.filter(d => d.status === DeliveryStatus.IN_TRANSIT).length}</p>
                  </div>
                </div>
                <div className="absolute -bottom-10 -right-10 opacity-5 pointer-events-none">
                  <Truck className="w-48 h-48" />
                </div>
              </div>
            </div>
          </div>
        )}

        {/* DRIVERS_MGMT VIEW */}
        {role === 'DRIVERS_MGMT' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-1 bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm space-y-6">
              <h3 className="font-black text-slate-800 flex items-center gap-2 uppercase text-xs tracking-widest">
                <Plus className="w-5 h-5 text-blue-600" />
                Novo Parceiro
              </h3>
              <div className="space-y-4">
                <input 
                  type="text" 
                  placeholder="Nome do motorista..."
                  value={newDriverName}
                  onChange={(e) => setNewDriverName(e.target.value)}
                  className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-100 outline-none transition-all font-bold"
                />
                <button 
                  onClick={addDriver}
                  className="w-full bg-slate-900 hover:bg-black text-white font-black py-4 rounded-2xl transition-all shadow-lg uppercase text-xs tracking-widest"
                >
                  Cadastrar
                </button>
              </div>
            </div>
            <div className="lg:col-span-2 bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50 border-b border-slate-200">
                  <tr>
                    <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome</th>
                    <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ação</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {drivers.map(driver => (
                    <tr key={driver.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-8 py-5 font-bold text-slate-800">{driver.name}</td>
                      <td className="px-8 py-5 text-right">
                        <button onClick={() => removeDriver(driver.id)} className="p-3 text-red-400 hover:bg-red-50 rounded-xl transition-all"><Trash2 className="w-4 h-4" /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* MODALS */}

        {/* Mandatory Photo Modal */}
        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 space-y-8 shadow-2xl border-4 border-green-500/20">
              <div className="text-center space-y-4">
                <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <Camera className="w-12 h-12" />
                </div>
                <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">FOTO OBRIGATÓRIA</h3>
                <p className="text-sm text-slate-500 font-medium leading-relaxed">
                   A entrega para <strong>{photoModal.customer}</strong> exige a foto do canhoto assinado para ser finalizada no sistema.
                </p>
              </div>

              <div className="space-y-4">
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl transition-all shadow-xl flex items-center justify-center gap-3 uppercase text-xs tracking-widest"
                >
                  <Camera className="w-5 h-5" /> Abrir Câmera
                </button>
                <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
                <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[10px] tracking-widest hover:text-slate-600 transition-colors">Cancelar</button>
              </div>
            </div>
          </div>
        )}

        {/* Rejection Modal */}
        {rejectionModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 space-y-8 shadow-2xl border-4 border-red-500/20 text-center">
              <div className="w-20 h-20 bg-red-100 text-red-600 rounded-full flex items-center justify-center mx-auto">
                <RotateCcw className="w-10 h-10" />
              </div>
              <div className="space-y-2">
                <h3 className="text-2xl font-black text-slate-900 uppercase">Devolver Pedido?</h3>
                <p className="text-slate-500 font-medium">Você confirma que o cliente <strong>{rejectionModal.customer}</strong> recusou a mercadoria?</p>
              </div>
              <div className="flex gap-4">
                 <button onClick={() => setRejectionModal(null)} className="flex-1 py-4 font-black text-slate-400 uppercase text-xs">Não</button>
                 <button onClick={finalizeRejection} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-black uppercase text-xs shadow-lg">Confirmar Devolução</button>
              </div>
            </div>
          </div>
        )}

        {/* Pending Import Driver Assign */}
        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-50 p-4">
            <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl p-10 space-y-8">
              <div className="text-center">
                <div className="w-20 h-20 bg-blue-100 text-blue-600 rounded-3xl flex items-center justify-center mx-auto mb-6 rotate-2 shadow-inner">
                  <Package className="w-10 h-10" />
                </div>
                <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Carregar Rota</h3>
                <p className="text-slate-500 mt-2 font-medium">Encontramos <span className="text-blue-600 font-black">{pendingImport.length} pedidos</span>. Atribua um motorista:</p>
              </div>

              <div className="space-y-6">
                <select 
                  value={importDriverId}
                  onChange={(e) => setImportDriverId(e.target.value)}
                  className="w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-3xl font-black text-slate-800 focus:ring-8 focus:ring-blue-50 outline-none appearance-none cursor-pointer"
                >
                  <option value="">Selecione o parceiro...</option>
                  {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                </select>

                <div className="flex gap-4 pt-4">
                  <button onClick={() => setPendingImport(null)} className="flex-1 py-5 rounded-2xl font-black text-slate-400 hover:bg-slate-50 transition-all uppercase text-xs tracking-widest">Cancelar</button>
                  <button 
                    onClick={confirmImport}
                    disabled={!importDriverId}
                    className="flex-1 py-5 bg-slate-900 hover:bg-black text-white rounded-3xl font-black transition-all shadow-2xl disabled:opacity-20 uppercase text-xs tracking-widest"
                  >
                    Gerar Carregamento
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Photo View Overlay */}
        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-2xl w-full" onClick={e => e.stopPropagation()}>
              <button onClick={() => setViewPhoto(null)} className="absolute -top-12 right-0 text-white p-2 hover:bg-white/10 rounded-full transition-all"><X className="w-8 h-8" /></button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-3xl shadow-2xl border-4 border-white/20" />
            </div>
          </div>
        )}

        {loading && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-12 rounded-[3rem] shadow-2xl flex flex-col items-center gap-6 animate-pulse">
                <div className="w-16 h-16 border-8 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-xs">Lendo dados do Pará...</p>
             </div>
          </div>
        )}

      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Search, 
  FileUp, 
  CheckCircle2, 
  Clock, 
  MapPin, 
  ChevronRight,
  LayoutDashboard,
  Users,
  Plus,
  Trash2,
  DollarSign,
  AlertCircle,
  Camera,
  X,
  ImageIcon,
  RotateCcw,
  Navigation
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import DeliveryMap from './components/DeliveryMap';
import { generateTrackingMessage } from './services/geminiService';
import { saveData, getData } from './services/dbService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [role, setRole] = useState<UserRole>('CUSTOMER');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [newDriverName, setNewDriverName] = useState('');

  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadData = async () => {
      const dls = await getData('deliveries');
      const drs = await getData('drivers');
      if (dls.length) setDeliveries(dls);
      if (drs.length) setDrivers(drs);
      else {
        const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
        setDrivers(defaultDrivers);
        await saveData('drivers', defaultDrivers);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    if (deliveries.length >= 0) saveData('deliveries', deliveries);
  }, [deliveries]);

  useEffect(() => {
    if (drivers.length >= 0) saveData('drivers', drivers);
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          // B=1 (Pedido), D=3 (Valor), F=5 (Fantasia), I=8 (Endereço), J=9 (Cidade)
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: String(row[8] || `${row[9] || 'Belém'}, Pará`)
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel.");
      } finally {
        setLoading(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -1.4558 + (Math.random() - 0.5) * 1.5,
      lng: -48.4902 + (Math.random() - 0.5) * 3.0,
    }));

    setDeliveries([...deliveries, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      const updated = deliveries.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      );
      setDeliveries(updated);

      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const finalizeRejection = async () => {
    if (!rejectionModal) return;
    const updated = deliveries.map(d => 
      d.id === rejectionModal.id ? { 
        ...d, 
        status: DeliveryStatus.REJECTED, 
        updatedAt: new Date().toISOString(),
        notes: 'Cliente recusou a entrega'
      } : d
    );
    setDeliveries(updated);
    setRejectionModal(null);
    setAiMessage("Entrega marcada como devolvida.");
    setTimeout(() => setAiMessage(null), 3000);
  };

  const updateDeliveryStatus = async (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;

    if (newStatus === DeliveryStatus.DELIVERED) {
      setPhotoModal({ id, customer: delivery.customerName });
      return;
    }

    if (newStatus === DeliveryStatus.REJECTED) {
      setRejectionModal({ id, customer: delivery.customerName });
      return;
    }

    const updated = deliveries.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    );
    setDeliveries(updated);
  };

  const addDriver = async () => {
    if (!newDriverName.trim()) return;
    const newDriver: Driver = { id: crypto.randomUUID(), name: newDriverName.trim() };
    setDrivers([...drivers, newDriver]);
    setNewDriverName('');
  };

  const removeDriver = async (id: string) => {
    setDrivers(drivers.filter(d => d.id !== id));
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.address.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      <aside className="w-full md:w-64 bg-slate-900 text-white p-6 space-y-8 flex flex-col sticky top-0 md:h-screen z-20 shadow-2xl">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-600 rounded-lg">
            <Package className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {[
            { id: 'ADMIN', label: 'Painel Geral', icon: LayoutDashboard },
            { id: 'DRIVERS_MGMT', label: 'Motoristas', icon: Users },
            { id: 'DRIVER', label: 'Portal Motorista', icon: Truck },
            { id: 'CUSTOMER', label: 'Rastreio Cliente', icon: User },
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => setRole(item.id as UserRole)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${role === item.id ? 'bg-blue-600 shadow-lg' : 'hover:bg-slate-800 text-slate-400'}`}
            >
              <item.icon className="w-5 h-5" />
              <span className="font-medium text-sm">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="pt-6 border-t border-slate-800">
           <div className="flex items-center gap-3 p-3 bg-slate-800 rounded-xl">
             <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-xs font-bold text-white uppercase tracking-tighter">PA</div>
             <div className="flex-1 min-w-0">
               <p className="text-xs font-bold truncate tracking-widest uppercase">Operação Pará</p>
               <p className="text-[10px] text-blue-400 font-bold uppercase">Estado Ativo</p>
             </div>
           </div>
        </div>
      </aside>

      <main className="flex-1 overflow-y-auto p-4 md:p-8 lg:p-12 space-y-8 relative">
        {aiMessage && (
          <div className="fixed top-5 right-5 z-50 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="bg-white border-l-4 border-green-500 text-slate-800 px-6 py-4 rounded-xl shadow-2xl flex items-center gap-4">
              <CheckCircle2 className="w-6 h-6 text-green-500" />
              <div>
                <p className="font-bold text-sm">Atualização do Sistema</p>
                <p className="text-xs text-slate-500">{aiMessage}</p>
              </div>
            </div>
          </div>
        )}

        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h2 className="text-3xl font-black tracking-tight text-slate-900 uppercase">
              {role === 'ADMIN' && "Controle SwiftLog"}
              {role === 'DRIVERS_MGMT' && "Base de Motoristas"}
              {role === 'DRIVER' && "Meu Roteiro"}
              {role === 'CUSTOMER' && "Rastreio de Pedidos"}
            </h2>
            <p className="text-slate-500 font-medium">Monitoramento logístico especializado em tempo real.</p>
          </div>
          {role === 'ADMIN' && (
            <label className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black cursor-pointer transition-all shadow-xl hover:shadow-blue-200 uppercase text-xs tracking-widest">
              <FileUp className="w-4 h-4" />
              Carregar Excel
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </header>

        {(role === 'ADMIN' || role === 'DRIVER' || role === 'CUSTOMER') && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-6">
              <div className="relative group">
                <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" />
                <input 
                  type="text" 
                  placeholder={role === 'CUSTOMER' ? "Qual o número do seu pedido?" : "Filtrar por cliente, pedido ou cidade..."}
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-14 pr-6 py-5 bg-white border border-slate-200 rounded-3xl focus:ring-8 focus:ring-blue-50 outline-none transition-all shadow-sm font-bold text-slate-700"
                />
              </div>

              {role === 'DRIVER' && (
                <div className="bg-slate-900 p-5 rounded-3xl shadow-xl flex items-center gap-4 text-white">
                  <div className="bg-blue-600 p-3 rounded-2xl"><Truck className="w-5 h-5" /></div>
                  <select 
                    value={selectedDriver}
                    onChange={(e) => setSelectedDriver(e.target.value)}
                    className="flex-1 bg-white/5 border-none outline-none font-black text-sm uppercase tracking-widest p-3 rounded-xl"
                  >
                    <option value="" className="text-slate-900">SELECIONE SEU NOME...</option>
                    {drivers.map(d => <option key={d.id} value={d.name} className="text-slate-900">{d.name}</option>)}
                  </select>
                </div>
              )}

              <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead className="bg-slate-50 border-b border-slate-200">
                      <tr>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pedido / Cidade</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Cliente (Fantasia)</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Status</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {(role === 'DRIVER' ? driversOrders : (role === 'CUSTOMER' && searchQuery ? filteredDeliveries : (role === 'ADMIN' ? filteredDeliveries : []))).map((delivery) => (
                        <tr key={delivery.id} className="hover:bg-slate-50 transition-colors group">
                          <td className="px-8 py-6">
                            <span className="font-mono text-blue-600 font-black text-base block leading-none">#{delivery.orderNumber}</span>
                            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tight block mt-1.5 flex items-center gap-1">
                               <MapPin className="w-3 h-3 text-red-400" /> {delivery.city}, PA
                            </span>
                          </td>
                          <td className="px-8 py-6">
                            <p className="font-black text-slate-900 text-lg leading-tight tracking-tight uppercase">{delivery.customerName}</p>
