        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 space-y-8 shadow-2xl border-4 border-green-500/20">
              <div className="text-center space-y-4">
                <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <Camera className="w-12 h-12" />
                </div>
                <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter leading-none">REGISTRO DE CANHOTO</h3>
                <p className="text-sm text-slate-500 font-medium leading-relaxed">
                   Capture a foto do comprovante para finalizar a entrega de <strong>{photoModal.customer}</strong>.
                </p>
              </div>

              <div className="space-y-4">
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl transition-all shadow-xl flex items-center justify-center gap-3 uppercase text-xs tracking-widest"
                >
                  <Camera className="w-5 h-5" /> Abrir Câmera
                </button>
                <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
                <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[10px] tracking-widest hover:text-slate-600 transition-colors">Cancelar</button>
              </div>
