              <div className="space-y-2">
                <h3 className="text-2xl font-black text-slate-900 uppercase">Confirmar Devolução?</h3>
                <p className="text-slate-500 font-medium">O cliente <strong>{rejectionModal.customer}</strong> recusou o pedido?</p>
              </div>
              <div className="flex gap-4">
                 <button onClick={() => setRejectionModal(null)} className="flex-1 py-4 font-black text-slate-400 uppercase text-xs">Não</button>
                 <button onClick={finalizeRejection} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-black uppercase text-xs shadow-lg">Sim, Devolvido</button>
              </div>
            </div>
          </div>
        )}

        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-50 p-4">
            <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl p-10 space-y-8">
              <div className="text-center">
                <div className="w-20 h-20 bg-blue-100 text-blue-600 rounded-3xl flex items-center justify-center mx-auto mb-6 rotate-2 shadow-inner">
                  <Package className="w-10 h-10" />
                </div>
                <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tighter leading-none">GERAR ROTA</h3>
                <p className="text-slate-500 mt-2 font-medium">Detectamos <span className="text-blue-600 font-black">{pendingImport.length} pedidos</span>. Escolha o motorista:</p>
              </div>

              <div className="space-y-6">
                <select 
                  value={importDriverId}
                  onChange={(e) => setImportDriverId(e.target.value)}
                  className="w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-3xl font-black text-slate-800 focus:ring-8 focus:ring-blue-50 outline-none appearance-none cursor-pointer"
                >
                  <option value="">Selecione o parceiro...</option>
                  {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                </select>

                <div className="flex gap-4 pt-4">
                  <button onClick={() => setPendingImport(null)} className="flex-1 py-5 rounded-2xl font-black text-slate-400 hover:bg-slate-50 transition-all uppercase text-xs tracking-widest">Cancelar</button>
                  <button 
                    onClick={confirmImport}
                    disabled={!importDriverId}
                    className="flex-1 py-5 bg-slate-900 hover:bg-black text-white rounded-3xl font-black transition-all shadow-2xl disabled:opacity-20 uppercase text-xs tracking-widest"
                  >
                    Confirmar Carga
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-2xl w-full" onClick={e => e.stopPropagation()}>
              <button onClick={() => setViewPhoto(null)} className="absolute -top-12 right-0 text-white p-2 hover:bg-white/10 rounded-full transition-all"><X className="w-8 h-8" /></button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-3xl shadow-2xl border-4 border-white/20" />
            </div>
          </div>
        )}

        {loading && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-12 rounded-[3rem] shadow-2xl flex flex-col items-center gap-6 animate-pulse">
                <div className="w-16 h-16 border-8 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-xs">Processando Carregamento...</p>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Search, 
  FileUp, 
  CheckCircle2, 
  Clock, 
  MapPin, 
  ChevronRight,
  LayoutDashboard,
  Users,
  Plus,
  Trash2,
  DollarSign,
  AlertCircle,
  Camera,
  X,
  ImageIcon,
  RotateCcw,
  Navigation,
  BarChart3,
  ClipboardList
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import { generateTrackingMessage } from './services/geminiService';
import { saveData, getData } from './services/dbService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [role, setRole] = useState<UserRole>('CUSTOMER');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [newDriverName, setNewDriverName] = useState('');

  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadData = async () => {
      const dls = await getData('deliveries');
      const drs = await getData('drivers');
      if (dls.length) setDeliveries(dls);
      if (drs.length) setDrivers(drs);
      else {
        const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
        setDrivers(defaultDrivers);
        await saveData('drivers', defaultDrivers);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    if (deliveries.length >= 0) saveData('deliveries', deliveries);
  }, [deliveries]);

  useEffect(() => {
    if (drivers.length >= 0) saveData('drivers', drivers);
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          // B=1 (Pedido), D=3 (Valor), F=5 (Fantasia), I=8 (Endereço Completo), J=9 (Cidade)
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: String(row[8] || `${row[9] || 'Belém'}, Pará`)
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel.");
      } finally {
        setLoading(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -1.4558 + (Math.random() - 0.5) * 1.5,
      lng: -48.4902 + (Math.random() - 0.5) * 3.0,
    }));

    setDeliveries([...deliveries, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      const updated = deliveries.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      );
      setDeliveries(updated);

      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const finalizeRejection = async () => {
    if (!rejectionModal) return;
    const updated = deliveries.map(d => 
      d.id === rejectionModal.id ? { 
        ...d, 
        status: DeliveryStatus.REJECTED, 
        updatedAt: new Date().toISOString(),
        notes: 'Cliente recusou a entrega'
      } : d
    );
    setDeliveries(updated);
    setRejectionModal(null);
    setAiMessage("Entrega marcada como devolvida.");
    setTimeout(() => setAiMessage(null), 3000);
  };

  const updateDeliveryStatus = async (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;

    if (newStatus === DeliveryStatus.DELIVERED) {
      setPhotoModal({ id, customer: delivery.customerName });
      return;
    }

    if (newStatus === DeliveryStatus.REJECTED) {
      setRejectionModal({ id, customer: delivery.customerName });
      return;
    }

    const updated = deliveries.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    );
    setDeliveries(updated);
  };

  const addDriver = async () => {
    if (!newDriverName.trim()) return;
    const newDriver: Driver = { id: crypto.randomUUID(), name: newDriverName.trim() };
    setDrivers([...drivers, newDriver]);
    setNewDriverName('');
  };

  const removeDriver = async (id: string) => {
    setDrivers(drivers.filter(d => d.id !== id));
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.address.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);

  // KPIs
  const totalOrders = role === 'DRIVER' ? driversOrders.length : deliveries.length;
  const deliveredCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.DELIVERED).length;
  const inTransitCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.IN_TRANSIT).length;
  const rejectedCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.REJECTED).length;

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-72 bg-slate-900 text-white p-6 space-y-8 flex flex-col sticky top-0 md:h-screen z-20 shadow-2xl">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-blue-600 rounded-xl shadow-lg shadow-blue-900/20">
            <Package className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-2xl font-black tracking-tighter">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {[
            { id: 'ADMIN', label: 'Painel de Controle', icon: LayoutDashboard },
            { id: 'DRIVERS_MGMT', label: 'Frota / Parceiros', icon: Users },
            { id: 'DRIVER', label: 'Portal do Motorista', icon: Truck },
            { id: 'CUSTOMER', label: 'Rastreio do Cliente', icon: Search },
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => {
                setRole(item.id as UserRole);
                setSearchQuery('');
              }}
              className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all ${role === item.id ? 'bg-blue-600 shadow-xl shadow-blue-900/40 text-white font-bold' : 'hover:bg-slate-800 text-slate-400 font-medium'}`}
            >
              <item.icon className="w-5 h-5" />
              <span className="text-sm">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="pt-6 border-t border-slate-800">
           <div className="flex items-center gap-4 p-4 bg-slate-800/50 rounded-[1.5rem] border border-slate-700/50">
             <div className="w-10 h-10 rounded-2xl bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-xs font-black text-white shadow-lg">PA</div>
             <div className="flex-1 min-w-0">
               <p className="text-xs font-black truncate tracking-widest uppercase text-slate-100">Regional Pará</p>
               <p className="text-[10px] text-blue-400 font-bold uppercase flex items-center gap-1">
                 <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span> Sistema Ativo
               </p>
             </div>
           </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8 lg:p-12 space-y-10 relative">
        {aiMessage && (
          <div className="fixed top-5 right-5 z-50 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="bg-white border-l-4 border-blue-600 text-slate-800 px-8 py-5 rounded-[1.5rem] shadow-2xl flex items-center gap-4 border border-slate-100">
              <div className="bg-blue-50 p-2 rounded-full"><CheckCircle2 className="w-6 h-6 text-blue-600" /></div>
              <div>
                <p className="font-black text-xs uppercase tracking-widest text-blue-600">Mensagem do Sistema</p>
                <p className="text-sm text-slate-600 font-medium">{aiMessage}</p>
              </div>
            </div>
          </div>
        )}

        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="space-y-1">
            <h2 className="text-4xl font-black tracking-tight text-slate-900 uppercase">
              {role === 'ADMIN' && "Controle SwiftLog"}
