import React, { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Search, 
  FileUp, 
  CheckCircle2, 
  Clock, 
  MapPin, 
  ChevronRight,
  LayoutDashboard,
  Users,
  Plus,
  Trash2,
  DollarSign,
  AlertCircle,
  Camera,
  X,
  ImageIcon,
  RotateCcw,
  Navigation,
  BarChart3,
  ClipboardList,
  Menu
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import { generateTrackingMessage } from './services/geminiService';
import { saveData, getData } from './services/dbService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [role, setRole] = useState<UserRole>('CUSTOMER');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [newDriverName, setNewDriverName] = useState('');
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadData = async () => {
      const dls = await getData('deliveries');
      const drs = await getData('drivers');
      if (dls.length) setDeliveries(dls);
      if (drs.length) setDrivers(drs);
      else {
        const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
        setDrivers(defaultDrivers);
        await saveData('drivers', defaultDrivers);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    if (deliveries.length >= 0) saveData('deliveries', deliveries);
  }, [deliveries]);

  useEffect(() => {
    if (drivers.length >= 0) saveData('drivers', drivers);
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: String(row[8] || `${row[9] || 'Belém'}, Pará`)
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel.");
      } finally {
        setLoading(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -1.4558,
      lng: -48.4902,
    }));

    setDeliveries([...deliveries, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      const updated = deliveries.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      );
      setDeliveries(updated);

      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const finalizeRejection = async () => {
    if (!rejectionModal) return;
    const updated = deliveries.map(d => 
      d.id === rejectionModal.id ? { 
        ...d, 
        status: DeliveryStatus.REJECTED, 
        updatedAt: new Date().toISOString(),
        notes: 'Cliente recusou a entrega'
      } : d
    );
    setDeliveries(updated);
    setRejectionModal(null);
    setAiMessage("Entrega marcada como devolvida.");
    setTimeout(() => setAiMessage(null), 3000);
  };

  const updateDeliveryStatus = async (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;

    if (newStatus === DeliveryStatus.DELIVERED) {
      setPhotoModal({ id, customer: delivery.customerName });
      return;
    }

    if (newStatus === DeliveryStatus.REJECTED) {
      setRejectionModal({ id, customer: delivery.customerName });
      return;
    }

    const updated = deliveries.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    );
    setDeliveries(updated);
  };

  const addDriver = async () => {
    if (!newDriverName.trim()) return;
    const newDriver: Driver = { id: crypto.randomUUID(), name: newDriverName.trim() };
    setDrivers([...drivers, newDriver]);
    setNewDriverName('');
  };

  const removeDriver = async (id: string) => {
    setDrivers(drivers.filter(d => d.id !== id));
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.address.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);

  // KPIs
  const totalOrders = role === 'DRIVER' ? driversOrders.length : deliveries.length;
  const deliveredCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.DELIVERED).length;
  const inTransitCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.IN_TRANSIT).length;
  const rejectedCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.REJECTED).length;

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">

      {/* Mobile Top Header */}
      <div className="md:hidden bg-slate-900 text-white p-4 flex items-center justify-between sticky top-0 z-40 shadow-lg">
        <div className="flex items-center gap-2">
          <div className="p-1.5 bg-blue-600 rounded-lg">
            <Package className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-xl font-black tracking-tighter">SwiftLog</h1>
        </div>
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          className="p-2 hover:bg-slate-800 rounded-lg transition-colors"
        >
          {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-72 bg-slate-900 text-white p-6 space-y-6 flex flex-col transition-transform duration-300 transform 
        ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:relative md:translate-x-0 md:flex shadow-2xl
      `}>
        <div className="hidden md:flex items-center gap-3 mb-4">
          <div className="p-2 bg-blue-600 rounded-xl">
            <Package className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-2xl font-black tracking-tighter">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {[
            { id: 'ADMIN', label: 'Painel Geral', icon: LayoutDashboard },
            { id: 'DRIVERS_MGMT', label: 'Motoristas', icon: Users },
            { id: 'DRIVER', label: 'Meu Portal', icon: Truck },
            { id: 'CUSTOMER', label: 'Rastreio Cliente', icon: Search },
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => {
                setRole(item.id as UserRole);
                setSearchQuery('');
                setIsMenuOpen(false);
              }}
              className={`w-full flex items-center gap-4 px-4 py-3.5 rounded-2xl transition-all ${role === item.id ? 'bg-blue-600 shadow-lg text-white font-bold' : 'hover:bg-slate-800 text-slate-400 font-medium'}`}
            >
              <item.icon className="w-5 h-5" />
              <span className="text-sm">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="pt-4 border-t border-slate-800">
           <div className="flex items-center gap-3 p-3 bg-slate-800/50 rounded-2xl">
             <div className="w-8 h-8 rounded-lg bg-blue-500 flex items-center justify-center text-[10px] font-black text-white">PA</div>
             <div className="flex-1 min-w-0">
               <p className="text-[10px] font-black truncate uppercase text-slate-100">Regional Pará</p>
               <p className="text-[9px] text-blue-400 font-bold uppercase">Sistema Online</p>
             </div>
           </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8 space-y-6 relative">
        {aiMessage && (
          <div className="fixed top-5 right-5 z-50 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="bg-white border-l-4 border-blue-600 text-slate-800 px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 border border-slate-100">
              <CheckCircle2 className="w-5 h-5 text-blue-600" />
              <p className="text-xs text-slate-600 font-bold">{aiMessage}</p>
            </div>
          </div>
        )}

        <header className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div>
            <h2 className="text-2xl md:text-3xl font-black tracking-tight text-slate-900 uppercase">
              {role === 'ADMIN' && "Controle"}
              {role === 'DRIVERS_MGMT' && "Motoristas"}
              {role === 'DRIVER' && "Meu Roteiro"}
              {role === 'CUSTOMER' && "Rastreio"}
            </h2>
            <p className="text-slate-500 text-sm font-medium">Logística Pará</p>
          </div>
          {role === 'ADMIN' && (
            <label className="flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-3 rounded-xl font-black cursor-pointer transition-all shadow-lg active:scale-95 uppercase text-[10px] tracking-widest">
              <FileUp className="w-4 h-4" />
              Importar Excel
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </header>

        {/* Compact KPIs */}
        <section className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4">
          <div className="bg-white p-4 md:p-5 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
             <div className="bg-blue-50 p-2 rounded-xl"><ClipboardList className="w-5 h-5 text-blue-600" /></div>
             <div>
               <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Pedidos</p>
               <p className="text-xl font-black text-slate-900 leading-none">{totalOrders}</p>
             </div>
          </div>
          <div className="bg-white p-4 md:p-5 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
             <div className="bg-indigo-50 p-2 rounded-xl"><Truck className="w-5 h-5 text-indigo-600" /></div>
             <div>
               <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Em Rota</p>
               <p className="text-xl font-black text-indigo-600 leading-none">{inTransitCount}</p>
             </div>
          </div>
          <div className="bg-white p-4 md:p-5 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
             <div className="bg-green-50 p-2 rounded-xl"><CheckCircle2 className="w-5 h-5 text-green-600" /></div>
             <div>
               <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Entregues</p>
               <p className="text-xl font-black text-green-600 leading-none">{deliveredCount}</p>
             </div>
          </div>
          <div className="bg-white p-4 md:p-5 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
             <div className="bg-red-50 p-2 rounded-xl"><RotateCcw className="w-5 h-5 text-red-600" /></div>
             <div>
               <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Devolvidos</p>
               <p className="text-xl font-black text-red-600 leading-none">{rejectedCount}</p>
             </div>
          </div>
        </section>

        {(role === 'ADMIN' || role === 'DRIVER' || role === 'CUSTOMER') && (
          <div className="space-y-4">
            <div className="relative group max-w-xl">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors w-4 h-4" />
              <input 
                type="text" 
                placeholder={role === 'CUSTOMER' ? "Número do pedido..." : "Pesquisar..."}
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-10 pr-4 py-3.5 bg-white border border-slate-200 rounded-xl focus:ring-4 focus:ring-blue-50 outline-none transition-all shadow-sm font-bold text-slate-700 text-sm"
              />
            </div>

            {role === 'DRIVER' && (
