                >
                  <option value="" className="text-slate-900">IDENTIFIQUE-SE...</option>
                  {drivers.map(d => <option key={d.id} value={d.name} className="text-slate-900">{d.name}</option>)}
                </select>
              </div>
            )}

            {/* List Table - Optimized for density */}
            <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b border-slate-100">
                    <tr>
                      <th className="px-5 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">Pedido</th>
                      <th className="px-5 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">Cliente / Fantasia</th>
                      <th className="px-5 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Status</th>
                      <th className="px-5 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Ação</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {(role === 'DRIVER' ? driversOrders : (role === 'CUSTOMER' && searchQuery ? filteredDeliveries : (role === 'ADMIN' ? filteredDeliveries : []))).map((delivery) => (
                      <tr key={delivery.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-5 py-3 align-top">
                          <span className="font-mono text-blue-600 font-black text-sm block">#{delivery.orderNumber}</span>
                          <span className="text-[9px] font-bold text-slate-400 uppercase flex items-center gap-1 mt-1">
                             <MapPin className="w-2.5 h-2.5" /> {delivery.city}
                          </span>
                        </td>
                        <td className="px-5 py-3 align-top">
                          <h3 className="font-black text-slate-900 text-sm md:text-base leading-tight uppercase truncate max-w-[150px] md:max-w-xs">{delivery.customerName}</h3>
                          <div className="flex flex-wrap items-center gap-2 mt-1">
                            <p className="text-[9px] text-green-600 font-black flex items-center gap-0.5 uppercase bg-green-50 px-1.5 py-0.5 rounded-lg">
                              <DollarSign className="w-2.5 h-2.5" />
                              {delivery.orderValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                            </p>
                            <p className="text-[8px] text-slate-400 font-medium italic truncate max-w-[120px]">{delivery.address}</p>
                          </div>
                        </td>
                        <td className="px-5 py-3 text-center align-top">
                          <span className={`px-2.5 py-1 rounded-lg text-[8px] font-black uppercase tracking-widest inline-flex items-center gap-1.5 border ${
                            delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-100 text-green-700 border-green-200' :
                            delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-indigo-100 text-indigo-700 border-indigo-200' :
                            delivery.status === DeliveryStatus.REJECTED ? 'bg-red-100 text-red-700 border-red-200' :
                            'bg-orange-100 text-orange-700 border-orange-200'
                          }`}>
                            <div className={`w-1.5 h-1.5 rounded-full ${
                              delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-500' :
                              delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-indigo-500' :
                              delivery.status === DeliveryStatus.REJECTED ? 'bg-red-500' : 'bg-orange-500'
                            }`}></div>
                            {delivery.status}
                          </span>
                        </td>
                        <td className="px-5 py-3 text-right align-top">
                          <div className="flex justify-end gap-2">
                            {role === 'DRIVER' && (delivery.status !== DeliveryStatus.DELIVERED && delivery.status !== DeliveryStatus.REJECTED) && (
                              <>
                                {delivery.status === DeliveryStatus.PENDING && (
                                  <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)} className="bg-indigo-600 text-white p-2 rounded-lg shadow-md active:scale-90"><Navigation className="w-3.5 h-3.5" /></button>
                                )}
                                {delivery.status === DeliveryStatus.IN_TRANSIT && (
                                  <div className="flex gap-2">
                                    <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 p-2 rounded-lg border border-red-100 active:scale-95"><RotateCcw className="w-3.5 h-3.5" /></button>
                                    <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)} className="bg-green-600 text-white flex items-center gap-1.5 px-3 py-1.5 rounded-lg font-black text-[9px] uppercase tracking-widest active:scale-95">
                                      <Camera className="w-3.5 h-3.5" /> Finalizar
                                    </button>
                                  </div>
                                )}
                              </>
                            )}
                            {delivery.receiptPhoto && (
                              <button onClick={() => setViewPhoto(delivery.receiptPhoto || null)} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all flex items-center gap-1 font-black text-[8px] uppercase tracking-widest border border-slate-50">
                                <ImageIcon className="w-3.5 h-3.5" /> Canhoto
                              </button>
                            )}
                          </div>
                        </td>
                      </tr>
                    ))}
                    {(role === 'CUSTOMER' && !searchQuery) && (
                       <tr>
                         <td colSpan={4} className="px-5 py-16 text-center">
                            <div className="flex flex-col items-center opacity-20">
                              <Search className="w-10 h-10 mb-2" />
                              <p className="text-xs font-black uppercase tracking-widest">Insira o número do pedido</p>
                            </div>
                         </td>
                       </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {role === 'DRIVERS_MGMT' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-1 bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4 h-fit">
              <h3 className="font-black text-slate-900 flex items-center gap-2 uppercase text-xs">
                <Plus className="w-4 h-4 text-blue-600" /> Novo Motorista
              </h3>
              <input 
                type="text" 
                placeholder="Nome..."
                value={newDriverName}
                onChange={(e) => setNewDriverName(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-4 focus:ring-blue-50 outline-none font-bold text-sm"
              />
              <button 
                onClick={addDriver}
                className="w-full bg-slate-900 text-white font-black py-3.5 rounded-xl uppercase text-[10px] tracking-widest active:scale-95"
              >
                Cadastrar
              </button>
            </div>
            <div className="lg:col-span-2 bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden h-fit">
              <table className="w-full text-left">
                <thead className="bg-slate-50 border-b border-slate-100">
                  <tr>
                    <th className="px-5 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest">Motorista</th>
                    <th className="px-5 py-3 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Ação</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {drivers.map(driver => (
                    <tr key={driver.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-5 py-3 font-black text-slate-900 text-sm uppercase">{driver.name}</td>
                      <td className="px-5 py-3 text-right">
                        <button onClick={() => removeDriver(driver.id)} className="p-2 text-red-400 hover:bg-red-50 rounded-lg active:scale-90"><Trash2 className="w-4 h-4" /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Modal Fixes */}
        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-3xl p-8 space-y-6 shadow-2xl">
              <div className="text-center space-y-4">
                <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <Camera className="w-8 h-8" />
                </div>
                <h3 className="text-xl font-black text-slate-900 uppercase tracking-tighter">FOTO DO CANHOTO</h3>
                <p className="text-xs text-slate-500 font-medium">Finalizar entrega para <strong>{photoModal.customer}</strong>.</p>
              </div>
              <button onClick={() => fileInputRef.current?.click()} className="w-full bg-blue-600 text-white font-black py-4 rounded-xl shadow-lg flex items-center justify-center gap-2 uppercase text-[10px] tracking-widest active:scale-95">
                <Camera className="w-4 h-4" /> Capturar Foto
              </button>
              <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
              <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[9px] tracking-widest">Cancelar</button>
            </div>
          </div>
        )}

        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4">
            <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl p-8 space-y-6">
              <div className="text-center">
                <h3 className="text-xl font-black text-slate-900 uppercase">IMPORTAR CARGA</h3>
                <p className="text-slate-500 text-xs mt-1"><strong>{pendingImport.length} pedidos</strong> encontrados.</p>
              </div>
              <select 
                value={importDriverId}
                onChange={(e) => setImportDriverId(e.target.value)}
                className="w-full px-4 py-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-slate-800 text-xs uppercase"
              >
                <option value="">Selecione o motorista...</option>
                {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
              <div className="flex gap-3">
                <button onClick={() => setPendingImport(null)} className="flex-1 py-3 text-[10px] font-black text-slate-400 uppercase">Voltar</button>
                <button onClick={confirmImport} disabled={!importDriverId} className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase shadow-lg disabled:opacity-30">Confirmar</button>
              </div>
            </div>
          </div>
        )}

        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-md w-full" onClick={e => e.stopPropagation()}>
              <button onClick={() => setViewPhoto(null)} className="absolute -top-10 right-0 text-white flex items-center gap-1 font-black text-[10px] uppercase tracking-widest"><X className="w-6 h-6" /> Fechar</button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-2xl shadow-2xl border-4 border-white/10" />
            </div>
          </div>
        )}

        {loading && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-8 rounded-3xl shadow-2xl flex flex-col items-center gap-4 animate-pulse">
                <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-[10px]">Aguarde...</p>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
