  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [newDriverName, setNewDriverName] = useState('');
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadData = async () => {
      const dls = await getData('deliveries');
      const drs = await getData('drivers');
      if (dls.length) setDeliveries(dls);
      if (drs.length) setDrivers(drs);
      else {
        const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
        setDrivers(defaultDrivers);
        await saveData('drivers', defaultDrivers);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    if (deliveries.length >= 0) saveData('deliveries', deliveries);
  }, [deliveries]);

  useEffect(() => {
    if (drivers.length >= 0) saveData('drivers', drivers);
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: String(row[8] || `${row[9] || 'Belém'}, Pará`)
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel.");
      } finally {
        setLoading(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -1.4558,
      lng: -48.4902,
    }));

    setDeliveries([...deliveries, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      const updated = deliveries.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      );
      setDeliveries(updated);

      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const finalizeRejection = async () => {
    if (!rejectionModal) return;
    const updated = deliveries.map(d => 
      d.id === rejectionModal.id ? { 
        ...d, 
        status: DeliveryStatus.REJECTED, 
        updatedAt: new Date().toISOString(),
        notes: 'Cliente recusou a entrega'
      } : d
    );
    setDeliveries(updated);
    setRejectionModal(null);
    setAiMessage("Entrega marcada como devolvida.");
    setTimeout(() => setAiMessage(null), 3000);
  };

  const updateDeliveryStatus = async (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;

    if (newStatus === DeliveryStatus.DELIVERED) {
      setPhotoModal({ id, customer: delivery.customerName });
      return;
    }

    if (newStatus === DeliveryStatus.REJECTED) {
      setRejectionModal({ id, customer: delivery.customerName });
      return;
    }

    const updated = deliveries.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    );
    setDeliveries(updated);
  };

  const addDriver = async () => {
    if (!newDriverName.trim()) return;
    const newDriver: Driver = { id: crypto.randomUUID(), name: newDriverName.trim() };
    setDrivers([...drivers, newDriver]);
    setNewDriverName('');
  };

  const removeDriver = async (id: string) => {
    setDrivers(drivers.filter(d => d.id !== id));
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.address.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);

  // KPIs
  const currentViewDeliveries = role === 'DRIVER' ? driversOrders : (role === 'CUSTOMER' && searchQuery ? filteredDeliveries : (role === 'ADMIN' ? filteredDeliveries : []));
  const totalOrders = role === 'DRIVER' ? driversOrders.length : deliveries.length;
  const deliveredCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.DELIVERED).length;
  const inTransitCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.IN_TRANSIT).length;
  const rejectedCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.REJECTED).length;

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">

      {/* Mobile Top Header - Compact */}
      <div className="md:hidden bg-slate-900 text-white px-4 py-3 flex items-center justify-between sticky top-0 z-40 shadow-md">
        <div className="flex items-center gap-2">
          <Package className="w-5 h-5 text-blue-500" />
          <h1 className="text-lg font-black tracking-tighter">SwiftLog</h1>
        </div>
        <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-1">
          {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {/* Sidebar - Collapsible */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white p-5 flex flex-col transition-transform duration-300 transform 
        ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:relative md:translate-x-0 md:flex shadow-2xl
      `}>
        <div className="hidden md:flex items-center gap-2 mb-6 px-2">
          <Package className="w-6 h-6 text-blue-500" />
          <h1 className="text-xl font-black tracking-tighter">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {[
            { id: 'ADMIN', label: 'Painel Geral', icon: LayoutDashboard },
            { id: 'DRIVERS_MGMT', label: 'Motoristas', icon: Users },
            { id: 'DRIVER', label: 'Meu Portal', icon: Truck },
            { id: 'CUSTOMER', label: 'Rastreio', icon: Search },
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => {
                setRole(item.id as UserRole);
                setSearchQuery('');
                setIsMenuOpen(false);
              }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${role === item.id ? 'bg-blue-600 text-white font-bold' : 'hover:bg-slate-800 text-slate-400 font-medium'}`}
            >
              <item.icon className="w-4 h-4" />
              <span className="text-xs uppercase tracking-wider">{item.label}</span>
            </button>
          ))}
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-6 space-y-4 overflow-x-hidden">

        {/* Compact Header */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div>
            <h2 className="text-xl font-black text-slate-900 uppercase leading-none">
              {role === 'ADMIN' && "Administração"}
              {role === 'DRIVERS_MGMT' && "Gestão de Frota"}
              {role === 'DRIVER' && "Minha Rota"}
              {role === 'CUSTOMER' && "Rastreamento"}
            </h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Regional Pará</p>
          </div>
          {role === 'ADMIN' && (
            <label className="flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2.5 rounded-lg font-bold cursor-pointer transition-all active:scale-95 uppercase text-[9px] tracking-widest">
              <FileUp className="w-4 h-4" /> Importar Excel
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </div>

        {/* Compact KPIs */}
        <section className="grid grid-cols-2 lg:grid-cols-4 gap-2 md:gap-4">
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-blue-50 p-2 rounded-lg"><ClipboardList className="w-4 h-4 text-blue-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Pedidos</p>
               <p className="text-lg font-black text-slate-900 leading-none">{totalOrders}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-indigo-50 p-2 rounded-lg"><Truck className="w-4 h-4 text-indigo-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Em Rota</p>
               <p className="text-lg font-black text-indigo-600 leading-none">{inTransitCount}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-green-50 p-2 rounded-lg"><CheckCircle2 className="w-4 h-4 text-green-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Entregues</p>
               <p className="text-lg font-black text-green-600 leading-none">{deliveredCount}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-red-50 p-2 rounded-lg"><RotateCcw className="w-4 h-4 text-red-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Devolvidos</p>
               <p className="text-lg font-black text-red-600 leading-none">{rejectedCount}</p>
             </div>
          </div>
        </section>

        {/* Search and Driver Selection */}
        <div className="flex flex-col md:flex-row gap-3">
          <div className="relative flex-1 group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input 
              type="text" 
              placeholder={role === 'CUSTOMER' ? "Número do pedido..." : "Pesquisar..."}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-9 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all font-bold text-slate-700 text-xs"
            />
          </div>

          {role === 'DRIVER' && (
            <div className="bg-slate-900 px-3 py-2 rounded-xl flex items-center gap-3 text-white">
              <Truck className="w-4 h-4 text-blue-400" />
              <select 
                value={selectedDriver}
                onChange={(e) => setSelectedDriver(e.target.value)}
                className="bg-transparent border-none outline-none font-black text-[10px] uppercase tracking-widest cursor-pointer text-white"
              >
                <option value="" className="text-slate-900">IDENTIFIQUE-SE</option>
                {drivers.map(d => <option key={d.id} value={d.name} className="text-slate-900">{d.name}</option>)}
              </select>
            </div>
          )}
        </div>

        {/* Deliveries List - Grid of Cards (No horizontal scroll!) */}
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-3">
          {currentViewDeliveries.map((delivery) => (
            <div key={delivery.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm hover:border-blue-300 transition-all flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-2">
                  <div className="flex flex-col">
                    <span className="font-mono text-blue-600 font-black text-sm">#{delivery.orderNumber}</span>
                    <span className="text-[9px] font-bold text-slate-400 uppercase flex items-center gap-1 mt-1">
                      <MapPin className="w-3 h-3 text-red-400" /> {delivery.city}
                    </span>
                  </div>
                  <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                    delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-50 text-green-700 border-green-200' :
                    delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-indigo-50 text-indigo-700 border-indigo-200' :
                    delivery.status === DeliveryStatus.REJECTED ? 'bg-red-50 text-red-700 border-red-200' :
                    'bg-orange-50 text-orange-700 border-orange-200'
                  }`}>
                    {delivery.status}
                  </span>
                </div>

                <h3 className="font-black text-slate-900 text-base leading-tight uppercase mb-1">{delivery.customerName}</h3>

                <div className="space-y-1 mb-4">
                  <div className="flex items-center gap-2">
                    <p className="text-[9px] text-green-600 font-black flex items-center gap-0.5 uppercase bg-green-50 px-1.5 py-0.5 rounded-lg">
                      <DollarSign className="w-2.5 h-2.5" />
                      {delivery.orderValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </p>
                    {role === 'ADMIN' && (
                      <p className="text-[8px] text-slate-400 font-bold uppercase flex items-center gap-1">
                        <User className="w-3 h-3" /> {delivery.driverName}
                      </p>
                    )}
                  </div>
                  <p className="text-[9px] text-slate-500 italic leading-tight">{delivery.address}</p>
                </div>
              </div>

              {/* Actions - Always Visible at the Bottom of Card */}
              <div className="flex gap-2 pt-3 border-t border-slate-50">
                {role === 'DRIVER' && (delivery.status !== DeliveryStatus.DELIVERED && delivery.status !== DeliveryStatus.REJECTED) && (
                  <>
                    {delivery.status === DeliveryStatus.PENDING && (
                      <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)} className="flex-1 bg-indigo-600 text-white p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase active:scale-95">
                        <Navigation className="w-3.5 h-3.5" /> Iniciar Rota
                      </button>
                    )}
                    {delivery.status === DeliveryStatus.IN_TRANSIT && (
                      <div className="flex w-full gap-2">
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 p-2.5 rounded-lg border border-red-100 flex items-center justify-center gap-1 active:scale-95">
                          <RotateCcw className="w-3.5 h-3.5" />
                        </button>
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)} className="flex-1 bg-green-600 text-white flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg font-black text-[9px] uppercase active:scale-95">
                          <Camera className="w-4 h-4" /> Finalizar
                        </button>
                      </div>
                    )}
                  </>
                )}
                {delivery.receiptPhoto && (
                  <button onClick={() => setViewPhoto(delivery.receiptPhoto || null)} className="flex-1 bg-slate-50 text-slate-500 p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase border border-slate-100 hover:bg-blue-50 hover:text-blue-600">
                    <ImageIcon className="w-4 h-4" /> Comprovante
                  </button>
                )}
              </div>
            </div>
          ))}

          {currentViewDeliveries.length === 0 && (
            <div className="col-span-full py-16 text-center opacity-20">
              <Search className="w-10 h-10 mx-auto mb-2" />
              <p className="text-xs font-black uppercase tracking-widest">Nenhum pedido encontrado</p>
            </div>
          )}
        </div>

        {/* Drivers Management - Also Compact */}
        {role === 'DRIVERS_MGMT' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm space-y-4 h-fit">
              <h3 className="font-black text-slate-900 flex items-center gap-2 uppercase text-[10px] tracking-widest">
                <Plus className="w-4 h-4 text-blue-600" /> Novo Motorista
              </h3>
              <input 
                type="text" 
                placeholder="Nome completo..."
                value={newDriverName}
                onChange={(e) => setNewDriverName(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-xs"
              />
              <button onClick={addDriver} className="w-full bg-slate-900 text-white font-black py-3 rounded-lg uppercase text-[9px] tracking-widest active:scale-95">
                Cadastrar
              </button>
            </div>
            <div className="lg:col-span-2 space-y-2">
              {drivers.map(driver => (
                <div key={driver.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
                  <p className="font-black text-slate-900 text-xs uppercase">{driver.name}</p>
                  <button onClick={() => removeDriver(driver.id)} className="p-2 text-red-400 hover:bg-red-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Modals & Overlays - Minimal Changes but Ensure Mobile Ready */}
        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-2xl p-6 space-y-6 shadow-2xl animate-in zoom-in-95 duration-200">
              <div className="text-center space-y-3">
                <div className="w-12 h-12 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <Camera className="w-6 h-6" />
                </div>
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Foto do Canhoto</h3>
                <p className="text-[10px] text-slate-500 font-medium leading-relaxed">Capture a foto do comprovante para finalizar a entrega de <strong>{photoModal.customer}</strong>.</p>
              </div>
              <button onClick={() => fileInputRef.current?.click()} className="w-full bg-blue-600 text-white font-black py-4 rounded-xl flex items-center justify-center gap-2 uppercase text-[10px] active:scale-95">
                <Camera className="w-4 h-4" /> Abrir Câmera
              </button>
              <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
              <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[9px]">Cancelar</button>
            </div>
          </div>
        )}

        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-sm w-full animate-in zoom-in-95 duration-200">
              <button onClick={() => setViewPhoto(null)} className="absolute -top-10 right-0 text-white flex items-center gap-1 font-black text-[10px] uppercase tracking-widest"><X className="w-5 h-5" /> Fechar</button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-xl shadow-2xl" />
            </div>
          </div>
        )}

        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4">
            <div className="bg-white w-full max-w-xs rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center">
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Vincular Carga</h3>
                <p className="text-[10px] text-slate-500 mt-1"><strong>{pendingImport.length} pedidos</strong> detectados.</p>
              </div>
              <select 
                value={importDriverId}
                onChange={(e) => setImportDriverId(e.target.value)}
                className="w-full px-3 py-3 bg-slate-50 border border-slate-200 rounded-lg font-black text-slate-800 text-[10px] uppercase"
              >
                <option value="">Selecione o motorista...</option>
                {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
              <div className="flex gap-2">
                <button onClick={() => setPendingImport(null)} className="flex-1 py-2 text-[9px] font-black text-slate-400 uppercase">Voltar</button>
                <button onClick={confirmImport} disabled={!importDriverId} className="flex-1 py-2 bg-blue-600 text-white rounded-lg font-black text-[9px] uppercase shadow-lg disabled:opacity-30">Confirmar</button>
              </div>
            </div>
          </div>
        )}

        {loading && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center gap-3 animate-pulse">
                <div className="w-6 h-6 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-[8px]">Aguarde...</p>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'export-react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Users,
  Search, 
  FileUp, 
  CheckCircle2, 
  MapPin, 
  DollarSign, 
  Camera, 
  X, 
  ImageIcon, 
  RotateCcw, 
  Navigation, 
  ClipboardList, 
  Menu,
  MoreVertical,
  Trash2,
  Plus,
  LayoutDashboard,
  BarChart3
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import { generateTrackingMessage } from './services/geminiService';
import { saveData, getData } from './services/dbService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [role, setRole] = useState<UserRole>('CUSTOMER');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [newDriverName, setNewDriverName] = useState('');
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadData = async () => {
      const dls = await getData('deliveries');
      const drs = await getData('drivers');
      if (dls.length) setDeliveries(dls);
      if (drs.length) setDrivers(drs);
      else {
        const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
        setDrivers(defaultDrivers);
        await saveData('drivers', defaultDrivers);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    if (deliveries.length >= 0) saveData('deliveries', deliveries);
  }, [deliveries]);

  useEffect(() => {
    if (drivers.length >= 0) saveData('drivers', drivers);
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: String(row[8] || `${row[9] || 'Belém'}, Pará`)
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel.");
      } finally {
        setLoading(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -1.4558,
      lng: -48.4902,
    }));

    setDeliveries([...deliveries, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      const updated = deliveries.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      );
      setDeliveries(updated);

      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const finalizeRejection = async () => {
    if (!rejectionModal) return;
    const updated = deliveries.map(d => 
      d.id === rejectionModal.id ? { 
        ...d, 
        status: DeliveryStatus.REJECTED, 
        updatedAt: new Date().toISOString(),
        notes: 'Cliente recusou a entrega'
      } : d
    );
    setDeliveries(updated);
    setRejectionModal(null);
    setAiMessage("Entrega marcada como devolvida.");
    setTimeout(() => setAiMessage(null), 3000);
  };

  const updateDeliveryStatus = async (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;

    if (newStatus === DeliveryStatus.DELIVERED) {
      setPhotoModal({ id, customer: delivery.customerName });
      return;
    }

    if (newStatus === DeliveryStatus.REJECTED) {
      setRejectionModal({ id, customer: delivery.customerName });
      return;
    }

    const updated = deliveries.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    );
    setDeliveries(updated);
  };

  const addDriver = async () => {
    if (!newDriverName.trim()) return;
    const newDriver: Driver = { id: crypto.randomUUID(), name: newDriverName.trim() };
    setDrivers([...drivers, newDriver]);
    setNewDriverName('');
  };

  const removeDriver = async (id: string) => {
    setDrivers(drivers.filter(d => d.id !== id));
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.address.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);

  // KPIs
  const currentViewDeliveries = role === 'DRIVER' ? driversOrders : (role === 'CUSTOMER' && searchQuery ? filteredDeliveries : (role === 'ADMIN' ? filteredDeliveries : []));
  const totalOrders = role === 'DRIVER' ? driversOrders.length : deliveries.length;
  const deliveredCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.DELIVERED).length;
  const inTransitCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.IN_TRANSIT).length;
  const rejectedCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.REJECTED).length;

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">

      {/* Mobile Top Header - Compact */}
      <div className="md:hidden bg-slate-900 text-white px-4 py-3 flex items-center justify-between sticky top-0 z-40 shadow-md">
        <div className="flex items-center gap-2">
          <Package className="w-5 h-5 text-blue-500" />
          <h1 className="text-lg font-black tracking-tighter">SwiftLog</h1>
        </div>
        <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-1">
          {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {/* Sidebar - Collapsible */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white p-5 flex flex-col transition-transform duration-300 transform 
        ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:relative md:translate-x-0 md:flex shadow-2xl
      `}>
        <div className="hidden md:flex items-center gap-2 mb-6 px-2">
          <Package className="w-6 h-6 text-blue-500" />
          <h1 className="text-xl font-black tracking-tighter">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {[
            { id: 'ADMIN', label: 'Painel Geral', icon: LayoutDashboard },
            { id: 'DRIVERS_MGMT', label: 'Motoristas', icon: Users },
            { id: 'DRIVER', label: 'Meu Portal', icon: Truck },
            { id: 'CUSTOMER', label: 'Rastreio', icon: Search },
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => {
                setRole(item.id as UserRole);
                setSearchQuery('');
                setIsMenuOpen(false);
              }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${role === item.id ? 'bg-blue-600 text-white font-bold' : 'hover:bg-slate-800 text-slate-400 font-medium'}`}
            >
              <item.icon className="w-4 h-4" />
              <span className="text-xs uppercase tracking-wider">{item.label}</span>
            </button>
          ))}
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-6 space-y-4 overflow-x-hidden">

        {/* Compact Header */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div>
            <h2 className="text-xl font-black text-slate-900 uppercase leading-none">
              {role === 'ADMIN' && "Administração"}
              {role === 'DRIVERS_MGMT' && "Gestão de Frota"}
              {role === 'DRIVER' && "Minha Rota"}
              {role === 'CUSTOMER' && "Rastreamento"}
            </h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Regional Pará</p>
          </div>
          {role === 'ADMIN' && (
            <label className="flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2.5 rounded-lg font-bold cursor-pointer transition-all active:scale-95 uppercase text-[9px] tracking-widest">
              <FileUp className="w-4 h-4" /> Importar Excel
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </div>

        {/* Compact KPIs */}
        <section className="grid grid-cols-2 lg:grid-cols-4 gap-2 md:gap-4">
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-blue-50 p-2 rounded-lg"><ClipboardList className="w-4 h-4 text-blue-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Pedidos</p>
               <p className="text-lg font-black text-slate-900 leading-none">{totalOrders}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-indigo-50 p-2 rounded-lg"><Truck className="w-4 h-4 text-indigo-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Em Rota</p>
               <p className="text-lg font-black text-indigo-600 leading-none">{inTransitCount}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-green-50 p-2 rounded-lg"><CheckCircle2 className="w-4 h-4 text-green-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Entregues</p>
               <p className="text-lg font-black text-green-600 leading-none">{deliveredCount}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-red-50 p-2 rounded-lg"><RotateCcw className="w-4 h-4 text-red-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Devolvidos</p>
               <p className="text-lg font-black text-red-600 leading-none">{rejectedCount}</p>
             </div>
          </div>
        </section>

        {/* Search and Driver Selection */}
        <div className="flex flex-col md:flex-row gap-3">
          <div className="relative flex-1 group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input 
              type="text" 
              placeholder={role === 'CUSTOMER' ? "Número do pedido..." : "Pesquisar..."}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-9 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all font-bold text-slate-700 text-xs"
            />
          </div>

          {role === 'DRIVER' && (
            <div className="bg-slate-900 px-3 py-2 rounded-xl flex items-center gap-3 text-white">
              <Truck className="w-4 h-4 text-blue-400" />
              <select 
                value={selectedDriver}
                onChange={(e) => setSelectedDriver(e.target.value)}
                className="bg-transparent border-none outline-none font-black text-[10px] uppercase tracking-widest cursor-pointer text-white"
              >
                <option value="" className="text-slate-900">IDENTIFIQUE-SE</option>
                {drivers.map(d => <option key={d.id} value={d.name} className="text-slate-900">{d.name}</option>)}
              </select>
            </div>
          )}
        </div>

        {/* Deliveries List - Grid of Cards (No horizontal scroll!) */}
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-3">
          {currentViewDeliveries.map((delivery) => (
            <div key={delivery.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm hover:border-blue-300 transition-all flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-2">
                  <div className="flex flex-col">
                    <span className="font-mono text-blue-600 font-black text-sm">#{delivery.orderNumber}</span>
                    <span className="text-[9px] font-bold text-slate-400 uppercase flex items-center gap-1 mt-1">
                      <MapPin className="w-3 h-3 text-red-400" /> {delivery.city}
                    </span>
                  </div>
                  <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                    delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-50 text-green-700 border-green-200' :
                    delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-indigo-50 text-indigo-700 border-indigo-200' :
                    delivery.status === DeliveryStatus.REJECTED ? 'bg-red-50 text-red-700 border-red-200' :
                    'bg-orange-50 text-orange-700 border-orange-200'
                  }`}>
                    {delivery.status}
                  </span>
                </div>

                <h3 className="font-black text-slate-900 text-base leading-tight uppercase mb-1">{delivery.customerName}</h3>

                <div className="space-y-1 mb-4">
                  <div className="flex items-center gap-2">
                    <p className="text-[9px] text-green-600 font-black flex items-center gap-0.5 uppercase bg-green-50 px-1.5 py-0.5 rounded-lg">
                      <DollarSign className="w-2.5 h-2.5" />
                      {delivery.orderValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </p>
                    {role === 'ADMIN' && (
                      <p className="text-[8px] text-slate-400 font-bold uppercase flex items-center gap-1">
                        <User className="w-3 h-3" /> {delivery.driverName}
                      </p>
                    )}
                  </div>
                  <p className="text-[9px] text-slate-500 italic leading-tight">{delivery.address}</p>
                </div>
              </div>

              {/* Actions - Always Visible at the Bottom of Card */}
              <div className="flex gap-2 pt-3 border-t border-slate-50">
                {role === 'DRIVER' && (delivery.status !== DeliveryStatus.DELIVERED && delivery.status !== DeliveryStatus.REJECTED) && (
                  <>
                    {delivery.status === DeliveryStatus.PENDING && (
                      <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)} className="flex-1 bg-indigo-600 text-white p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase active:scale-95">
                        <Navigation className="w-3.5 h-3.5" /> Iniciar Rota
                      </button>
                    )}
                    {delivery.status === DeliveryStatus.IN_TRANSIT && (
                      <div className="flex w-full gap-2">
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 p-2.5 rounded-lg border border-red-100 flex items-center justify-center gap-1 active:scale-95">
                          <RotateCcw className="w-3.5 h-3.5" />
                        </button>
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)} className="flex-1 bg-green-600 text-white flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg font-black text-[9px] uppercase active:scale-95">
                          <Camera className="w-4 h-4" /> Finalizar
                        </button>
                      </div>
                    )}
                  </>
                )}
                {delivery.receiptPhoto && (
                  <button onClick={() => setViewPhoto(delivery.receiptPhoto || null)} className="flex-1 bg-slate-50 text-slate-500 p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase border border-slate-100 hover:bg-blue-50 hover:text-blue-600">
                    <ImageIcon className="w-4 h-4" /> Comprovante
                  </button>
                )}
              </div>
            </div>
          ))}

          {currentViewDeliveries.length === 0 && (
            <div className="col-span-full py-16 text-center opacity-20">
              <Search className="w-10 h-10 mx-auto mb-2" />
              <p className="text-xs font-black uppercase tracking-widest">Nenhum pedido encontrado</p>
            </div>
          )}
        </div>

        {/* Drivers Management - Also Compact */}
        {role === 'DRIVERS_MGMT' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm space-y-4 h-fit">
              <h3 className="font-black text-slate-900 flex items-center gap-2 uppercase text-[10px] tracking-widest">
                <Plus className="w-4 h-4 text-blue-600" /> Novo Motorista
              </h3>
              <input 
                type="text" 
                placeholder="Nome completo..."
                value={newDriverName}
                onChange={(e) => setNewDriverName(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-xs"
              />
              <button onClick={addDriver} className="w-full bg-slate-900 text-white font-black py-3 rounded-lg uppercase text-[9px] tracking-widest active:scale-95">
                Cadastrar
              </button>
            </div>
            <div className="lg:col-span-2 space-y-2">
              {drivers.map(driver => (
                <div key={driver.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
                  <p className="font-black text-slate-900 text-xs uppercase">{driver.name}</p>
                  <button onClick={() => removeDriver(driver.id)} className="p-2 text-red-400 hover:bg-red-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Modals & Overlays - Minimal Changes but Ensure Mobile Ready */}
        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-2xl p-6 space-y-6 shadow-2xl animate-in zoom-in-95 duration-200">
              <div className="text-center space-y-3">
                <div className="w-12 h-12 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <Camera className="w-6 h-6" />
                </div>
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Foto do Canhoto</h3>
                <p className="text-[10px] text-slate-500 font-medium leading-relaxed">Capture a foto do comprovante para finalizar a entrega de <strong>{photoModal.customer}</strong>.</p>
              </div>
              <button onClick={() => fileInputRef.current?.click()} className="w-full bg-blue-600 text-white font-black py-4 rounded-xl flex items-center justify-center gap-2 uppercase text-[10px] active:scale-95">
                <Camera className="w-4 h-4" /> Abrir Câmera
              </button>
              <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
              <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[9px]">Cancelar</button>
            </div>
          </div>
        )}

        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-sm w-full animate-in zoom-in-95 duration-200">
              <button onClick={() => setViewPhoto(null)} className="absolute -top-10 right-0 text-white flex items-center gap-1 font-black text-[10px] uppercase tracking-widest"><X className="w-5 h-5" /> Fechar</button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-xl shadow-2xl" />
            </div>
          </div>
        )}

        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4">
            <div className="bg-white w-full max-w-xs rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center">
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Vincular Carga</h3>
                <p className="text-[10px] text-slate-500 mt-1"><strong>{pendingImport.length} pedidos</strong> detectados.</p>
              </div>
              <select 
                value={importDriverId}
                onChange={(e) => setImportDriverId(e.target.value)}
                className="w-full px-3 py-3 bg-slate-50 border border-slate-200 rounded-lg font-black text-slate-800 text-[10px] uppercase"
              >
                <option value="">Selecione o motorista...</option>
                {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
              <div className="flex gap-2">
                <button onClick={() => setPendingImport(null)} className="flex-1 py-2 text-[9px] font-black text-slate-400 uppercase">Voltar</button>
                <button onClick={confirmImport} disabled={!importDriverId} className="flex-1 py-2 bg-blue-600 text-white rounded-lg font-black text-[9px] uppercase shadow-lg disabled:opacity-30">Confirmar</button>
              </div>
            </div>
          </div>
        )}

        {loading && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center gap-3 animate-pulse">
                <div className="w-6 h-6 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-[8px]">Aguarde...</p>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Users,
  Search, 
  FileUp, 
  CheckCircle2, 
  MapPin, 
  DollarSign, 
  Camera, 
  X, 
  ImageIcon, 
  RotateCcw, 
  Navigation, 
  ClipboardList, 
  Menu,
  MoreVertical,
  Trash2,
  Plus,
  LayoutDashboard,
  BarChart3
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import { generateTrackingMessage } from './services/geminiService';
import { saveData, getData } from './services/dbService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [role, setRole] = useState<UserRole>('CUSTOMER');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [newDriverName, setNewDriverName] = useState('');
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadData = async () => {
      const dls = await getData('deliveries');
      const drs = await getData('drivers');
      if (dls.length) setDeliveries(dls);
      if (drs.length) setDrivers(drs);
      else {
        const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
        setDrivers(defaultDrivers);
        await saveData('drivers', defaultDrivers);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    if (deliveries.length >= 0) saveData('deliveries', deliveries);
  }, [deliveries]);

  useEffect(() => {
    if (drivers.length >= 0) saveData('drivers', drivers);
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: String(row[8] || `${row[9] || 'Belém'}, Pará`)
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel.");
      } finally {
        setLoading(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -1.4558,
      lng: -48.4902,
    }));

    setDeliveries([...deliveries, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      const updated = deliveries.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      );
      setDeliveries(updated);

      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const finalizeRejection = async () => {
    if (!rejectionModal) return;
    const updated = deliveries.map(d => 
      d.id === rejectionModal.id ? { 
        ...d, 
        status: DeliveryStatus.REJECTED, 
        updatedAt: new Date().toISOString(),
        notes: 'Cliente recusou a entrega'
      } : d
    );
    setDeliveries(updated);
    setRejectionModal(null);
    setAiMessage("Entrega marcada como devolvida.");
    setTimeout(() => setAiMessage(null), 3000);
  };

  const updateDeliveryStatus = async (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;

    if (newStatus === DeliveryStatus.DELIVERED) {
      setPhotoModal({ id, customer: delivery.customerName });
      return;
    }

    if (newStatus === DeliveryStatus.REJECTED) {
      setRejectionModal({ id, customer: delivery.customerName });
      return;
    }

    const updated = deliveries.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    );
    setDeliveries(updated);
  };

  const addDriver = async () => {
    if (!newDriverName.trim()) return;
    const newDriver: Driver = { id: crypto.randomUUID(), name: newDriverName.trim() };
    setDrivers([...drivers, newDriver]);
    setNewDriverName('');
  };

  const removeDriver = async (id: string) => {
    setDrivers(drivers.filter(d => d.id !== id));
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.address.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);

  // KPIs
  const currentViewDeliveries = role === 'DRIVER' ? driversOrders : (role === 'CUSTOMER' && searchQuery ? filteredDeliveries : (role === 'ADMIN' ? filteredDeliveries : []));
  const totalOrders = role === 'DRIVER' ? driversOrders.length : deliveries.length;
  const deliveredCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.DELIVERED).length;
  const inTransitCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.IN_TRANSIT).length;
  const rejectedCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.REJECTED).length;

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">

      {/* Mobile Top Header - Compact */}
      <div className="md:hidden bg-slate-900 text-white px-4 py-3 flex items-center justify-between sticky top-0 z-40 shadow-md">
        <div className="flex items-center gap-2">
          <Package className="w-5 h-5 text-blue-500" />
          <h1 className="text-lg font-black tracking-tighter">SwiftLog</h1>
        </div>
        <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-1">
          {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {/* Sidebar - Collapsible */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white p-5 flex flex-col transition-transform duration-300 transform 
        ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:relative md:translate-x-0 md:flex shadow-2xl
      `}>
        <div className="hidden md:flex items-center gap-2 mb-6 px-2">
          <Package className="w-6 h-6 text-blue-500" />
          <h1 className="text-xl font-black tracking-tighter">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {[
            { id: 'ADMIN', label: 'Painel Geral', icon: LayoutDashboard },
            { id: 'DRIVERS_MGMT', label: 'Motoristas', icon: Users },
            { id: 'DRIVER', label: 'Meu Portal', icon: Truck },
            { id: 'CUSTOMER', label: 'Rastreio', icon: Search },
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => {
                setRole(item.id as UserRole);
                setSearchQuery('');
                setIsMenuOpen(false);
              }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${role === item.id ? 'bg-blue-600 text-white font-bold' : 'hover:bg-slate-800 text-slate-400 font-medium'}`}
            >
              <item.icon className="w-4 h-4" />
              <span className="text-xs uppercase tracking-wider">{item.label}</span>
            </button>
          ))}
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-6 space-y-4 overflow-x-hidden">

        {/* Compact Header */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div>
            <h2 className="text-xl font-black text-slate-900 uppercase leading-none">
              {role === 'ADMIN' && "Administração"}
              {role === 'DRIVERS_MGMT' && "Gestão de Frota"}
              {role === 'DRIVER' && "Minha Rota"}
              {role === 'CUSTOMER' && "Rastreamento"}
            </h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Regional Pará</p>
          </div>
          {role === 'ADMIN' && (
            <label className="flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2.5 rounded-lg font-bold cursor-pointer transition-all active:scale-95 uppercase text-[9px] tracking-widest">
              <FileUp className="w-4 h-4" /> Importar Excel
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </div>

        {/* Compact KPIs */}
        <section className="grid grid-cols-2 lg:grid-cols-4 gap-2 md:gap-4">
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-blue-50 p-2 rounded-lg"><ClipboardList className="w-4 h-4 text-blue-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Pedidos</p>
               <p className="text-lg font-black text-slate-900 leading-none">{totalOrders}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-indigo-50 p-2 rounded-lg"><Truck className="w-4 h-4 text-indigo-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Em Rota</p>
               <p className="text-lg font-black text-indigo-600 leading-none">{inTransitCount}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-green-50 p-2 rounded-lg"><CheckCircle2 className="w-4 h-4 text-green-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Entregues</p>
               <p className="text-lg font-black text-green-600 leading-none">{deliveredCount}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-red-50 p-2 rounded-lg"><RotateCcw className="w-4 h-4 text-red-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Devolvidos</p>
               <p className="text-lg font-black text-red-600 leading-none">{rejectedCount}</p>
             </div>
          </div>
        </section>

        {/* Search and Driver Selection */}
        <div className="flex flex-col md:flex-row gap-3">
          <div className="relative flex-1 group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input 
              type="text" 
              placeholder={role === 'CUSTOMER' ? "Número do pedido..." : "Pesquisar..."}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-9 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all font-bold text-slate-700 text-xs"
            />
          </div>

          {role === 'DRIVER' && (
            <div className="bg-slate-900 px-3 py-2 rounded-xl flex items-center gap-3 text-white">
              <Truck className="w-4 h-4 text-blue-400" />
              <select 
                value={selectedDriver}
                onChange={(e) => setSelectedDriver(e.target.value)}
                className="bg-transparent border-none outline-none font-black text-[10px] uppercase tracking-widest cursor-pointer text-white"
              >
                <option value="" className="text-slate-900">IDENTIFIQUE-SE</option>
                {drivers.map(d => <option key={d.id} value={d.name} className="text-slate-900">{d.name}</option>)}
              </select>
            </div>
          )}
        </div>

        {/* Deliveries List - Grid of Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-3">
          {currentViewDeliveries.map((delivery) => (
            <div key={delivery.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm hover:border-blue-300 transition-all flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-2">
                  <div className="flex flex-col">
                    <span className="font-mono text-blue-600 font-black text-sm">#{delivery.orderNumber}</span>
                    <span className="text-[9px] font-bold text-slate-400 uppercase flex items-center gap-1 mt-1">
                      <MapPin className="w-3 h-3 text-red-400" /> {delivery.city}
                    </span>
                  </div>
                  <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                    delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-50 text-green-700 border-green-200' :
                    delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-indigo-50 text-indigo-700 border-indigo-200' :
                    delivery.status === DeliveryStatus.REJECTED ? 'bg-red-50 text-red-700 border-red-200' :
                    'bg-orange-50 text-orange-700 border-orange-200'
                  }`}>
                    {delivery.status}
                  </span>
                </div>

                <h3 className="font-black text-slate-900 text-base leading-tight uppercase mb-1">{delivery.customerName}</h3>

                <div className="space-y-1 mb-4">
                  <div className="flex items-center gap-2">
                    <p className="text-[9px] text-green-600 font-black flex items-center gap-0.5 uppercase bg-green-50 px-1.5 py-0.5 rounded-lg">
                      <DollarSign className="w-2.5 h-2.5" />
                      {delivery.orderValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </p>
                    {role === 'ADMIN' && (
                      <p className="text-[8px] text-slate-400 font-bold uppercase flex items-center gap-1">
                        <User className="w-3 h-3" /> {delivery.driverName}
                      </p>
                    )}
                  </div>
                  <p className="text-[9px] text-slate-500 italic leading-tight">{delivery.address}</p>
                </div>
              </div>

              <div className="flex gap-2 pt-3 border-t border-slate-50">
                {role === 'DRIVER' && (delivery.status !== DeliveryStatus.DELIVERED && delivery.status !== DeliveryStatus.REJECTED) && (
                  <>
                    {delivery.status === DeliveryStatus.PENDING && (
                      <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)} className="flex-1 bg-indigo-600 text-white p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase active:scale-95">
                        <Navigation className="w-3.5 h-3.5" /> Iniciar Rota
                      </button>
                    )}
                    {delivery.status === DeliveryStatus.IN_TRANSIT && (
                      <div className="flex w-full gap-2">
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 p-2.5 rounded-lg border border-red-100 flex items-center justify-center gap-1 active:scale-95">
                          <RotateCcw className="w-3.5 h-3.5" />
                        </button>
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)} className="flex-1 bg-green-600 text-white flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg font-black text-[9px] uppercase active:scale-95">
                          <Camera className="w-4 h-4" /> Finalizar
                        </button>
                      </div>
                    )}
                  </>
                )}
                {delivery.receiptPhoto && (
                  <button onClick={() => setViewPhoto(delivery.receiptPhoto || null)} className="flex-1 bg-slate-50 text-slate-500 p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase border border-slate-100 hover:bg-blue-50 hover:text-blue-600">
                    <ImageIcon className="w-4 h-4" /> Comprovante
                  </button>
                )}
              </div>
            </div>
          ))}

          {currentViewDeliveries.length === 0 && (
            <div className="col-span-full py-16 text-center opacity-20">
              <Search className="w-10 h-10 mx-auto mb-2" />
              <p className="text-xs font-black uppercase tracking-widest">Nenhum pedido encontrado</p>
            </div>
          )}
        </div>

        {role === 'DRIVERS_MGMT' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm space-y-4 h-fit">
              <h3 className="font-black text-slate-900 flex items-center gap-2 uppercase text-[10px] tracking-widest">
                <Plus className="w-4 h-4 text-blue-600" /> Novo Motorista
              </h3>
              <input 
                type="text" 
                placeholder="Nome completo..."
                value={newDriverName}
                onChange={(e) => setNewDriverName(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-xs"
              />
              <button onClick={addDriver} className="w-full bg-slate-900 text-white font-black py-3 rounded-lg uppercase text-[9px] tracking-widest active:scale-95">
                Cadastrar
              </button>
            </div>
            <div className="lg:col-span-2 space-y-2">
              {drivers.map(driver => (
                <div key={driver.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
                  <p className="font-black text-slate-900 text-xs uppercase">{driver.name}</p>
                  <button onClick={() => removeDriver(driver.id)} className="p-2 text-red-400 hover:bg-red-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>
                </div>
              ))}
            </div>
          </div>
        )}

        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center space-y-3">
                <div className="w-12 h-12 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <Camera className="w-6 h-6" />
                </div>
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Foto do Canhoto</h3>
                <p className="text-[10px] text-slate-500 font-medium leading-relaxed">Capture a foto do comprovante para finalizar a entrega de <strong>{photoModal.customer}</strong>.</p>
              </div>
              <button onClick={() => fileInputRef.current?.click()} className="w-full bg-blue-600 text-white font-black py-4 rounded-xl flex items-center justify-center gap-2 uppercase text-[10px] active:scale-95">
                <Camera className="w-4 h-4" /> Abrir Câmera
              </button>
              <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
              <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[9px]">Cancelar</button>
            </div>
          </div>
        )}

        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-sm w-full">
              <button onClick={() => setViewPhoto(null)} className="absolute -top-10 right-0 text-white flex items-center gap-1 font-black text-[10px] uppercase tracking-widest"><X className="w-5 h-5" /> Fechar</button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-xl shadow-2xl" />
            </div>
          </div>
        )}

        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4">
            <div className="bg-white w-full max-w-xs rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center">
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Vincular Carga</h3>
                <p className="text-[10px] text-slate-500 mt-1"><strong>{pendingImport.length} pedidos</strong> detectados.</p>
              </div>
              <select 
                value={importDriverId}
                onChange={(e) => setImportDriverId(e.target.value)}
                className="w-full px-3 py-3 bg-slate-50 border border-slate-200 rounded-lg font-black text-slate-800 text-[10px] uppercase"
              >
                <option value="">Selecione o motorista...</option>
                {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
              <div className="flex gap-2">
                <button onClick={() => setPendingImport(null)} className="flex-1 py-2 text-[9px] font-black text-slate-400 uppercase">Voltar</button>
                <button onClick={confirmImport} disabled={!importDriverId} className="flex-1 py-2 bg-blue-600 text-white rounded-lg font-black text-[9px] uppercase shadow-lg disabled:opacity-30">Confirmar</button>
              </div>
            </div>
          </div>
        )}

        {loading && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center gap-3 animate-pulse">
                <div className="w-6 h-6 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-[8px]">Aguarde...</p>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Users,
  Search, 
  FileUp, 
  CheckCircle2, 
  MapPin, 
  DollarSign, 
  Camera, 
  X, 
  ImageIcon, 
  RotateCcw, 
  Navigation, 
  ClipboardList, 
  Menu,
  MoreVertical,
  Trash2,
  Plus,
  LayoutDashboard,
  BarChart3,
  AlertCircle
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import { generateTrackingMessage } from './services/geminiService';
import { saveData, getData } from './services/dbService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [role, setRole] = useState<UserRole>('CUSTOMER');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [newDriverName, setNewDriverName] = useState('');
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadData = async () => {
      const dls = await getData('deliveries');
      const drs = await getData('drivers');
      if (dls.length) setDeliveries(dls);
      if (drs.length) setDrivers(drs);
      else {
        const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
        setDrivers(defaultDrivers);
        await saveData('drivers', defaultDrivers);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    if (deliveries.length >= 0) saveData('deliveries', deliveries);
  }, [deliveries]);

  useEffect(() => {
    if (drivers.length >= 0) saveData('drivers', drivers);
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: String(row[8] || `${row[9] || 'Belém'}, Pará`)
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel.");
      } finally {
        setLoading(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -1.4558,
      lng: -48.4902,
    }));

    setDeliveries([...deliveries, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      const updated = deliveries.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      );
      setDeliveries(updated);

      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const finalizeRejection = async () => {
    if (!rejectionModal) return;
    const updated = deliveries.map(d => 
      d.id === rejectionModal.id ? { 
        ...d, 
        status: DeliveryStatus.REJECTED, 
        updatedAt: new Date().toISOString(),
        notes: 'Cliente recusou a entrega'
      } : d
    );
    setDeliveries(updated);
    setRejectionModal(null);
    setAiMessage("Entrega marcada como devolvida.");
    setTimeout(() => setAiMessage(null), 3000);
  };

  const updateDeliveryStatus = async (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;

    if (newStatus === DeliveryStatus.DELIVERED) {
      setPhotoModal({ id, customer: delivery.customerName });
      return;
    }

    if (newStatus === DeliveryStatus.REJECTED) {
      setRejectionModal({ id, customer: delivery.customerName });
      return;
    }

    const updated = deliveries.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    );
    setDeliveries(updated);
  };

  const addDriver = async () => {
    if (!newDriverName.trim()) return;
    const newDriver: Driver = { id: crypto.randomUUID(), name: newDriverName.trim() };
    setDrivers([...drivers, newDriver]);
    setNewDriverName('');
  };

  const removeDriver = async (id: string) => {
    setDrivers(drivers.filter(d => d.id !== id));
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.address.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);

  // KPIs
  const currentViewDeliveries = role === 'DRIVER' ? driversOrders : (role === 'CUSTOMER' && searchQuery ? filteredDeliveries : (role === 'ADMIN' ? filteredDeliveries : []));
  const totalOrders = role === 'DRIVER' ? driversOrders.length : deliveries.length;
  const deliveredCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.DELIVERED).length;
  const inTransitCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.IN_TRANSIT).length;
  const rejectedCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.REJECTED).length;

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">

      {/* Mobile Top Header - Compact */}
      <div className="md:hidden bg-slate-900 text-white px-4 py-3 flex items-center justify-between sticky top-0 z-40 shadow-md">
        <div className="flex items-center gap-2">
          <Package className="w-5 h-5 text-blue-500" />
          <h1 className="text-lg font-black tracking-tighter">SwiftLog</h1>
        </div>
        <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-1">
          {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {/* Sidebar - Collapsible */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white p-5 flex flex-col transition-transform duration-300 transform 
        ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:relative md:translate-x-0 md:flex shadow-2xl
      `}>
        <div className="hidden md:flex items-center gap-2 mb-6 px-2">
          <Package className="w-6 h-6 text-blue-500" />
          <h1 className="text-xl font-black tracking-tighter">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {[
            { id: 'ADMIN', label: 'Painel Geral', icon: LayoutDashboard },
            { id: 'DRIVERS_MGMT', label: 'Motoristas', icon: Users },
            { id: 'DRIVER', label: 'Meu Portal', icon: Truck },
            { id: 'CUSTOMER', label: 'Rastreio', icon: Search },
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => {
                setRole(item.id as UserRole);
                setSearchQuery('');
                setIsMenuOpen(false);
              }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${role === item.id ? 'bg-blue-600 text-white font-bold' : 'hover:bg-slate-800 text-slate-400 font-medium'}`}
            >
              <item.icon className="w-4 h-4" />
              <span className="text-xs uppercase tracking-wider">{item.label}</span>
            </button>
          ))}
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-6 space-y-4 overflow-x-hidden">

        {/* AI Notification Overlay */}
        {aiMessage && (
          <div className="fixed top-5 right-5 z-50 animate-in fade-in slide-in-from-top-4">
            <div className="bg-white border-l-4 border-blue-600 text-slate-800 px-4 py-3 rounded-lg shadow-xl flex items-center gap-3">
              <CheckCircle2 className="w-4 h-4 text-blue-600" />
              <p className="text-[10px] font-black uppercase text-slate-600">{aiMessage}</p>
            </div>
          </div>
        )}

        {/* Compact Header */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div>
            <h2 className="text-xl font-black text-slate-900 uppercase leading-none">
              {role === 'ADMIN' && "Administração"}
              {role === 'DRIVERS_MGMT' && "Gestão de Frota"}
              {role === 'DRIVER' && "Minha Rota"}
              {role === 'CUSTOMER' && "Rastreamento"}
            </h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Regional Pará</p>
          </div>
          {role === 'ADMIN' && (
            <label className="flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2.5 rounded-lg font-bold cursor-pointer transition-all active:scale-95 uppercase text-[9px] tracking-widest">
              <FileUp className="w-4 h-4" /> Importar Excel
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </div>

        {/* Compact KPIs */}
        <section className="grid grid-cols-2 lg:grid-cols-4 gap-2 md:gap-4">
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-blue-50 p-2 rounded-lg"><ClipboardList className="w-4 h-4 text-blue-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Pedidos</p>
               <p className="text-lg font-black text-slate-900 leading-none">{totalOrders}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-indigo-50 p-2 rounded-lg"><Truck className="w-4 h-4 text-indigo-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Em Rota</p>
               <p className="text-lg font-black text-indigo-600 leading-none">{inTransitCount}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-green-50 p-2 rounded-lg"><CheckCircle2 className="w-4 h-4 text-green-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Entregues</p>
               <p className="text-lg font-black text-green-600 leading-none">{deliveredCount}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-red-50 p-2 rounded-lg"><RotateCcw className="w-4 h-4 text-red-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Devolvidos</p>
               <p className="text-lg font-black text-red-600 leading-none">{rejectedCount}</p>
             </div>
          </div>
        </section>

        {/* Search and Driver Selection */}
        <div className="flex flex-col md:flex-row gap-3">
          <div className="relative flex-1 group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input 
              type="text" 
              placeholder={role === 'CUSTOMER' ? "Número do pedido..." : "Pesquisar..."}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-9 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all font-bold text-slate-700 text-xs"
            />
          </div>

          {role === 'DRIVER' && (
            <div className="bg-slate-900 px-3 py-2 rounded-xl flex items-center gap-3 text-white">
              <Truck className="w-4 h-4 text-blue-400" />
              <select 
                value={selectedDriver}
                onChange={(e) => setSelectedDriver(e.target.value)}
                className="bg-transparent border-none outline-none font-black text-[10px] uppercase tracking-widest cursor-pointer text-white"
              >
                <option value="" className="text-slate-900">IDENTIFIQUE-SE</option>
                {drivers.map(d => <option key={d.id} value={d.name} className="text-slate-900">{d.name}</option>)}
              </select>
            </div>
          )}
        </div>

        {/* Deliveries List - Grid of Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-3">
          {currentViewDeliveries.map((delivery) => (
            <div key={delivery.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm hover:border-blue-300 transition-all flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-2">
                  <div className="flex flex-col">
                    <span className="font-mono text-blue-600 font-black text-sm">#{delivery.orderNumber}</span>
                    <span className="text-[9px] font-bold text-slate-400 uppercase flex items-center gap-1 mt-1">
                      <MapPin className="w-3 h-3 text-red-400" /> {delivery.city}
                    </span>
                  </div>
                  <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                    delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-50 text-green-700 border-green-200' :
                    delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-indigo-50 text-indigo-700 border-indigo-200' :
                    delivery.status === DeliveryStatus.REJECTED ? 'bg-red-50 text-red-700 border-red-200' :
                    'bg-orange-50 text-orange-700 border-orange-200'
                  }`}>
                    {delivery.status}
                  </span>
                </div>

                <h3 className="font-black text-slate-900 text-base leading-tight uppercase mb-1">{delivery.customerName}</h3>

                <div className="space-y-1 mb-4">
                  <div className="flex items-center gap-2">
                    <p className="text-[9px] text-green-600 font-black flex items-center gap-0.5 uppercase bg-green-50 px-1.5 py-0.5 rounded-lg">
                      <DollarSign className="w-2.5 h-2.5" />
                      {delivery.orderValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </p>
                    {role === 'ADMIN' && (
                      <p className="text-[8px] text-slate-400 font-bold uppercase flex items-center gap-1">
                        <User className="w-3 h-3" /> {delivery.driverName}
                      </p>
                    )}
                  </div>
                  <p className="text-[9px] text-slate-500 italic leading-tight">{delivery.address}</p>
                </div>
              </div>

              <div className="flex gap-2 pt-3 border-t border-slate-50">
                {role === 'DRIVER' && (delivery.status !== DeliveryStatus.DELIVERED && delivery.status !== DeliveryStatus.REJECTED) && (
                  <>
                    {delivery.status === DeliveryStatus.PENDING && (
                      <div className="flex w-full gap-2">
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 px-3 py-2.5 rounded-lg border border-red-100 flex items-center justify-center gap-1 active:scale-95" title="Recusar/Devolver">
                          <RotateCcw className="w-4 h-4" />
                        </button>
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)} className="flex-1 bg-indigo-600 text-white p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase active:scale-95">
                          <Navigation className="w-3.5 h-3.5" /> Iniciar Rota
                        </button>
                      </div>
                    )}
                    {delivery.status === DeliveryStatus.IN_TRANSIT && (
                      <div className="flex w-full gap-2">
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 px-3 py-2.5 rounded-lg border border-red-100 flex items-center justify-center gap-1 active:scale-95" title="Recusar/Devolver">
                          <RotateCcw className="w-4 h-4" />
                        </button>
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)} className="flex-1 bg-green-600 text-white flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg font-black text-[9px] uppercase active:scale-95">
                          <Camera className="w-4 h-4" /> Finalizar
                        </button>
                      </div>
                    )}
                  </>
                )}
                {delivery.receiptPhoto && (
                  <button onClick={() => setViewPhoto(delivery.receiptPhoto || null)} className="flex-1 bg-slate-50 text-slate-500 p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase border border-slate-100 hover:bg-blue-50 hover:text-blue-600">
                    <ImageIcon className="w-4 h-4" /> Comprovante
                  </button>
                )}
              </div>
            </div>
          ))}

          {currentViewDeliveries.length === 0 && (
            <div className="col-span-full py-16 text-center opacity-20">
              <Search className="w-10 h-10 mx-auto mb-2" />
              <p className="text-xs font-black uppercase tracking-widest">Nenhum pedido encontrado</p>
            </div>
          )}
        </div>

        {/* Drivers Management */}
        {role === 'DRIVERS_MGMT' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm space-y-4 h-fit">
              <h3 className="font-black text-slate-900 flex items-center gap-2 uppercase text-[10px] tracking-widest">
                <Plus className="w-4 h-4 text-blue-600" /> Novo Motorista
              </h3>
              <input 
                type="text" 
                placeholder="Nome completo..."
                value={newDriverName}
                onChange={(e) => setNewDriverName(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-xs"
              />
              <button onClick={addDriver} className="w-full bg-slate-900 text-white font-black py-3 rounded-lg uppercase text-[9px] tracking-widest active:scale-95">
                Cadastrar
              </button>
            </div>
            <div className="lg:col-span-2 space-y-2">
              {drivers.map(driver => (
                <div key={driver.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
                  <p className="font-black text-slate-900 text-xs uppercase">{driver.name}</p>
                  <button onClick={() => removeDriver(driver.id)} className="p-2 text-red-400 hover:bg-red-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Modal: Photo Capture */}
        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center space-y-3">
                <div className="w-12 h-12 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <Camera className="w-6 h-6" />
                </div>
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Foto do Canhoto</h3>
                <p className="text-[10px] text-slate-500 font-medium leading-relaxed">Capture a foto do comprovante para finalizar a entrega de <strong>{photoModal.customer}</strong>.</p>
              </div>
              <button onClick={() => fileInputRef.current?.click()} className="w-full bg-blue-600 text-white font-black py-4 rounded-xl flex items-center justify-center gap-2 uppercase text-[10px] active:scale-95">
                <Camera className="w-4 h-4" /> Abrir Câmera
              </button>
              <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
              <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[9px]">Cancelar</button>
            </div>
          </div>
        )}

        {/* Modal: Rejection Confirmation */}
        {rejectionModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center space-y-3">
                <div className="w-12 h-12 bg-red-100 text-red-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <AlertCircle className="w-6 h-6" />
                </div>
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Confirmar Devolução</h3>
                <p className="text-[10px] text-slate-500 font-medium leading-relaxed">Você confirma que o pedido para <strong>{rejectionModal.customer}</strong> foi devolvido ou recusado?</p>
              </div>
              <div className="flex flex-col gap-2">
                <button onClick={finalizeRejection} className="w-full bg-red-600 text-white font-black py-4 rounded-xl flex items-center justify-center gap-2 uppercase text-[10px] active:scale-95 shadow-lg">
                  Confirmar Devolução
                </button>
                <button onClick={() => setRejectionModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[9px] hover:text-slate-600 transition-colors">
                  Cancelar
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Modal: View Photo */}
        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-sm w-full">
              <button onClick={() => setViewPhoto(null)} className="absolute -top-10 right-0 text-white flex items-center gap-1 font-black text-[10px] uppercase tracking-widest"><X className="w-5 h-5" /> Fechar</button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-xl shadow-2xl" />
            </div>
          </div>
        )}

        {/* Modal: Pending Import */}
        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4">
            <div className="bg-white w-full max-w-xs rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center">
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Vincular Carga</h3>
                <p className="text-[10px] text-slate-500 mt-1"><strong>{pendingImport.length} pedidos</strong> detectados.</p>
              </div>
              <select 
                value={importDriverId}
                onChange={(e) => setImportDriverId(e.target.value)}
                className="w-full px-3 py-3 bg-slate-50 border border-slate-200 rounded-lg font-black text-slate-800 text-[10px] uppercase"
              >
                <option value="">Selecione o motorista...</option>
                {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
              <div className="flex gap-2">
                <button onClick={() => setPendingImport(null)} className="flex-1 py-2 text-[9px] font-black text-slate-400 uppercase">Voltar</button>
                <button onClick={confirmImport} disabled={!importDriverId} className="flex-1 py-2 bg-blue-600 text-white rounded-lg font-black text-[9px] uppercase shadow-lg disabled:opacity-30">Confirmar</button>
              </div>
            </div>
          </div>
        )}

        {/* Loading Overlay */}
        {loading && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center gap-3 animate-pulse">
                <div className="w-6 h-6 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-[8px]">Aguarde...</p>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Users,
  Search, 
  FileUp, 
  CheckCircle2, 
  MapPin, 
  DollarSign, 
  Camera, 
  X, 
  ImageIcon, 
  RotateCcw, 
  Navigation, 
  ClipboardList, 
  Menu,
  MoreVertical,
  Trash2,
  Plus,
  LayoutDashboard,
  BarChart3,
  AlertCircle,
  Play
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import { generateTrackingMessage } from './services/geminiService';
import { saveData, getData } from './services/dbService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [role, setRole] = useState<UserRole>('CUSTOMER');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [newDriverName, setNewDriverName] = useState('');
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadData = async () => {
      const dls = await getData('deliveries');
      const drs = await getData('drivers');
      if (dls.length) setDeliveries(dls);
      if (drs.length) setDrivers(drs);
      else {
        const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
        setDrivers(defaultDrivers);
        await saveData('drivers', defaultDrivers);
      }
    };
    loadData();
  }, []);

  useEffect(() => {
    if (deliveries.length >= 0) saveData('deliveries', deliveries);
  }, [deliveries]);

  useEffect(() => {
    if (drivers.length >= 0) saveData('drivers', drivers);
  }, [drivers]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);

        const parsedData = rows.map(row => {
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: String(row[8] || `${row[9] || 'Belém'}, Pará`)
          };
        }).filter(Boolean);

        setPendingImport(parsedData);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel.");
      } finally {
        setLoading(false);
        e.target.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Motorista Não Atribuído';

    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -1.4558,
      lng: -48.4902,
    }));

    setDeliveries([...deliveries, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setRole('ADMIN');
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;

    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      const updated = deliveries.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      );
      setDeliveries(updated);

      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const finalizeRejection = async () => {
    if (!rejectionModal) return;
    const updated = deliveries.map(d => 
      d.id === rejectionModal.id ? { 
        ...d, 
        status: DeliveryStatus.REJECTED, 
        updatedAt: new Date().toISOString(),
        notes: 'Cliente recusou a entrega'
      } : d
    );
    setDeliveries(updated);
    setRejectionModal(null);
    setAiMessage("Entrega marcada como devolvida.");
    setTimeout(() => setAiMessage(null), 3000);
  };

  const updateDeliveryStatus = async (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;

    if (newStatus === DeliveryStatus.DELIVERED) {
      setPhotoModal({ id, customer: delivery.customerName });
      return;
    }

    if (newStatus === DeliveryStatus.REJECTED) {
      setRejectionModal({ id, customer: delivery.customerName });
      return;
    }

    const updated = deliveries.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    );
    setDeliveries(updated);
  };

  const handleStartAllRoutes = () => {
    if (!selectedDriver) return;

    const hasPending = deliveries.some(d => d.driverName === selectedDriver && d.status === DeliveryStatus.PENDING);
    if (!hasPending) return;

    const updated = deliveries.map(d => {
      if (d.driverName === selectedDriver && d.status === DeliveryStatus.PENDING) {
        return { ...d, status: DeliveryStatus.IN_TRANSIT, updatedAt: new Date().toISOString() };
      }
      return d;
    });

    setDeliveries(updated);
    setAiMessage("Todos os pedidos agora estão em rota!");
    setTimeout(() => setAiMessage(null), 4000);
  };

  const addDriver = async () => {
    if (!newDriverName.trim()) return;
    const newDriver: Driver = { id: crypto.randomUUID(), name: newDriverName.trim() };
    setDrivers([...drivers, newDriver]);
    setNewDriverName('');
  };

  const removeDriver = async (id: string) => {
    setDrivers(drivers.filter(d => d.id !== id));
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.address.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);
  const pendingOrdersForDriver = driversOrders.filter(d => d.status === DeliveryStatus.PENDING);

  // KPIs
  const currentViewDeliveries = role === 'DRIVER' ? driversOrders : (role === 'CUSTOMER' && searchQuery ? filteredDeliveries : (role === 'ADMIN' ? filteredDeliveries : []));
  const totalOrders = role === 'DRIVER' ? driversOrders.length : deliveries.length;
  const deliveredCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.DELIVERED).length;
  const inTransitCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.IN_TRANSIT).length;
  const rejectedCount = (role === 'DRIVER' ? driversOrders : deliveries).filter(d => d.status === DeliveryStatus.REJECTED).length;

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">

      {/* Mobile Top Header - Compact */}
      <div className="md:hidden bg-slate-900 text-white px-4 py-3 flex items-center justify-between sticky top-0 z-40 shadow-md">
        <div className="flex items-center gap-2">
          <Package className="w-5 h-5 text-blue-500" />
          <h1 className="text-lg font-black tracking-tighter">SwiftLog</h1>
        </div>
        <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-1">
          {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {/* Sidebar - Collapsible */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white p-5 flex flex-col transition-transform duration-300 transform 
        ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:relative md:translate-x-0 md:flex shadow-2xl
      `}>
        <div className="hidden md:flex items-center gap-2 mb-6 px-2">
          <Package className="w-6 h-6 text-blue-500" />
          <h1 className="text-xl font-black tracking-tighter">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {[
            { id: 'ADMIN', label: 'Painel Geral', icon: LayoutDashboard },
            { id: 'DRIVERS_MGMT', label: 'Motoristas', icon: Users },
            { id: 'DRIVER', label: 'Meu Portal', icon: Truck },
            { id: 'CUSTOMER', label: 'Rastreio', icon: Search },
          ].map(item => (
            <button 
              key={item.id}
              onClick={() => {
                setRole(item.id as UserRole);
                setSearchQuery('');
                setIsMenuOpen(false);
              }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${role === item.id ? 'bg-blue-600 text-white font-bold' : 'hover:bg-slate-800 text-slate-400 font-medium'}`}
            >
              <item.icon className="w-4 h-4" />
              <span className="text-xs uppercase tracking-wider">{item.label}</span>
            </button>
          ))}
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-6 space-y-4 overflow-x-hidden">

        {/* AI Notification Overlay */}
        {aiMessage && (
          <div className="fixed top-5 right-5 z-50 animate-in fade-in slide-in-from-top-4">
            <div className="bg-white border-l-4 border-blue-600 text-slate-800 px-4 py-3 rounded-lg shadow-xl flex items-center gap-3">
              <CheckCircle2 className="w-4 h-4 text-blue-600" />
              <p className="text-[10px] font-black uppercase text-slate-600">{aiMessage}</p>
            </div>
          </div>
        )}

        {/* Compact Header */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div>
            <h2 className="text-xl font-black text-slate-900 uppercase leading-none">
              {role === 'ADMIN' && "Administração"}
              {role === 'DRIVERS_MGMT' && "Gestão de Frota"}
              {role === 'DRIVER' && "Minha Rota"}
              {role === 'CUSTOMER' && "Rastreamento"}
            </h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Regional Pará</p>
          </div>
          {role === 'ADMIN' && (
            <label className="flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2.5 rounded-lg font-bold cursor-pointer transition-all active:scale-95 uppercase text-[9px] tracking-widest">
              <FileUp className="w-4 h-4" /> Importar Excel
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </div>

        {/* Compact KPIs */}
        <section className="grid grid-cols-2 lg:grid-cols-4 gap-2 md:gap-4">
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-blue-50 p-2 rounded-lg"><ClipboardList className="w-4 h-4 text-blue-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Pedidos</p>
               <p className="text-lg font-black text-slate-900 leading-none">{totalOrders}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-indigo-50 p-2 rounded-lg"><Truck className="w-4 h-4 text-indigo-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Em Rota</p>
               <p className="text-lg font-black text-indigo-600 leading-none">{inTransitCount}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-green-50 p-2 rounded-lg"><CheckCircle2 className="w-4 h-4 text-green-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Entregues</p>
               <p className="text-lg font-black text-green-600 leading-none">{deliveredCount}</p>
             </div>
          </div>
          <div className="bg-white p-3 rounded-xl border border-slate-200 flex items-center gap-3">
             <div className="bg-red-50 p-2 rounded-lg"><RotateCcw className="w-4 h-4 text-red-600" /></div>
             <div>
               <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Devolvidos</p>
               <p className="text-lg font-black text-red-600 leading-none">{rejectedCount}</p>
             </div>
          </div>
        </section>

        {/* Search and Driver Selection */}
        <div className="space-y-3">
          <div className="flex flex-col md:flex-row gap-3">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
              <input 
                type="text" 
                placeholder={role === 'CUSTOMER' ? "Número do pedido..." : "Pesquisar..."}
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-9 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all font-bold text-slate-700 text-xs"
              />
            </div>

            {role === 'DRIVER' && (
              <div className="bg-slate-900 px-3 py-2 rounded-xl flex items-center gap-3 text-white">
                <Truck className="w-4 h-4 text-blue-400" />
                <select 
                  value={selectedDriver}
                  onChange={(e) => setSelectedDriver(e.target.value)}
                  className="bg-transparent border-none outline-none font-black text-[10px] uppercase tracking-widest cursor-pointer text-white"
                >
                  <option value="" className="text-slate-900">IDENTIFIQUE-SE</option>
                  {drivers.map(d => <option key={d.id} value={d.name} className="text-slate-900">{d.name}</option>)}
                </select>
              </div>
            )}
          </div>

          {/* Mass Action Button for Driver */}
          {role === 'DRIVER' && selectedDriver && pendingOrdersForDriver.length > 0 && (
            <button 
              onClick={handleStartAllRoutes}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white py-3 rounded-xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest shadow-lg shadow-blue-200 transition-all active:scale-[0.98] border-b-4 border-blue-800"
            >
              <Play className="w-4 h-4 fill-white" />
              Sair com toda a carga ({pendingOrdersForDriver.length} pedidos)
            </button>
          )}
        </div>

        {/* Deliveries List - Grid of Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-3">
          {currentViewDeliveries.map((delivery) => (
            <div key={delivery.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm hover:border-blue-300 transition-all flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-2">
                  <div className="flex flex-col">
                    <span className="font-mono text-blue-600 font-black text-sm">#{delivery.orderNumber}</span>
                    <span className="text-[9px] font-bold text-slate-400 uppercase flex items-center gap-1 mt-1">
                      <MapPin className="w-3 h-3 text-red-400" /> {delivery.city}
                    </span>
                  </div>
                  <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                    delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-50 text-green-700 border-green-200' :
                    delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-indigo-50 text-indigo-700 border-indigo-200' :
                    delivery.status === DeliveryStatus.REJECTED ? 'bg-red-50 text-red-700 border-red-200' :
                    'bg-orange-50 text-orange-700 border-orange-200'
                  }`}>
                    {delivery.status}
                  </span>
                </div>

                <h3 className="font-black text-slate-900 text-base leading-tight uppercase mb-1">{delivery.customerName}</h3>

                <div className="space-y-1 mb-4">
                  <div className="flex items-center gap-2">
                    <p className="text-[9px] text-green-600 font-black flex items-center gap-0.5 uppercase bg-green-50 px-1.5 py-0.5 rounded-lg">
                      <DollarSign className="w-2.5 h-2.5" />
                      {delivery.orderValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </p>
                    {role === 'ADMIN' && (
                      <p className="text-[8px] text-slate-400 font-bold uppercase flex items-center gap-1">
                        <User className="w-3 h-3" /> {delivery.driverName}
                      </p>
                    )}
                  </div>
                  <p className="text-[9px] text-slate-500 italic leading-tight">{delivery.address}</p>
                </div>
              </div>

              <div className="flex gap-2 pt-3 border-t border-slate-50">
                {role === 'DRIVER' && (delivery.status !== DeliveryStatus.DELIVERED && delivery.status !== DeliveryStatus.REJECTED) && (
                  <>
                    {delivery.status === DeliveryStatus.PENDING && (
                      <div className="flex w-full gap-2">
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 px-3 py-2.5 rounded-lg border border-red-100 flex items-center justify-center gap-1 active:scale-95" title="Recusar/Devolver">
                          <RotateCcw className="w-4 h-4" />
                        </button>
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)} className="flex-1 bg-indigo-600 text-white p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase active:scale-95">
                          <Navigation className="w-3.5 h-3.5" /> Iniciar Rota
                        </button>
                      </div>
                    )}
                    {delivery.status === DeliveryStatus.IN_TRANSIT && (
                      <div className="flex w-full gap-2">
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 px-3 py-2.5 rounded-lg border border-red-100 flex items-center justify-center gap-1 active:scale-95" title="Recusar/Devolver">
                          <RotateCcw className="w-4 h-4" />
                        </button>
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)} className="flex-1 bg-green-600 text-white flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg font-black text-[9px] uppercase active:scale-95">
                          <Camera className="w-4 h-4" /> Finalizar
                        </button>
                      </div>
                    )}
                  </>
                )}
                {delivery.receiptPhoto && (
                  <button onClick={() => setViewPhoto(delivery.receiptPhoto || null)} className="flex-1 bg-slate-50 text-slate-500 p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase border border-slate-100 hover:bg-blue-50 hover:text-blue-600">
                    <ImageIcon className="w-4 h-4" /> Comprovante
                  </button>
                )}
              </div>
            </div>
          ))}

          {currentViewDeliveries.length === 0 && (
            <div className="col-span-full py-16 text-center opacity-20">
              <Search className="w-10 h-10 mx-auto mb-2" />
              <p className="text-xs font-black uppercase tracking-widest">Nenhum pedido encontrado</p>
            </div>
          )}
        </div>

        {/* Drivers Management */}
        {role === 'DRIVERS_MGMT' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm space-y-4 h-fit">
              <h3 className="font-black text-slate-900 flex items-center gap-2 uppercase text-[10px] tracking-widest">
                <Plus className="w-4 h-4 text-blue-600" /> Novo Motorista
              </h3>
              <input 
                type="text" 
                placeholder="Nome completo..."
                value={newDriverName}
                onChange={(e) => setNewDriverName(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-xs"
              />
              <button onClick={addDriver} className="w-full bg-slate-900 text-white font-black py-3 rounded-lg uppercase text-[9px] tracking-widest active:scale-95">
                Cadastrar
              </button>
            </div>
            <div className="lg:col-span-2 space-y-2">
              {drivers.map(driver => (
                <div key={driver.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
                  <p className="font-black text-slate-900 text-xs uppercase">{driver.name}</p>
                  <button onClick={() => removeDriver(driver.id)} className="p-2 text-red-400 hover:bg-red-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Modal: Photo Capture */}
        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center space-y-3">
                <div className="w-12 h-12 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <Camera className="w-6 h-6" />
