            <button 
              onClick={handleStartAllRoutes}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white py-3 rounded-xl flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest shadow-lg shadow-blue-200 transition-all active:scale-[0.98] border-b-4 border-blue-800"
            >
              <Play className="w-4 h-4 fill-white" />
              Sair com toda a carga ({pendingOrdersForDriver.length} pedidos)
            </button>
          )}
        </div>

        {/* Card Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-3">
          {currentViewDeliveries.map((delivery) => (
            <div key={delivery.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm hover:border-blue-300 transition-all flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-2">
                  <div className="flex flex-col">
                    <span className="font-mono text-blue-600 font-black text-sm">#{delivery.orderNumber}</span>
                    <span className="text-[9px] font-bold text-slate-400 uppercase flex items-center gap-1 mt-1">
                      <MapPin className="w-3 h-3 text-red-400" /> {delivery.city}
                    </span>
                  </div>
                  <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                    delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-50 text-green-700 border-green-200' :
                    delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-indigo-50 text-indigo-700 border-indigo-200' :
                    delivery.status === DeliveryStatus.REJECTED ? 'bg-red-50 text-red-700 border-red-200' :
                    'bg-orange-50 text-orange-700 border-orange-200'
                  }`}>
                    {delivery.status}
                  </span>
                </div>

                <h3 className="font-black text-slate-900 text-base leading-tight uppercase mb-1">{delivery.customerName}</h3>

                <div className="space-y-1 mb-4">
                  <div className="flex items-center gap-2">
                    <p className="text-[9px] text-green-600 font-black flex items-center gap-0.5 uppercase bg-green-50 px-1.5 py-0.5 rounded-lg">
                      <DollarSign className="w-2.5 h-2.5" />
                      {delivery.orderValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </p>
                    {role === 'ADMIN' && (
                      <p className="text-[8px] text-slate-400 font-bold uppercase flex items-center gap-1">
                        <User className="w-3 h-3" /> {delivery.driverName}
                      </p>
                    )}
                  </div>
                  <p className="text-[9px] text-slate-500 italic leading-tight">{delivery.address}</p>
                </div>
              </div>

              {/* Actions */}
              <div className="flex gap-2 pt-3 border-t border-slate-50">
                {role === 'DRIVER' && (delivery.status !== DeliveryStatus.DELIVERED && delivery.status !== DeliveryStatus.REJECTED) && (
                  <>
                    {delivery.status === DeliveryStatus.PENDING && (
                      <div className="flex w-full gap-2">
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 px-3 py-2.5 rounded-lg border border-red-100 flex items-center justify-center gap-1 active:scale-95" title="Recusar/Devolver">
                          <RotateCcw className="w-4 h-4" />
                        </button>
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)} className="flex-1 bg-indigo-600 text-white p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase active:scale-95">
                          <Navigation className="w-3.5 h-3.5" /> Iniciar Rota
                        </button>
                      </div>
                    )}
                    {delivery.status === DeliveryStatus.IN_TRANSIT && (
                      <div className="flex w-full gap-2">
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 px-3 py-2.5 rounded-lg border border-red-100 flex items-center justify-center gap-1 active:scale-95" title="Recusar/Devolver">
                          <RotateCcw className="w-4 h-4" />
                        </button>
                        <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)} className="flex-1 bg-green-600 text-white flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg font-black text-[9px] uppercase active:scale-95">
                          <Camera className="w-4 h-4" /> Finalizar
                        </button>
                      </div>
                    )}
                  </>
                )}
                {delivery.receiptPhoto && (
                  <button onClick={() => setViewPhoto(delivery.receiptPhoto || null)} className="flex-1 bg-slate-50 text-slate-500 p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase border border-slate-100 hover:bg-blue-50 hover:text-blue-600 transition-colors">
                    <ImageIcon className="w-4 h-4" /> Comprovante
                  </button>
                )}
                {role === 'ADMIN' && (
                   <button onClick={() => {
                     setDeliveries(prev => prev.filter(d => d.id !== delivery.id));
                   }} className="p-2.5 text-slate-300 hover:text-red-500 transition-colors" title="Remover">
                      <Trash2 className="w-4 h-4" />
                   </button>
                )}
              </div>
            </div>
          ))}

          {currentViewDeliveries.length === 0 && (
            <div className="col-span-full py-24 text-center">
              <div className="inline-flex items-center justify-center w-16 h-16 bg-slate-100 rounded-full mb-4">
                 <Search className="w-6 h-6 text-slate-300" />
              </div>
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-300">Nenhum pedido encontrado</p>
            </div>
          )}
        </div>

        {/* Drivers MGMT View */}
        {role === 'DRIVERS_MGMT' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
            <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm space-y-4 h-fit">
              <h3 className="font-black text-slate-900 flex items-center gap-2 uppercase text-[10px] tracking-widest">
                <Plus className="w-4 h-4 text-blue-600" /> Novo Motorista
              </h3>
              <input 
                type="text" 
                placeholder="Nome completo..."
                value={newDriverName}
                onChange={(e) => setNewDriverName(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-xs"
              />
              <button onClick={addDriver} className="w-full bg-slate-900 text-white font-black py-3 rounded-lg uppercase text-[9px] tracking-widest active:scale-95">
                Cadastrar
              </button>
            </div>
            <div className="lg:col-span-2 space-y-2">
              {drivers.map(driver => (
                <div key={driver.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
                  <p className="font-black text-slate-900 text-xs uppercase">{driver.name}</p>
                  <button onClick={() => removeDriver(driver.id)} className="p-2 text-red-400 hover:bg-red-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Modals */}
        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center space-y-3">
                <div className="w-12 h-12 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <Camera className="w-6 h-6" />
                </div>
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Foto do Canhoto</h3>
                <p className="text-[10px] text-slate-500 font-medium leading-relaxed">Capture a foto do comprovante para finalizar a entrega de <strong>{photoModal.customer}</strong>.</p>
              </div>
              <button onClick={() => fileInputRef.current?.click()} className="w-full bg-blue-600 text-white font-black py-4 rounded-xl flex items-center justify-center gap-2 uppercase text-[10px] active:scale-95 shadow-lg">
                <Camera className="w-4 h-4" /> Abrir Câmera
              </button>
              <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
              <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[9px]">Cancelar</button>
            </div>
          </div>
        )}

        {rejectionModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center space-y-3">
                <div className="w-12 h-12 bg-red-100 text-red-600 rounded-full flex items-center justify-center mx-auto shadow-inner">
                  <AlertCircle className="w-6 h-6" />
                </div>
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Confirmar Devolução</h3>
                <p className="text-[10px] text-slate-500 font-medium leading-relaxed">Deseja marcar o pedido de <strong>{rejectionModal.customer}</strong> como devolvido?</p>
              </div>
              <div className="flex flex-col gap-2">
                <button onClick={finalizeRejection} className="w-full bg-red-600 text-white font-black py-4 rounded-xl uppercase text-[10px] active:scale-95 shadow-lg">
                  Confirmar Devolução
                </button>
                <button onClick={() => setRejectionModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[9px]">Cancelar</button>
              </div>
            </div>
          </div>
        )}

        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-sm w-full animate-in zoom-in-95 duration-200">
              <button onClick={() => setViewPhoto(null)} className="absolute -top-10 right-0 text-white flex items-center gap-1 font-black text-[10px] uppercase tracking-widest"><X className="w-5 h-5" /> Fechar</button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-xl shadow-2xl" />
            </div>
          </div>
        )}

        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4">
            <div className="bg-white w-full max-w-xs rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center">
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Vincular Carga</h3>
                <p className="text-[10px] text-slate-500 mt-1"><strong>{pendingImport.length} pedidos</strong> detectados.</p>
              </div>
              <select 
                value={importDriverId}
                onChange={(e) => setImportDriverId(e.target.value)}
                className="w-full px-3 py-3 bg-slate-50 border border-slate-200 rounded-lg font-black text-slate-800 text-[10px] uppercase outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="">Selecione o motorista...</option>
                {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
              <div className="flex gap-2">
                <button onClick={() => setPendingImport(null)} className="flex-1 py-2 text-[9px] font-black text-slate-400 uppercase">Voltar</button>
                <button onClick={confirmImport} disabled={!importDriverId} className="flex-1 py-2 bg-blue-600 text-white rounded-lg font-black text-[9px] uppercase shadow-lg disabled:opacity-30">Confirmar</button>
              </div>
            </div>
          </div>
        )}

        {loading && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center gap-3 animate-pulse">
                <div className="w-6 h-6 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-[8px]">Aguarde...</p>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export enum DeliveryStatus {
  PENDING = 'PENDENTE',
  IN_TRANSIT = 'EM TRÂNSITO',
  DELIVERED = 'ENTREGUE',
  FAILED = 'FALHA NA ENTREGA',
  REJECTED = 'DEVOLVIDO'
}

export interface Driver {
  id: string;
  name: string;
  phone?: string;
  vehicle?: string;
}

export interface Delivery {
  id: string;
  orderNumber: string;
  customerName: string;
  orderValue: number;
  city: string;
  address: string;
  driverName: string;
  status: DeliveryStatus;
  updatedAt: string;
  completedAt?: string;
  lat: number;
  lng: number;
  notes?: string;
  receiptPhoto?: string; // Base64 image
}

export type UserRole = 'ADMIN' | 'MOTORISTA' | 'VENDEDOR';

export interface AppState {
  deliveries: Delivery[];
  drivers: Driver[];
  currentUserRole: UserRole | null;
  selectedDriver: string | null;
}

import React, { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Users,
  Search, 
  FileUp, 
  CheckCircle2, 
  MapPin, 
  DollarSign, 
  Camera, 
  X, 
  ImageIcon, 
  RotateCcw, 
  Navigation, 
  ClipboardList, 
  Menu,
  Trash2,
  Plus,
  LayoutDashboard,
  AlertCircle,
  Play,
  Database,
  ShieldCheck,
  LogOut,
  ShoppingBag
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import { generateTrackingMessage } from './services/geminiService';
import { saveData, getData } from './services/dbService';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [loggedRole, setLoggedRole] = useState<UserRole | null>(null);
  const [activeView, setActiveView] = useState<string>('');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriver, setSelectedDriver] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [newDriverName, setNewDriverName] = useState('');
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);

  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // 1. Carregamento Inicial
  useEffect(() => {
    const loadStoredData = async () => {
      try {
        const storedDeliveries = await getData('deliveries');
        const storedDrivers = await getData('drivers');

        if (storedDeliveries.length > 0) setDeliveries(storedDeliveries);
        if (storedDrivers.length > 0) setDrivers(storedDrivers);
        else {
          const defaultDrivers = [{ id: '1', name: 'João Carlos' }, { id: '2', name: 'Maria Silva' }];
          setDrivers(defaultDrivers);
          await saveData('drivers', defaultDrivers);
        }
      } catch (err) {
        console.error("Falha ao inicializar banco de dados:", err);
      } finally {
        setIsInitialized(true);
      }
    };
    loadStoredData();
  }, []);

  // 2. Persistência Automática
  useEffect(() => {
    if (isInitialized) saveData('deliveries', deliveries);
  }, [deliveries, isInitialized]);

  useEffect(() => {
    if (isInitialized) saveData('drivers', drivers);
  }, [drivers, isInitialized]);

  // Define a visualização inicial ao logar
  useEffect(() => {
    if (loggedRole === 'ADMIN') setActiveView('ADMIN_PANEL');
    else if (loggedRole === 'MOTORISTA') setActiveView('DRIVER_PORTAL');
    else if (loggedRole === 'VENDEDOR') setActiveView('TRACKING');
  }, [loggedRole]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);
        const parsedData = rows.map(row => {
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: String(row[8] || `${row[9] || 'Belém'}, Pará`)
          };
        }).filter(Boolean);
        setPendingImport(parsedData);
      } catch (err) { alert("Erro ao ler o arquivo Excel."); }
      finally { setLoading(false); e.target.value = ''; }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Não Atribuído';
    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -1.4558 + (Math.random() * 0.1 - 0.05),
      lng: -48.4902 + (Math.random() * 0.1 - 0.05),
    }));
    setDeliveries(prev => [...prev, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setAiMessage(`${newDeliveries.length} entregas importadas!`);
    setTimeout(() => setAiMessage(null), 3000);
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;
    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      setDeliveries(prev => prev.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      ));
      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const finalizeRejection = async () => {
    if (!rejectionModal) return;
    setDeliveries(prev => prev.map(d => 
      d.id === rejectionModal.id ? { 
        ...d, 
        status: DeliveryStatus.REJECTED, 
        updatedAt: new Date().toISOString(),
        notes: 'Recusado pelo cliente'
      } : d
    ));
    setRejectionModal(null);
    setAiMessage("Entrega marcada como devolvida.");
    setTimeout(() => setAiMessage(null), 3000);
  };

  const updateDeliveryStatus = (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;
    if (newStatus === DeliveryStatus.DELIVERED) { setPhotoModal({ id, customer: delivery.customerName }); return; }
    if (newStatus === DeliveryStatus.REJECTED) { setRejectionModal({ id, customer: delivery.customerName }); return; }
    setDeliveries(prev => prev.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    ));
  };

  const handleStartAllRoutes = () => {
    if (!selectedDriver) return;
    setDeliveries(prev => prev.map(d => {
      if (d.driverName === selectedDriver && d.status === DeliveryStatus.PENDING) {
        return { ...d, status: DeliveryStatus.IN_TRANSIT, updatedAt: new Date().toISOString() };
      }
      return d;
    }));
    setAiMessage("Todos os seus pedidos estão em rota!");
    setTimeout(() => setAiMessage(null), 4000);
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriver);
  const pendingOrdersForDriver = driversOrders.filter(d => d.status === DeliveryStatus.PENDING);

  // --- RENDERING LOGIC ---

  if (!loggedRole) {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-6 text-white">
        <div className="mb-12 text-center space-y-2">
          <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg shadow-blue-500/20">
            <Package className="w-10 h-10" />
          </div>
          <h1 className="text-4xl font-black tracking-tighter">SwiftLog</h1>
          <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.2em]">SISTEMA DE LOGÍSTICA REGIONAL</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full max-w-5xl">
          {[
            { id: 'ADMIN', label: 'Administrador', icon: ShieldCheck, color: 'bg-blue-600', desc: 'Controle de carga e motoristas' },
            { id: 'MOTORISTA', label: 'Motorista', icon: Truck, color: 'bg-indigo-600', desc: 'Meu portal de entregas e rotas' },
            { id: 'VENDEDOR', label: 'Vendedor', icon: ShoppingBag, color: 'bg-emerald-600', desc: 'Rastreio e status de pedidos' },
          ].map(role => (
            <button 
              key={role.id}
              onClick={() => setLoggedRole(role.id as UserRole)}
              className="bg-slate-900 border border-slate-800 p-8 rounded-3xl hover:border-blue-500 transition-all group text-left space-y-4 hover:-translate-y-2 active:scale-95 shadow-xl"
            >
              <div className={`${role.color} w-12 h-12 rounded-xl flex items-center justify-center group-hover:scale-110 transition-transform`}>
                <role.icon className="w-6 h-6" />
              </div>
              <div>
                <h3 className="text-xl font-black uppercase tracking-tight">{role.label}</h3>
                <p className="text-sm text-slate-500 font-medium">{role.desc}</p>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  // Define menus baseados no LoggedRole
  const navItems = [];
  if (loggedRole === 'ADMIN') {
    navItems.push({ id: 'ADMIN_PANEL', label: 'Painel Geral', icon: LayoutDashboard });
    navItems.push({ id: 'DRIVERS_MGMT', label: 'Motoristas', icon: Users });
  }
  if (loggedRole === 'MOTORISTA') {
    navItems.push({ id: 'DRIVER_PORTAL', label: 'Meu Portal', icon: Truck });
  }
  if (loggedRole === 'VENDEDOR') {
    navItems.push({ id: 'TRACKING', label: 'Rastreio', icon: Search });
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">

      {/* Mobile Top Header */}
      <div className="md:hidden bg-slate-900 text-white px-4 py-3 flex items-center justify-between sticky top-0 z-40 shadow-md">
        <div className="flex items-center gap-2">
          <Package className="w-5 h-5 text-blue-500" />
          <h1 className="text-lg font-black tracking-tighter">SwiftLog</h1>
        </div>
        <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-1">
          {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white p-5 flex flex-col transition-transform duration-300 transform 
        ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:relative md:translate-x-0 md:flex shadow-2xl
      `}>
        <div className="hidden md:flex items-center gap-2 mb-6 px-2">
          <Package className="w-6 h-6 text-blue-500" />
          <h1 className="text-xl font-black tracking-tighter">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {navItems.map(item => (
            <button 
              key={item.id}
              onClick={() => { setActiveView(item.id); setIsMenuOpen(false); }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeView === item.id ? 'bg-blue-600 text-white font-bold' : 'hover:bg-slate-800 text-slate-400 font-medium'}`}
            >
              <item.icon className="w-4 h-4" />
              <span className="text-[10px] uppercase tracking-wider font-black">{item.label}</span>
            </button>
          ))}
        </nav>

        {/* User Info & Logout */}
        <div className="mt-auto pt-4 border-t border-slate-800 space-y-4">
           <div className="px-2">
              <p className="text-[8px] font-black uppercase text-slate-500 tracking-widest">SESSÃO ATIVA</p>
              <div className="flex items-center gap-2 mt-1">
                 <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                 <p className="text-xs font-black text-white">{loggedRole}</p>
              </div>
           </div>
           <button onClick={() => setLoggedRole(null)} className="w-full bg-slate-800 hover:bg-red-900/40 text-red-400 p-3 rounded-xl flex items-center justify-center gap-2 font-black text-[9px] uppercase transition-colors">
              <LogOut className="w-4 h-4" /> Sair / Trocar Perfil
           </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-6 space-y-4 overflow-x-hidden">

        {/* AI Notification */}
        {aiMessage && (
          <div className="fixed top-5 right-5 z-50 animate-in fade-in slide-in-from-top-4">
            <div className="bg-white border-l-4 border-blue-600 text-slate-800 px-4 py-3 rounded-lg shadow-xl flex items-center gap-3">
              <CheckCircle2 className="w-4 h-4 text-blue-600" />
              <p className="text-[10px] font-black uppercase text-slate-600">{aiMessage}</p>
            </div>
          </div>
        )}

        {/* View Header */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div>
            <h2 className="text-xl font-black text-slate-900 uppercase leading-none">
              {activeView === 'ADMIN_PANEL' && "Painel de Administração"}
              {activeView === 'DRIVERS_MGMT' && "Gestão de Motoristas"}
              {activeView === 'DRIVER_PORTAL' && "Meu Portal de Entregas"}
              {activeView === 'TRACKING' && "Rastreamento de Vendas"}
            </h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">SISTEMA ATIVO - REGIONAL PA</p>
          </div>
          {activeView === 'ADMIN_PANEL' && (
            <label className="flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2.5 rounded-lg font-bold cursor-pointer transition-all active:scale-95 uppercase text-[9px] tracking-widest shadow-lg shadow-blue-200">
              <FileUp className="w-4 h-4" /> Importar Planilha
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </div>

        {/* SEARCH AND DRIVER SELECTION (Contextual) */}
        <div className="space-y-3">
          <div className="flex flex-col md:flex-row gap-3">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
              <input 
                type="text" 
                placeholder="Pesquisar por pedido, cliente ou cidade..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-9 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-700 text-xs shadow-sm"
              />
            </div>
            {activeView === 'DRIVER_PORTAL' && (
              <div className="bg-slate-900 px-4 py-2 rounded-xl flex items-center gap-3 text-white shadow-lg">
                <User className="w-4 h-4 text-blue-400" />
                <select 
                  value={selectedDriver}
                  onChange={(e) => setSelectedDriver(e.target.value)}
                  className="bg-transparent border-none outline-none font-black text-[10px] uppercase tracking-widest cursor-pointer text-white"
                >
                  <option value="" className="text-slate-900">SELECIONE SEU NOME</option>
                  {drivers.map(d => <option key={d.id} value={d.name} className="text-slate-900">{d.name}</option>)}
                </select>
              </div>
            )}
          </div>

          {activeView === 'DRIVER_PORTAL' && selectedDriver && pendingOrdersForDriver.length > 0 && (
            <button 
              onClick={handleStartAllRoutes}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white py-4 rounded-xl flex items-center justify-center gap-3 font-black text-[11px] uppercase tracking-widest shadow-xl shadow-blue-200 transition-all active:scale-[0.98] border-b-4 border-blue-800"
            >
              <Play className="w-4 h-4 fill-white" />
              Iniciar Rota de Toda a Carga ({pendingOrdersForDriver.length} pedidos)
            </button>
          )}
        </div>

        {/* LISTA DE ENTREGAS (Filtrada por View) */}
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-3">
          {(activeView === 'DRIVER_PORTAL' ? driversOrders : filteredDeliveries).map((delivery) => (
            <div key={delivery.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm hover:border-blue-300 transition-all flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-2">
                  <span className="font-mono text-blue-600 font-black text-sm">#{delivery.orderNumber}</span>
                  <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                    delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-50 text-green-700 border-green-200' :
                    delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-indigo-50 text-indigo-700 border-indigo-200' :
                    delivery.status === DeliveryStatus.REJECTED ? 'bg-red-50 text-red-700 border-red-200' :
                    'bg-orange-50 text-orange-700 border-orange-200'
                  }`}>
                    {delivery.status}
                  </span>
                </div>
                <h3 className="font-black text-slate-900 text-base uppercase leading-tight">{delivery.customerName}</h3>
                <div className="mt-2 space-y-1">
                   <p className="text-[10px] font-bold text-slate-400 uppercase flex items-center gap-1">
                      <MapPin className="w-3 h-3" /> {delivery.city}
                   </p>
                   <p className="text-[9px] text-slate-500 italic leading-tight">{delivery.address}</p>
                   <div className="flex items-center gap-2 mt-2">
                      <span className="text-[9px] font-black bg-green-50 text-green-700 px-2 py-0.5 rounded-lg flex items-center gap-1">
                         <DollarSign className="w-3 h-3" /> {delivery.orderValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                      </span>
                      {loggedRole === 'ADMIN' && (
                        <span className="text-[9px] font-bold text-slate-400 uppercase">Motorista: {delivery.driverName}</span>
                      )}
                   </div>
                </div>
              </div>

              {/* AÇÕES */}
              <div className="flex gap-2 pt-4 mt-4 border-t border-slate-50">
                {activeView === 'DRIVER_PORTAL' && delivery.status !== DeliveryStatus.DELIVERED && delivery.status !== DeliveryStatus.REJECTED && (
                  <>
                    <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 px-3 py-2.5 rounded-lg border border-red-100 flex items-center justify-center active:scale-95" title="Devolver">
                      <RotateCcw className="w-4 h-4" />
                    </button>
                    {delivery.status === DeliveryStatus.PENDING ? (
                      <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)} className="flex-1 bg-indigo-600 text-white p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase active:scale-95">
                         Iniciar
                      </button>
                    ) : (
                      <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)} className="flex-1 bg-green-600 text-white p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase active:scale-95">
                         <Camera className="w-4 h-4" /> Entregar
                      </button>
                    )}
                  </>
                )}
                {delivery.receiptPhoto && (
                  <button onClick={() => setViewPhoto(delivery.receiptPhoto || null)} className="flex-1 bg-slate-50 text-slate-500 p-2.5 rounded-lg flex items-center justify-center gap-2 font-black text-[9px] uppercase border border-slate-100 hover:bg-blue-50 hover:text-blue-600 transition-colors">
                    <ImageIcon className="w-4 h-4" /> Comprovante
                  </button>
                )}
                {loggedRole === 'ADMIN' && activeView === 'ADMIN_PANEL' && (
                  <button onClick={() => setDeliveries(prev => prev.filter(d => d.id !== delivery.id))} className="p-2.5 text-slate-200 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
                )}
              </div>
            </div>
          ))}
          {((activeView === 'DRIVER_PORTAL' ? driversOrders : filteredDeliveries).length === 0) && (
            <div className="col-span-full py-24 text-center opacity-30">
               <Package className="w-12 h-12 mx-auto mb-2" />
               <p className="text-[10px] font-black uppercase tracking-widest">Nenhuma entrega para mostrar</p>
            </div>
          )}
        </div>

        {/* GESTÃO DE MOTORISTAS (Apenas ADMIN) */}
        {activeView === 'DRIVERS_MGMT' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4 h-fit">
              <h3 className="font-black text-slate-900 uppercase text-[10px] tracking-widest flex items-center gap-2">
                <Plus className="w-4 h-4 text-blue-600" /> Cadastrar Novo
              </h3>
              <input 
                type="text" 
                placeholder="Nome completo..."
                value={newDriverName}
                onChange={(e) => setNewDriverName(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-xs"
              />
              <button onClick={() => {
                if (!newDriverName.trim()) return;
                setDrivers(prev => [...prev, { id: crypto.randomUUID(), name: newDriverName.trim() }]);
                setNewDriverName('');
              }} className="w-full bg-slate-900 text-white font-black py-4 rounded-xl uppercase text-[10px] shadow-lg active:scale-95">
                Salvar Motorista
              </button>
            </div>
            <div className="lg:col-span-2 space-y-2">
              {drivers.map(driver => (
                <div key={driver.id} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between hover:border-blue-200 transition-all">
                  <p className="font-black text-slate-900 text-xs uppercase tracking-tight">{driver.name}</p>
                  <button onClick={() => setDrivers(prev => prev.filter(d => d.id !== driver.id))} className="p-2 text-slate-300 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* MODAIS (Reutilizados do sistema anterior) */}
        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center space-y-2">
                <Camera className="w-10 h-10 text-green-600 mx-auto" />
                <h3 className="text-sm font-black text-slate-900 uppercase">Foto do Canhoto</h3>
                <p className="text-[10px] text-slate-500 uppercase font-black tracking-tighter">CLIENTE: {photoModal.customer}</p>
              </div>
              <button onClick={() => fileInputRef.current?.click()} className="w-full bg-blue-600 text-white font-black py-4 rounded-xl uppercase text-[10px] active:scale-95">Abrir Câmera</button>
              <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
              <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[9px]">Cancelar</button>
            </div>
          </div>
        )}

        {rejectionModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-2xl p-6 space-y-6 shadow-2xl">
              <div className="text-center space-y-2">
                <AlertCircle className="w-10 h-10 text-red-600 mx-auto" />
                <h3 className="text-sm font-black text-slate-900 uppercase">Confirmar Devolução</h3>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-tighter">Registrar devolução para {rejectionModal.customer}?</p>
              </div>
              <div className="flex flex-col gap-2">
                <button onClick={finalizeRejection} className="w-full bg-red-600 text-white font-black py-4 rounded-xl uppercase text-[10px] active:scale-95">Confirmar</button>
                <button onClick={() => setRejectionModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[9px]">Cancelar</button>
              </div>
            </div>
          </div>
        )}

        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-sm w-full">
              <button onClick={() => setViewPhoto(null)} className="absolute -top-10 right-0 text-white flex items-center gap-1 font-black text-[10px] uppercase"><X className="w-5 h-5" /> Fechar</button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-xl shadow-2xl" />
            </div>
          </div>
        )}

        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4">
            <div className="bg-white w-full max-w-xs rounded-3xl p-6 space-y-6 shadow-2xl">
              <div className="text-center">
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Vincular Carga</h3>
                <p className="text-[10px] text-slate-500 mt-1 uppercase font-bold">{pendingImport.length} pedidos detectados</p>
              </div>
              <select 
                value={importDriverId}
                onChange={(e) => setImportDriverId(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl font-black text-slate-800 text-[10px] uppercase outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="">Selecione o motorista...</option>
                {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
              <div className="flex gap-2">
                <button onClick={() => setPendingImport(null)} className="flex-1 py-2 text-[9px] font-black text-slate-400 uppercase">Voltar</button>
                <button onClick={confirmImport} disabled={!importDriverId} className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-black text-[9px] uppercase shadow-lg disabled:opacity-30">Confirmar</button>
              </div>
            </div>
          </div>
        )}

        {loading && (
          <div className="fixed inset-0 bg-slate-950/40 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center gap-3 animate-pulse">
                <div className="w-6 h-6 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-[8px]">Aguarde...</p>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export enum DeliveryStatus {
  PENDING = 'PENDENTE',
  IN_TRANSIT = 'EM TRÂNSITO',
  DELIVERED = 'ENTREGUE',
  FAILED = 'FALHA NA ENTREGA',
  REJECTED = 'DEVOLVIDO'
}

export interface Driver {
  id: string;
  name: string;
  password?: string; // Senha para acesso individual
  phone?: string;
  vehicle?: string;
}

export interface Delivery {
  id: string;
  orderNumber: string;
  customerName: string;
  orderValue: number;
  city: string;
  address: string;
  driverName: string;
  status: DeliveryStatus;
  updatedAt: string;
  completedAt?: string;
  lat: number;
  lng: number;
  notes?: string;
  receiptPhoto?: string; // Base64 image
}

export type UserRole = 'ADMIN' | 'MOTORISTA' | 'VENDEDOR';

export interface AppState {
  deliveries: Delivery[];
  drivers: Driver[];
  currentUserRole: UserRole | null;
  selectedDriver: string | null;
}

import React, { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Users,
  Search, 
  FileUp, 
  CheckCircle2, 
  MapPin, 
  DollarSign, 
  Camera, 
  X, 
  ImageIcon, 
  RotateCcw, 
  Navigation, 
  ClipboardList, 
  Menu,
  Trash2,
  Plus,
  LayoutDashboard,
  AlertCircle,
  Play,
  Database,
  ShieldCheck,
  LogOut,
  ShoppingBag,
  Lock,
  Eye,
  EyeOff
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import { generateTrackingMessage } from './services/geminiService';
import { saveData, getData } from './services/dbService';

const ADMIN_PASSWORD_DEFAULT = 'admin123';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [loggedRole, setLoggedRole] = useState<UserRole | null>(null);
  const [activeView, setActiveView] = useState<string>('');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriverName, setSelectedDriverName] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);

  // Login States
  const [authStep, setAuthStep] = useState<'CHOICE' | 'CREDENTIALS'>('CHOICE');
  const [selectedRole, setSelectedRole] = useState<UserRole | null>(null);
  const [passwordInput, setPasswordInput] = useState('');
  const [driverLoginId, setDriverLoginId] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [authError, setAuthError] = useState<string | null>(null);

  // Management States
  const [newDriverName, setNewDriverName] = useState('');
  const [newDriverPass, setNewDriverPass] = useState('');

  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadStoredData = async () => {
      try {
        const storedDeliveries = await getData('deliveries');
        const storedDrivers = await getData('drivers');
        if (storedDeliveries.length > 0) setDeliveries(storedDeliveries);
        if (storedDrivers.length > 0) setDrivers(storedDrivers);
        else {
          const defaultDrivers = [
            { id: '1', name: 'João Carlos', password: '123' }, 
            { id: '2', name: 'Maria Silva', password: '123' }
          ];
          setDrivers(defaultDrivers);
          await saveData('drivers', defaultDrivers);
        }
      } catch (err) { console.error("Falha ao inicializar banco:", err); }
      finally { setIsInitialized(true); }
    };
    loadStoredData();
  }, []);

  useEffect(() => {
    if (isInitialized) saveData('deliveries', deliveries);
  }, [deliveries, isInitialized]);

  useEffect(() => {
    if (isInitialized) saveData('drivers', drivers);
  }, [drivers, isInitialized]);

  const handleLogin = () => {
    setAuthError(null);
    if (selectedRole === 'ADMIN') {
      if (passwordInput === ADMIN_PASSWORD_DEFAULT) {
        setLoggedRole('ADMIN');
        setActiveView('ADMIN_PANEL');
      } else {
        setAuthError('Senha de administrador incorreta.');
      }
    } else if (selectedRole === 'MOTORISTA') {
      const driver = drivers.find(d => d.id === driverLoginId);
      if (driver && driver.password === passwordInput) {
        setLoggedRole('MOTORISTA');
        setSelectedDriverName(driver.name);
        setActiveView('DRIVER_PORTAL');
      } else {
        setAuthError('Nome ou senha do motorista incorretos.');
      }
    } else if (selectedRole === 'VENDEDOR') {
      setLoggedRole('VENDEDOR');
      setActiveView('TRACKING');
    }
  };

  const logout = () => {
    setLoggedRole(null);
    setAuthStep('CHOICE');
    setSelectedRole(null);
    setPasswordInput('');
    setDriverLoginId('');
    setSelectedDriverName('');
    setAuthError(null);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);
        const parsedData = rows.map(row => {
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: String(row[8] || `${row[9] || 'Belém'}, Pará`)
          };
        }).filter(Boolean);
        setPendingImport(parsedData);
      } catch (err) { alert("Erro ao ler o arquivo Excel."); }
      finally { setLoading(false); e.target.value = ''; }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Não Atribuído';
    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -1.4558 + (Math.random() * 0.1 - 0.05),
      lng: -48.4902 + (Math.random() * 0.1 - 0.05),
    }));
    setDeliveries(prev => [...prev, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setAiMessage(`${newDeliveries.length} entregas importadas!`);
    setTimeout(() => setAiMessage(null), 3000);
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;
    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      setDeliveries(prev => prev.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      ));
      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const updateDeliveryStatus = (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;
    if (newStatus === DeliveryStatus.DELIVERED) { setPhotoModal({ id, customer: delivery.customerName }); return; }
    if (newStatus === DeliveryStatus.REJECTED) { setRejectionModal({ id, customer: delivery.customerName }); return; }
    setDeliveries(prev => prev.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    ));
  };

  const handleStartAllRoutes = () => {
    if (!selectedDriverName) return;
    setDeliveries(prev => prev.map(d => {
      if (d.driverName === selectedDriverName && d.status === DeliveryStatus.PENDING) {
        return { ...d, status: DeliveryStatus.IN_TRANSIT, updatedAt: new Date().toISOString() };
      }
      return d;
    }));
    setAiMessage("Todos os seus pedidos estão em rota!");
    setTimeout(() => setAiMessage(null), 4000);
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriverName);
  const pendingOrdersForDriver = driversOrders.filter(d => d.status === DeliveryStatus.PENDING);

  // --- RENDERING LOGIC ---

  if (!loggedRole) {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-6 text-white overflow-y-auto">
        <div className="mb-8 text-center space-y-2">
          <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg shadow-blue-500/20">
            <Package className="w-10 h-10" />
          </div>
          <h1 className="text-4xl font-black tracking-tighter">SwiftLog</h1>
          <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.2em]">SISTEMA DE LOGÍSTICA PRIVADO</p>
        </div>

        {authStep === 'CHOICE' ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full max-w-5xl animate-in fade-in zoom-in-95 duration-300">
            {[
              { id: 'ADMIN', label: 'Administrador', icon: ShieldCheck, color: 'bg-blue-600', desc: 'Controle total de carga' },
              { id: 'MOTORISTA', label: 'Motorista', icon: Truck, color: 'bg-indigo-600', desc: 'Acesso às minhas cargas' },
              { id: 'VENDEDOR', label: 'Vendedor', icon: ShoppingBag, color: 'bg-emerald-600', desc: 'Rastreio de pedidos' },
            ].map(role => (
              <button 
                key={role.id}
                onClick={() => { setSelectedRole(role.id as UserRole); setAuthStep('CREDENTIALS'); }}
                className="bg-slate-900 border border-slate-800 p-8 rounded-3xl hover:border-blue-500 transition-all group text-left space-y-4 hover:-translate-y-2 shadow-xl"
              >
                <div className={`${role.color} w-12 h-12 rounded-xl flex items-center justify-center group-hover:scale-110 transition-transform`}>
                  <role.icon className="w-6 h-6" />
                </div>
                <div>
                  <h3 className="text-xl font-black uppercase tracking-tight">{role.label}</h3>
                  <p className="text-sm text-slate-500 font-medium">{role.desc}</p>
                </div>
              </button>
            ))}
          </div>
        ) : (
          <div className="w-full max-w-md bg-slate-900 border border-slate-800 p-8 rounded-3xl shadow-2xl space-y-6 animate-in slide-in-from-bottom-4 duration-300">
            <div className="flex items-center gap-4 border-b border-slate-800 pb-4">
              <button onClick={() => {setAuthStep('CHOICE'); setAuthError(null);}} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400"><X className="w-5 h-5" /></button>
              <div>
                <h2 className="font-black uppercase text-sm tracking-widest">{selectedRole === 'ADMIN' ? 'Acesso Restrito' : selectedRole === 'MOTORISTA' ? 'Login Motorista' : 'Acesso Vendedor'}</h2>
                <p className="text-[10px] text-slate-500 font-bold uppercase">Identifique-se para continuar</p>
              </div>
            </div>

            <div className="space-y-4">
              {selectedRole === 'MOTORISTA' && (
                <div className="space-y-1">
                  <label className="text-[9px] font-black uppercase text-slate-500 ml-1">Selecione seu Nome</label>
                  <select 
                    value={driverLoginId}
                    onChange={(e) => setDriverLoginId(e.target.value)}
                    className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3.5 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none text-white appearance-none"
                  >
                    <option value="">Escolha seu perfil...</option>
                    {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                  </select>
                </div>
              )}

              {(selectedRole === 'ADMIN' || selectedRole === 'MOTORISTA') && (
                <div className="space-y-1">
                  <label className="text-[9px] font-black uppercase text-slate-500 ml-1">Sua Senha</label>
                  <div className="relative">
                    <input 
                      type={showPassword ? "text" : "password"}
                      value={passwordInput}
                      onChange={(e) => setPasswordInput(e.target.value)}
                      placeholder="••••••••"
                      className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3.5 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none text-white"
                      onKeyDown={(e) => e.key === 'Enter' && handleLogin()}
                    />
                    <button 
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-600 hover:text-slate-400"
                    >
                      {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                    </button>
                  </div>
                </div>
              )}

              {selectedRole === 'VENDEDOR' && (
                <div className="py-4 text-center">
                  <p className="text-xs text-slate-400 font-medium">O acesso de vendedor permite apenas a consulta pública de status de pedidos.</p>
                </div>
              )}

              {authError && (
                <div className="bg-red-900/20 border border-red-900/50 text-red-400 p-3 rounded-xl flex items-center gap-3 animate-shake">
                  <AlertCircle className="w-4 h-4" />
                  <p className="text-[10px] font-black uppercase">{authError}</p>
                </div>
              )}

              <button 
                onClick={handleLogin}
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-xl uppercase text-xs tracking-widest shadow-lg shadow-blue-500/10 transition-all active:scale-95"
              >
                Entrar no Sistema
              </button>
            </div>
          </div>
        )}
      </div>
    );
  }

  // --- MAIN APP ---
  const navItems = [];
  if (loggedRole === 'ADMIN') {
    navItems.push({ id: 'ADMIN_PANEL', label: 'Painel Geral', icon: LayoutDashboard });
    navItems.push({ id: 'DRIVERS_MGMT', label: 'Motoristas', icon: Users });
  } else if (loggedRole === 'MOTORISTA') {
    navItems.push({ id: 'DRIVER_PORTAL', label: 'Meu Portal', icon: Truck });
  } else if (loggedRole === 'VENDEDOR') {
    navItems.push({ id: 'TRACKING', label: 'Rastreio', icon: Search });
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white p-5 flex flex-col transition-transform duration-300 transform 
        ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 md:flex shadow-2xl
      `}>
        <div className="flex items-center gap-2 mb-8 px-2">
          <Package className="w-6 h-6 text-blue-500" />
          <h1 className="text-xl font-black tracking-tighter leading-none">SwiftLog</h1>
        </div>

        <nav className="flex-1 space-y-1">
          {navItems.map(item => (
            <button 
              key={item.id}
              onClick={() => { setActiveView(item.id); setIsMenuOpen(false); }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeView === item.id ? 'bg-blue-600 text-white font-bold' : 'hover:bg-slate-800 text-slate-400 font-medium'}`}
            >
              <item.icon className="w-4 h-4" />
              <span className="text-[10px] uppercase tracking-wider font-black">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="mt-auto pt-4 border-t border-slate-800 space-y-4">
           <div className="px-2">
              <p className="text-[8px] font-black uppercase text-slate-500 tracking-widest">SESSÃO ATIVA</p>
              <div className="flex items-center gap-2 mt-1">
                 <div className="w-2 h-2 rounded-full bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.5)]"></div>
                 <p className="text-xs font-black text-white truncate">{loggedRole === 'MOTORISTA' ? selectedDriverName : loggedRole}</p>
              </div>
           </div>
           <button onClick={logout} className="w-full bg-slate-800 hover:bg-red-900/40 text-red-400 p-3 rounded-xl flex items-center justify-center gap-2 font-black text-[9px] uppercase transition-colors">
              <LogOut className="w-4 h-4" /> Sair / Trocar Perfil
           </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-6 space-y-4 overflow-x-hidden">
        {aiMessage && (
          <div className="fixed top-5 right-5 z-50 animate-in slide-in-from-right-10 duration-300">
            <div className="bg-white border-l-4 border-blue-600 text-slate-800 px-4 py-3 rounded-lg shadow-2xl flex items-center gap-3">
              <CheckCircle2 className="w-4 h-4 text-blue-600" />
              <p className="text-[10px] font-black uppercase text-slate-600">{aiMessage}</p>
            </div>
          </div>
        )}

        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
          <div>
            <h2 className="text-xl font-black text-slate-900 uppercase leading-none">
              {activeView === 'ADMIN_PANEL' && "Administração Geral"}
              {activeView === 'DRIVERS_MGMT' && "Gestão de Frota"}
              {activeView === 'DRIVER_PORTAL' && `Minhas Entregas`}
              {activeView === 'TRACKING' && "Consultar Rastreio"}
            </h2>
          </div>
          {activeView === 'ADMIN_PANEL' && (
            <label className="flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2.5 rounded-lg font-bold cursor-pointer transition-all active:scale-95 uppercase text-[9px] tracking-widest shadow-lg shadow-blue-200">
              <FileUp className="w-4 h-4" /> Importar Planilha
              <input type="file" className="hidden" accept=".xlsx, .xls" onChange={handleFileUpload} />
            </label>
          )}
        </div>

        {/* Global Search */}
        <div className="relative group">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
          <input 
            type="text" 
            placeholder="Filtrar pedidos, clientes ou destinos..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-4 py-3.5 bg-white border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-slate-700 text-xs shadow-sm"
          />
        </div>

        {activeView === 'DRIVER_PORTAL' && pendingOrdersForDriver.length > 0 && (
          <button 
            onClick={handleStartAllRoutes}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white py-4 rounded-2xl flex items-center justify-center gap-3 font-black text-[11px] uppercase tracking-widest shadow-xl shadow-blue-200 transition-all active:scale-[0.98] border-b-4 border-blue-800"
          >
            <Play className="w-4 h-4 fill-white" />
            Iniciar Toda a Carga ({pendingOrdersForDriver.length} itens)
          </button>
        )}

        {/* LISTA DE ENTREGAS */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {(activeView === 'DRIVER_PORTAL' ? driversOrders : filteredDeliveries).map((delivery) => (
            <div key={delivery.id} className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-all flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-3">
                  <span className="font-mono text-blue-600 font-black text-sm">#{delivery.orderNumber}</span>
                  <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                    delivery.status === DeliveryStatus.DELIVERED ? 'bg-green-50 text-green-700 border-green-200' :
                    delivery.status === DeliveryStatus.IN_TRANSIT ? 'bg-indigo-50 text-indigo-700 border-indigo-200' :
                    delivery.status === DeliveryStatus.REJECTED ? 'bg-red-50 text-red-700 border-red-200' :
                    'bg-orange-50 text-orange-700 border-orange-200'
                  }`}>
                    {delivery.status}
                  </span>
                </div>
                <h3 className="font-black text-slate-900 text-base uppercase leading-tight mb-2">{delivery.customerName}</h3>
                <div className="space-y-1.5">
                   <p className="text-[10px] font-bold text-slate-400 uppercase flex items-center gap-1.5">
                      <MapPin className="w-3 h-3 text-red-400" /> {delivery.city}
                   </p>
                   <p className="text-[9px] text-slate-500 italic leading-snug">{delivery.address}</p>
                   <div className="flex items-center gap-2 pt-2">
                      <span className="text-[9px] font-black bg-green-50 text-green-700 px-2 py-1 rounded-lg flex items-center gap-1 shadow-sm">
                         <DollarSign className="w-3 h-3" /> {delivery.orderValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                      </span>
                      {loggedRole === 'ADMIN' && (
                        <span className="text-[9px] font-bold text-slate-400 uppercase flex items-center gap-1 bg-slate-50 px-2 py-1 rounded-lg">
                          <Truck className="w-3 h-3" /> {delivery.driverName}
                        </span>
                      )}
                   </div>
                </div>
              </div>

              <div className="flex gap-2 mt-5 pt-4 border-t border-slate-50">
                {activeView === 'DRIVER_PORTAL' && delivery.status !== DeliveryStatus.DELIVERED && delivery.status !== DeliveryStatus.REJECTED && (
                  <>
                    <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.REJECTED)} className="bg-red-50 text-red-600 px-4 py-3 rounded-xl border border-red-100 flex items-center justify-center active:scale-95 transition-colors" title="Devolver">
                      <RotateCcw className="w-4 h-4" />
                    </button>
                    {delivery.status === DeliveryStatus.PENDING ? (
                      <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.IN_TRANSIT)} className="flex-1 bg-indigo-600 text-white p-3 rounded-xl flex items-center justify-center gap-2 font-black text-[9px] uppercase active:scale-95 shadow-lg shadow-indigo-100">
                         <Navigation className="w-3 h-3" /> Iniciar
                      </button>
                    ) : (
                      <button onClick={() => updateDeliveryStatus(delivery.id, DeliveryStatus.DELIVERED)} className="flex-1 bg-green-600 text-white p-3 rounded-xl flex items-center justify-center gap-2 font-black text-[9px] uppercase active:scale-95 shadow-lg shadow-green-100">
                         <Camera className="w-4 h-4" /> Finalizar
                      </button>
                    )}
                  </>
                )}
                {delivery.receiptPhoto && (
                  <button onClick={() => setViewPhoto(delivery.receiptPhoto || null)} className="flex-1 bg-slate-50 text-slate-500 p-3 rounded-xl flex items-center justify-center gap-2 font-black text-[9px] uppercase border border-slate-100 hover:bg-blue-50 hover:text-blue-600 transition-all">
                    <ImageIcon className="w-4 h-4" /> Ver Comprovante
                  </button>
                )}
                {loggedRole === 'ADMIN' && (
                  <button onClick={() => setDeliveries(prev => prev.filter(d => d.id !== delivery.id))} className="p-3 text-slate-200 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
                )}
              </div>
            </div>
          ))}
          {((activeView === 'DRIVER_PORTAL' ? driversOrders : filteredDeliveries).length === 0) && (
            <div className="col-span-full py-32 text-center opacity-30 animate-pulse">
               <Package className="w-16 h-16 mx-auto mb-4" />
               <p className="text-[11px] font-black uppercase tracking-[0.2em]">Sem resultados para exibição</p>
            </div>
          )}
        </div>

        {/* GESTÃO DE MOTORISTAS (Apenas ADMIN) */}
        {activeView === 'DRIVERS_MGMT' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm space-y-5 h-fit">
              <div className="space-y-1">
                <h3 className="font-black text-slate-900 uppercase text-[10px] tracking-widest flex items-center gap-2">
                  <Plus className="w-4 h-4 text-blue-600" /> Cadastrar Motorista
                </h3>
                <p className="text-[9px] text-slate-400 font-bold">Defina o nome e a senha de acesso individual.</p>
              </div>

              <div className="space-y-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Nome Completo</label>
                  <input 
                    type="text" 
                    placeholder="Ex: Roberto Mendes"
                    value={newDriverName}
                    onChange={(e) => setNewDriverName(e.target.value)}
                    className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-xs"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Senha de Acesso</label>
                  <input 
                    type="text" 
                    placeholder="Mínimo 3 caracteres"
                    value={newDriverPass}
                    onChange={(e) => setNewDriverPass(e.target.value)}
                    className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-xs"
                  />
                </div>
              </div>

              <button 
                onClick={() => {
                  if (!newDriverName.trim() || !newDriverPass.trim()) return;
                  setDrivers(prev => [...prev, { id: crypto.randomUUID(), name: newDriverName.trim(), password: newDriverPass.trim() }]);
                  setNewDriverName(''); setNewDriverPass('');
                }} 
                className="w-full bg-slate-900 text-white font-black py-4 rounded-xl uppercase text-[10px] shadow-lg hover:bg-slate-800 transition-all active:scale-95"
              >
                Ativar Novo Motorista
              </button>
            </div>

            <div className="lg:col-span-2 space-y-3">
              {drivers.map(driver => (
                <div key={driver.id} className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm flex items-center justify-between hover:border-blue-200 transition-all group">
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-blue-50 rounded-xl flex items-center justify-center text-blue-600">
                      <User className="w-5 h-5" />
                    </div>
                    <div>
                      <p className="font-black text-slate-900 text-sm uppercase tracking-tight">{driver.name}</p>
                      <p className="text-[9px] text-slate-400 font-bold uppercase flex items-center gap-1"><Lock className="w-2.5 h-2.5" /> Senha: {driver.password}</p>
                    </div>
                  </div>
                  <button onClick={() => setDrivers(prev => prev.filter(d => d.id !== driver.id))} className="p-3 text-slate-200 hover:text-red-500 transition-colors bg-slate-50 rounded-xl group-hover:bg-red-50"><Trash2 className="w-4 h-4" /></button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* MODAIS */}
        {photoModal && (
          <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-3xl p-8 space-y-6 shadow-2xl">
              <div className="text-center space-y-3">
                <div className="w-16 h-16 bg-green-50 text-green-600 rounded-full flex items-center justify-center mx-auto">
                  <Camera className="w-8 h-8" />
                </div>
                <h3 className="text-base font-black text-slate-900 uppercase tracking-widest">Finalizar Entrega</h3>
                <p className="text-[10px] text-slate-500 uppercase font-black">Cliente: {photoModal.customer}</p>
              </div>
              <button onClick={() => fileInputRef.current?.click()} className="w-full bg-blue-600 text-white font-black py-4 rounded-xl uppercase text-[10px] shadow-lg active:scale-95">Capturar Comprovante</button>
              <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handlePhotoCapture} />
              <button onClick={() => setPhotoModal(null)} className="w-full text-slate-400 font-black py-2 uppercase text-[9px]">Cancelar</button>
            </div>
          </div>
        )}

        {viewPhoto && (
          <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-lg z-[200] flex items-center justify-center p-4" onClick={() => setViewPhoto(null)}>
            <div className="relative max-w-md w-full animate-in zoom-in-95 duration-200">
              <button onClick={() => setViewPhoto(null)} className="absolute -top-12 right-0 text-white flex items-center gap-2 font-black text-[11px] uppercase tracking-widest bg-white/10 px-4 py-2 rounded-full"><X className="w-5 h-5" /> Fechar</button>
              <img src={viewPhoto} alt="Comprovante" className="w-full rounded-2xl shadow-2xl border-4 border-white/20" />
            </div>
          </div>
        )}

        {pendingImport && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4">
            <div className="bg-white w-full max-w-xs rounded-3xl p-8 space-y-6 shadow-2xl text-center">
              <div className="space-y-1">
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Vincular Carga</h3>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Atribuir {pendingImport.length} pedidos</p>
              </div>
              <select 
                value={importDriverId}
                onChange={(e) => setImportDriverId(e.target.value)}
                className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl font-black text-slate-800 text-[10px] uppercase outline-none focus:ring-2 focus:ring-blue-500 appearance-none"
              >
                <option value="">Selecione o motorista...</option>
                {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
              <div className="flex gap-3">
                <button onClick={() => setPendingImport(null)} className="flex-1 py-3 text-[9px] font-black text-slate-400 uppercase">Voltar</button>
                <button onClick={confirmImport} disabled={!importDriverId} className="flex-1 py-3.5 bg-blue-600 text-white rounded-xl font-black text-[9px] uppercase shadow-lg disabled:opacity-30">Vincular</button>
              </div>
            </div>
          </div>
        )}

        {loading && (
          <div className="fixed inset-0 bg-slate-950/40 backdrop-blur-sm flex items-center justify-center z-[100]">
             <div className="bg-white p-8 rounded-3xl shadow-2xl flex flex-col items-center gap-4">
                <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="font-black text-slate-900 tracking-widest uppercase text-[9px]">Processando dados...</p>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { 
  Package, 
  Truck, 
  User, 
  Users,
  Search, 
  FileUp, 
  CheckCircle2, 
  MapPin, 
  DollarSign, 
  Camera, 
  X, 
  ImageIcon, 
  RotateCcw, 
  Navigation, 
  ClipboardList, 
  Menu,
  Trash2,
  Plus,
  LayoutDashboard,
  AlertCircle,
  Play,
  Database,
  ShieldCheck,
  LogOut,
  ShoppingBag,
  Lock,
  Eye,
  EyeOff
} from 'lucide-react';
import { Delivery, DeliveryStatus, UserRole, Driver } from './types';
import { generateTrackingMessage } from './services/geminiService';
import { saveData, getData } from './services/dbService';

const ADMIN_PASSWORD_DEFAULT = 'admin123';

const App: React.FC = () => {
  const [deliveries, setDeliveries] = useState<Delivery[]>([]);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [loggedRole, setLoggedRole] = useState<UserRole | null>(null);
  const [activeView, setActiveView] = useState<string>('');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDriverName, setSelectedDriverName] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [aiMessage, setAiMessage] = useState<string | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);

  // Login States
  const [authStep, setAuthStep] = useState<'CHOICE' | 'CREDENTIALS'>('CHOICE');
  const [selectedRole, setSelectedRole] = useState<UserRole | null>(null);
  const [passwordInput, setPasswordInput] = useState('');
  const [driverLoginId, setDriverLoginId] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [authError, setAuthError] = useState<string | null>(null);

  // Management States
  const [newDriverName, setNewDriverName] = useState('');
  const [newDriverPass, setNewDriverPass] = useState('');

  const [pendingImport, setPendingImport] = useState<any[] | null>(null);
  const [importDriverId, setImportDriverId] = useState<string>('');
  const [photoModal, setPhotoModal] = useState<{id: string, customer: string} | null>(null);
  const [viewPhoto, setViewPhoto] = useState<string | null>(null);
  const [rejectionModal, setRejectionModal] = useState<{id: string, customer: string} | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadStoredData = async () => {
      try {
        const storedDeliveries = await getData('deliveries');
        const storedDrivers = await getData('drivers');
        if (storedDeliveries.length > 0) setDeliveries(storedDeliveries);
        if (storedDrivers.length > 0) setDrivers(storedDrivers);
        else {
          const defaultDrivers = [
            { id: '1', name: 'João Carlos', password: '123' }, 
            { id: '2', name: 'Maria Silva', password: '123' }
          ];
          setDrivers(defaultDrivers);
          await saveData('drivers', defaultDrivers);
        }
      } catch (err) { console.error("Falha ao inicializar banco:", err); }
      finally { setIsInitialized(true); }
    };
    loadStoredData();
  }, []);

  useEffect(() => {
    if (isInitialized) saveData('deliveries', deliveries);
  }, [deliveries, isInitialized]);

  useEffect(() => {
    if (isInitialized) saveData('drivers', drivers);
  }, [drivers, isInitialized]);

  const handleLogin = () => {
    setAuthError(null);
    if (selectedRole === 'ADMIN') {
      if (passwordInput === ADMIN_PASSWORD_DEFAULT) {
        setLoggedRole('ADMIN');
        setActiveView('ADMIN_PANEL');
      } else {
        setAuthError('Senha de administrador incorreta.');
      }
    } else if (selectedRole === 'MOTORISTA') {
      const driver = drivers.find(d => d.id === driverLoginId);
      if (driver && driver.password === passwordInput) {
        setLoggedRole('MOTORISTA');
        setSelectedDriverName(driver.name);
        setActiveView('DRIVER_PORTAL');
      } else {
        setAuthError('Nome ou senha do motorista incorretos.');
      }
    } else if (selectedRole === 'VENDEDOR') {
      setLoggedRole('VENDEDOR');
      setActiveView('TRACKING');
    }
  };

  const logout = () => {
    setLoggedRole(null);
    setAuthStep('CHOICE');
    setSelectedRole(null);
    setPasswordInput('');
    setDriverLoginId('');
    setSelectedDriverName('');
    setAuthError(null);
    setIsMenuOpen(false);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setLoading(true);
    const reader = new FileReader();
    reader.onload = async (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const rawRows: any[][] = XLSX.utils.sheet_to_json(ws, { header: 1 });
        const rows = rawRows.slice(1);
        const parsedData = rows.map(row => {
          if (!row[1] && !row[5]) return null;
          return {
            orderNumber: String(row[1] || ''),
            orderValue: parseFloat(String(row[3]).replace(/[^\d.,]/g, '').replace(',', '.')) || 0,
            customerName: String(row[5] || 'Cliente Indefinido'),
            city: String(row[9] || 'Belém'),
            address: String(row[8] || `${row[9] || 'Belém'}, Pará`)
          };
        }).filter(Boolean);
        setPendingImport(parsedData);
      } catch (err) { alert("Erro ao ler o arquivo Excel."); }
      finally { setLoading(false); e.target.value = ''; }
    };
    reader.readAsBinaryString(file);
  };

  const confirmImport = async () => {
    if (!pendingImport || !importDriverId) return;
    const selectedDriverObj = drivers.find(d => d.id === importDriverId);
    const driverName = selectedDriverObj ? selectedDriverObj.name : 'Não Atribuído';
    const newDeliveries: Delivery[] = pendingImport.map(item => ({
      id: crypto.randomUUID(),
      orderNumber: item.orderNumber,
      orderValue: item.orderValue,
      customerName: item.customerName,
      city: item.city,
      address: item.address,
      driverName: driverName,
      status: DeliveryStatus.PENDING,
      updatedAt: new Date().toISOString(),
      lat: -1.4558 + (Math.random() * 0.1 - 0.05),
      lng: -48.4902 + (Math.random() * 0.1 - 0.05),
    }));
    setDeliveries(prev => [...prev, ...newDeliveries]);
    setPendingImport(null);
    setImportDriverId('');
    setAiMessage(`${newDeliveries.length} entregas importadas!`);
    setTimeout(() => setAiMessage(null), 3000);
  };

  const handlePhotoCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !photoModal) return;
    const reader = new FileReader();
    reader.onload = async (evt) => {
      const base64 = evt.target?.result as string;
      setDeliveries(prev => prev.map(d => 
        d.id === photoModal.id ? { 
          ...d, 
          status: DeliveryStatus.DELIVERED, 
          receiptPhoto: base64, 
          completedAt: new Date().toISOString(),
          updatedAt: new Date().toISOString()
        } : d
      ));
      const delivery = deliveries.find(d => d.id === photoModal.id);
      if (delivery) {
        const msg = await generateTrackingMessage(DeliveryStatus.DELIVERED, delivery.customerName);
        setAiMessage(msg);
        setTimeout(() => setAiMessage(null), 5000);
      }
      setPhotoModal(null);
    };
    reader.readAsDataURL(file);
  };

  const updateDeliveryStatus = (id: string, newStatus: DeliveryStatus) => {
    const delivery = deliveries.find(d => d.id === id);
    if (!delivery) return;
    if (newStatus === DeliveryStatus.DELIVERED) { setPhotoModal({ id, customer: delivery.customerName }); return; }
    if (newStatus === DeliveryStatus.REJECTED) { setRejectionModal({ id, customer: delivery.customerName }); return; }
    setDeliveries(prev => prev.map(d => 
      d.id === id ? { ...d, status: newStatus, updatedAt: new Date().toISOString() } : d
    ));
  };

  const handleStartAllRoutes = () => {
    if (!selectedDriverName) return;
    setDeliveries(prev => prev.map(d => {
      if (d.driverName === selectedDriverName && d.status === DeliveryStatus.PENDING) {
        return { ...d, status: DeliveryStatus.IN_TRANSIT, updatedAt: new Date().toISOString() };
      }
      return d;
    }));
    setAiMessage("Todos os seus pedidos estão em rota!");
    setTimeout(() => setAiMessage(null), 4000);
  };

  const filteredDeliveries = deliveries.filter(d => 
    d.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) || 
    d.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    d.city.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const driversOrders = deliveries.filter(d => d.driverName === selectedDriverName);
  const pendingOrdersForDriver = driversOrders.filter(d => d.status === DeliveryStatus.PENDING);

  // --- RENDERING LOGIC ---

  if (!loggedRole) {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-6 text-white overflow-y-auto">
        <div className="mb-8 text-center space-y-2">
          <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg shadow-blue-500/20">
            <Package className="w-10 h-10" />
          </div>
          <h1 className="text-4xl font-black tracking-tighter">SwiftLog</h1>
          <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.2em]">SISTEMA DE LOGÍSTICA PRIVADO</p>
        </div>

        {authStep === 'CHOICE' ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full max-w-5xl animate-in fade-in zoom-in-95 duration-300">
            {[
              { id: 'ADMIN', label: 'Administrador', icon: ShieldCheck, color: 'bg-blue-600', desc: 'Controle total de carga' },
              { id: 'MOTORISTA', label: 'Motorista', icon: Truck, color: 'bg-indigo-600', desc: 'Acesso às minhas cargas' },
              { id: 'VENDEDOR', label: 'Vendedor', icon: ShoppingBag, color: 'bg-emerald-600', desc: 'Rastreio de pedidos' },
            ].map(role => (
              <button 
                key={role.id}
                onClick={() => { setSelectedRole(role.id as UserRole); setAuthStep('CREDENTIALS'); }}
                className="bg-slate-900 border border-slate-800 p-8 rounded-3xl hover:border-blue-500 transition-all group text-left space-y-4 hover:-translate-y-2 shadow-xl"
              >
                <div className={`${role.color} w-12 h-12 rounded-xl flex items-center justify-center group-hover:scale-110 transition-transform`}>
                  <role.icon className="w-6 h-6" />
                </div>
                <div>
                  <h3 className="text-xl font-black uppercase tracking-tight">{role.label}</h3>
                  <p className="text-sm text-slate-500 font-medium">{role.desc}</p>
                </div>
              </button>
            ))}
          </div>
        ) : (
          <div className="w-full max-w-md bg-slate-900 border border-slate-800 p-8 rounded-3xl shadow-2xl space-y-6 animate-in slide-in-from-bottom-4 duration-300">
            <div className="flex items-center gap-4 border-b border-slate-800 pb-4">
              <button onClick={() => {setAuthStep('CHOICE'); setAuthError(null);}} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400"><X className="w-5 h-5" /></button>
              <div>
                <h2 className="font-black uppercase text-sm tracking-widest">{selectedRole === 'ADMIN' ? 'Acesso Restrito' : selectedRole === 'MOTORISTA' ? 'Login Motorista' : 'Acesso Vendedor'}</h2>
                <p className="text-[10px] text-slate-500 font-bold uppercase">Identifique-se para continuar</p>
              </div>
            </div>

            <div className="space-y-4">
              {selectedRole === 'MOTORISTA' && (
                <div className="space-y-1">
                  <label className="text-[9px] font-black uppercase text-slate-500 ml-1">Selecione seu Nome</label>
                  <select 
                    value={driverLoginId}
                    onChange={(e) => setDriverLoginId(e.target.value)}
                    className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3.5 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none text-white appearance-none"
                  >
                    <option value="">Escolha seu perfil...</option>
                    {drivers.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                  </select>
                </div>
              )}

              {(selectedRole === 'ADMIN' || selectedRole === 'MOTORISTA') && (
                <div className="space-y-1">
                  <label className="text-[9px] font-black uppercase text-slate-500 ml-1">Sua Senha</label>
                  <div className="relative">
                    <input 
                      type={showPassword ? "text" : "password"}
                      value={passwordInput}
                      onChange={(e) => setPasswordInput(e.target.value)}
                      placeholder="••••••••"
                      className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3.5 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none text-white"
                      onKeyDown={(e) => e.key === 'Enter' && handleLogin()}
                    />
                    <button 
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-600 hover:text-slate-400"
                    >
                      {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                    </button>
                  </div>
                </div>
              )}

              {selectedRole === 'VENDEDOR' && (
                <div className="py-4 text-center">
                  <p className="text-xs text-slate-400 font-medium">O acesso de vendedor permite apenas a consulta pública de status de pedidos.</p>
                </div>
              )}

              {authError && (
                <div className="bg-red-900/20 border border-red-900/50 text-red-400 p-3 rounded-xl flex items-center gap-3 animate-shake">
                  <AlertCircle className="w-4 h-4" />
                  <p className="text-[10px] font-black uppercase">{authError}</p>
                </div>
              )}

              <button 
                onClick={handleLogin}
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-xl uppercase text-xs tracking-widest shadow-lg shadow-blue-500/10 transition-all active:scale-95"
              >
                Entrar no Sistema
              </button>
            </div>
          </div>
        )}
      </div>
    );
  }

  // --- MAIN APP ---
  const navItems = [];
